(152, 1798, 'خدمات مالی و اداری رایان حساب نگر', 'کمتر از 10 نفر', NULL, '283', 'کرج', 'کرج فردیس فلکه دوم خیابان آزادی خیابان 49 پلاک 5', '09126084434', '5', 'البرز', NULL, 'انجام کلیه امور مالی و مالیاتی اصناف و شرکت ها،تهیه و تنظیم اظهارنامه های مالیاتی و ارزش افزوده،مشاوره مالی ،حسابرسی ،تهیه صورت های مالی و انواع گزارشات،طراحی سیستم های مالی و حسابداری،تهیه طرح های توجیهی جهت اخذ تسهیلات بانکی،ثبت برند و اخذ مجوزهای قانونی،', 'اولویت قراردادن رفتار سازمانی،استانداردها و احترام به منابع انسانی', 'آموزش ،رشد و ارتقا حرفه ای،حقوق و مزایای منطقی', '2022-07-14 08:20:11', '2022-07-14 08:20:11'),
(153, 1799, 'ماشین سازی برادران صادقی', 'تا 50 نفر', NULL, '117', 'تهران', 'تهران افسریه خاوران', '02133575363', '8', 'تهران', NULL, 'سازنده انواع ماشین های پرس', 'اولویت بخشی به رفتار سازمانی ،ارزش آفرینی منابع انسانی', 'رشد و ارتقا حرفه ای،حقوق و مزایای منطقی', '2022-07-14 09:16:57', '2022-07-14 09:16:57'),
(154, 1813, 'پارس باراد خلاقان مبتکر', 'تا 100 نفر', NULL, '153', 'مشهد', 'مشهد، شهرک صنعتی توس فاز 2 اندیشه 5 دانش 4 پلاک 658', '09020722988', '11', 'خراسان رضوی', NULL, 'برای ما هیچ ماموریتی شیرین‌تر از این نیست که مستقیما با سلامتی و حال خوب افراد در ارتباط باشیم. با افتخار در این مسیر قدم گذاشتیم و رسالتمان را تولید محصولات ارگونومیک و طبی برای هر گروه شغلی و متناسب با هر شرایط اقتصادی قرار دادیم و محصولاتی مانند پشتی طبی، به‌نشین، نگهدارنده مانیتور، محافظ مچ دست و محافظ گردن را تولید کردیم. با شعار زندگی با ایده‌های ارگونومی تولید را شروع کردیم و بر آنیم تا ارگونومی را به همه‌ی جنبه‌های زندگی افراد وارد کنیم. سبد محصولات ارگونومیک و طبی باراد، به زودی گسترده‌تر و بزرگ‌تر خواهد شد تا جایی‌که ارگونومی عضوی جدا نشدنی از زندگی تمام افراد باشد.', NULL, NULL, '2022-07-25 03:42:55', '2022-07-25 03:42:55'),
(155, 1851, 'تولیدی پوشاک ام اس پورت', 'تا 150 نفر', NULL, '128', 'کهریزک', 'تهران_کهریزک_۶۰ متری امام حسین(شوراباد)_هشتم شمالی_پلاک۱۰', '02156512546', '8', 'تهران', NULL, 'کارخانه تولیدی پوشاک مردانه و زنانه', 'کارخانه تولیدی پوشاک بصورت کاملا سازمانی و در قالب چارت سازمانی فعالیت میکند', 'حقوق و مزایای عالی\nسرویس ایاب و ذهاب\nبیمه تامین اجتماعی\nمحیط کاملا سالم\nپاداش \nعیدی و سنوات', '2022-07-29 09:26:28', '2022-07-29 09:26:28'),
