(157, 1931, 'سیماکالاپویا', 'تا 50 نفر', 'لوگو1661928704.jpg', '153', 'مشهد', 'چهارراه راهنمایی', '05138084', '11', 'خراسان رضوی', NULL, 'شرکت پژوهش محور سیماکالا پویا (سیکاپ) با هدف حمایت از تولیدات داخلی و گسترش فروش محصولات ایرانی از طریق تبلیغات گسترده تلویزیونی و فضای مجازی در سال 1395 آغاز به کار نمود. این شرکت بر پایه باور تولید کنندگان ملی بنا شده تا با تجاری سازی اختراعات و کمک به استارتاپ ها گامی موثر در جهت پیشرفت، آبادانی و رونق اقتصادی کشور عزیزمان بردارد.', NULL, NULL, '2022-08-31 06:51:33', '2022-08-31 06:51:44'),
