(238, 2433, 'ابزار پردازان نامی', NULL, 'company-default.png', '117', 'تهران', 'میدان حسن اباد کوچه شجاعی نبش کوچه فتحعلی خانی پلاک 16 طبقه سوم واحد 11', '66749105', '8', 'تهران', NULL, '<p>شرکت بازرگانی ابزارآلات صنعتی</p>', NULL, NULL, '2023-06-13 07:42:00', '2023-06-13 11:55:37'),
(239, 2434, 'رادین ترابر اسیا', NULL, 'company-default.png', '117', 'تهران', 'تهران خیابان ایران شهر بین سمیه و طالقانی پلاک 114 طبقه دو واحد 4', '88820346', '8', 'تهران', NULL, '<p>حمل و نقل بین المللی&nbsp;</p>', NULL, NULL, '2023-06-13 08:50:50', '2023-06-13 08:54:53'),
(240, 2436, 'سیاف تجارت  الیت', NULL, 'company-default.png', '117', 'تهران', 'میدان حسن آ باد کوچه شجاعی پلاک 32 واحد  5', '02154076', '8', 'تهران', NULL, '<p>تولید و واردات ابزارآلات برقی&nbsp;</p>', NULL, NULL, '2023-06-13 09:16:44', '2023-06-13 12:04:12'),
(241, 2437, 'سینما ویلاژتوریست', NULL, 'company-default.png', '153', 'مشهد', 'جاده طرقبه بین امام رضا 6 و 8  مجتمع تفریحی ویلاژ توریست', '09304344002', '11', 'خراسان رضوی', NULL, '<p>ویلاژ توریست مشهد دارای امکانات رفاهی مختلف مانند سینما، رستوران، شهربازی و غیره می باشد. این مجتمع تجاری و تفریحی یکی از مقاصد مهم گردشگران مشهدی و یکی از معروفترین مراکز خرید مشهد است.مجتمع ویلاژ توریست، طبقه‌ی سوم، با 1075 صندلی از دی ماه 1397 با 12 سالن مجهز سینمایی، واقع در طبقه ی سوم مجتمع ویلاژ توریست آماده‌ی میزبانی از علاقه مندان به سینما است</p>', NULL, NULL, '2023-06-13 12:13:54', '2023-06-14 09:09:06'),
(242, 2444, 'صنایع شیمیایی فراپل جم', NULL, 'company-default.png', '117', 'تهران', 'خیابان توانیر ، خیابان نظامی گنجوی', '09186055572', '8', 'تهران', NULL, '<p>&nbsp;صنایع شیمیایی فراپل جم (سهامی خاص) به عنوان توانمند­ترین تولید کننده دانش بنیان انواع رزین­های صنعتی فعالیت خود را از سال 1382 آغاز نموده است این مجموعه با همت متخصصین داخلی و خارجی و با استفاده از ماشین آلات تولیدی، تجهیزات آزمایشگاهی و جدید­ترین فرمولاسیون ­های روز دنیا&nbsp; موفق به تولید انبوه و یکنواخت انواع رزین های پلی استر غیر اشباع ارتو، ایزو، ترفتالیک، رزین­های ونیل استر بر پایه بیسفنل ­آ، نوالاک، رزین­ های مقاوم در برابر شعله، انواع ژل کت، خمیر رنگ و کبالت اکتوات شده است.<br>محصولات این شرکت دانش بنیان، موفق به اخذ گواهینامه های، WRAS از کشور انگلستان، پروانه ساخت بهداشتی از سازمان غذا و دارو به منظور قابلیت استفاده محصولات در ساخت مخازن و لوله­ های آب آشامیدنی و همچنین تاییدیه از موسسه رده بندی ایرانیان به منظور استفاده در صنایع دریایی شده است.</p>', NULL, NULL, '2023-06-14 09:35:30', '2023-06-14 09:39:17'),
(243, 2450, 'گروه مهندسی متات', NULL, 'company-default.png', '117', 'تهران', 'شهران شمالی بالاتر از فلکه دوم کوچه قشلاقی', '44894070', '8', 'تهران', NULL, '<p>شرکت بازرگانی و خدمات مهندسی و بیشتر از 18 سال سوابق کاری&nbsp;</p>', NULL, NULL, '2023-06-15 10:12:01', '2023-06-15 11:25:19'),
(244, 2457, 'فست فود سیتی استار', NULL, 'company-default.png', '153', 'مشهد', 'بلوار وکیل آباد  بین وکیل آباد 23 و 25', '09358811646', '11', 'خراسان رضوی', NULL, '<p>فست فود&nbsp;</p>', NULL, NULL, '2023-06-17 10:11:20', '2023-06-17 10:13:39'),
(245, 2459, 'بتن زارع', NULL, 'company-default.png', '153', 'مشهد', 'وکیل آباد 13 سروش 10 پلاک 119', '09353370594', '11', 'خراسان رضوی', NULL, '<p>تولیدی بتن&nbsp;</p>', NULL, NULL, '2023-06-17 10:55:27', '2023-06-17 11:02:10'),
(246, 2460, 'افق معدن تابران', NULL, 'company-default.png', '153', 'مشهد', 'ابادگران برج ادارای افتاب طبقه 9', '38718739', '11', 'خراسان رضوی', NULL, '<p>اکتشاف و استخراج مواد معدنی</p>', NULL, NULL, '2023-06-17 11:35:41', '2023-06-17 11:37:05'),
(247, 2474, 'بازرگانی صد و ده امیر', NULL, 'company-default.png', '117', 'تهران', 'تهران خیابان مصطفی خمینی کوچه شهید برهنه', '09121229997', '8', 'تهران', NULL, '<p>خرید و فروش ضایعات کاغذ</p>', NULL, NULL, '2023-06-19 11:49:51', '2023-06-19 11:52:34'),
(248, 2476, 'پوشاک مجلس ی', NULL, 'company-default.png', '117', 'تهران', 'تهران محدوده جمهوری', '09124798464', '8', 'تهران', NULL, '<p>تولیدی پوشاک زنانه&nbsp;</p>', NULL, NULL, '2023-06-19 12:23:56', '2023-06-19 12:25:54'),
(249, 2478, 'نولان توسعه اگری', NULL, 'company-default.png', '117', 'تهران', 'تهران، بلوار آفریقا، بالا تر از چهار راه جهان کودک، روبروی بانک پاسارگاد، ساختمان نگین آفریقا، طبقه 11، واحد 1101', '88673363', '8', 'تهران', NULL, '<p>گروه دامپروری و کشاورزی نولان با تکیه بر دو دهه تجربه و کار اجرایی در صنعت دامپروی و با هدف تامین تمام نیازمندی های یک واحد دامپروری از سال ۱۳۷۶ شروع به عرضه محصولات و خدمات خود نموده است. این مجموعه با تکیه بر توانمندی های خود در سه حوزه” طراحی ومهندسی”، “ساخت واجرا” و”تجهیز، تامین، نصب و راه اندازی ماشین آلات وتجهیزات” و با بهره گیری از دانش روز دنیا و متخصصان با تجربه و توانمند، توانسته است مجموعه ای کامل از استانداردها و راهکارهای تجهیز، ساخت و توسعه پروژه های دامپروری را ارائه نماید. همچنین از اهداف بلند مدت این شرکت حضور در بازارهای جهانی و ارائه خدمات پس از فروش مطابق با استانداردهای روز صنعت دامپروری دنیا می باشد.</p>', NULL, NULL, '2023-06-19 12:35:44', '2023-06-19 12:45:21'),
(250, 2510, 'فروشگاه 199', NULL, 'company-default.png', '117', 'تهران', 'میدان اعدام (محمدیه ) خیابان خیام جنوبی کوچه آهن فروشان', '55595356', '8', 'تهران', NULL, '<p>بنک دار مواد غذایی خارجی</p>', NULL, NULL, '2023-06-21 11:34:42', '2023-06-21 11:38:18'),
