(346, 2927, 'پارس نسیم دما', NULL, 'company-default.png', '117', 'تهران', 'شهرستان رباط کریم،خ علم و نظام پلاک ۹۰۹۰', '09123394178', '8', 'تهران', NULL, '<p><br>گروه صنعتی <strong>پارس دما فعالیت</strong> حرفه ای خود را در زمینه ساخت تجهیزات حرارتی ، برودتی و آبرسانی در سال ۱۳۸۵آغاز نمود و در ادامه به منظور اطلاع رسانی شفاف و سریع، سایت حاضر را تحت عنوان <strong>پارس دما</strong> تاسیس نمود.</p>', NULL, NULL, '2023-10-17 08:16:24', '2023-10-17 08:25:58'),
(347, 2928, 'پیک فرهنگ', NULL, 'company-default.png', '117', 'تهران', 'منطقه ۱۱، میدان انقلاب', '02166495086', '8', 'تهران', NULL, '<p>موسسه چاپ</p>', NULL, NULL, '2023-10-17 09:14:48', '2023-10-17 09:19:38'),
(348, 2929, 'شایان تجارت ویرا', NULL, 'company-default.png', '117', 'تهران', 'تهران _ آپادانا (خیابان خرمشهر) کوچه فرهاد پلاک 3 ساختمان پلاد طبقه 4 واحد 12', '02188533628', '8', 'تهران', NULL, '<p>شرکت بازرگانی&nbsp;</p>', NULL, NULL, '2023-10-21 07:28:43', '2023-10-21 07:34:17'),
(349, 2931, 'تامین کالا آراد', NULL, 'company-default.png', '117', 'تهران', 'تهران منطقه سه امامیه', '09914108014', '8', 'تهران', NULL, '<p>شرکت تامین کالا آراد(سهامی خاص) به عنوان یک شرکت بازرگانی در زمینه های مختلف از قبیل:<br>- کلیه فعالیت‌های مطالعاتی، خدمات فنی و مهندسی مشاوره‌ای،طراحی و اجرایی، نظارت بر طرح‌های عمرانی<br>- شرکت در مزایده ها و مناقصه های دولتی و خصوصی<br>- واردات و صادرات کلیه کالاهای مجاز بازرگانی</p>', NULL, NULL, '2023-10-21 07:54:36', '2023-10-21 08:00:17'),
(350, 2932, 'هیدرولیک بهفن', NULL, 'company-default.png', '117', 'تهران', 'منطقه ۱۰، شبیری', '09211190516', '8', 'تهران', NULL, '<p>شرکت هیدرولیک بهفن در سال 1375 فعالیت خود را آغازکرده و 25 سال بصورت حرفه ای در زمینه طراحی برای مدارهای هیدرولیکی،&nbsp;&nbsp;طراحی و ساخت پاورپک و جک هیدرولیک، طراحی وساخت بلوک زیرشیری و خنک کن های روغن و واردات قطعات هیدرولیک برای ماشین آلات صنعتی و راهسازی در صنایع مختلف مانند: خودروسازی، فولاد، ماشین آلات صنایع فلزی، ریخته گری، آسانسوری &nbsp;و غیره&nbsp;&nbsp;تجارب مفیدی بدست آورده است.</p>', NULL, NULL, '2023-10-21 08:21:04', '2023-10-21 08:25:54'),
(351, 2933, 'پوشاک ونسا', NULL, 'company-default.png', '117', 'تهران', 'تهران خ فلسطین جنوبی کوچه محتشم.', '09388808986', '8', 'تهران', NULL, '<p>تولیدی پوشاک</p>', NULL, NULL, '2023-10-21 09:00:05', '2023-10-21 09:02:21'),
(352, 2934, 'شیب شکن', NULL, 'company-default.png', '283', 'کرج', 'جاده قدیم هشتگرد کرج، شهرک گلسار، خیابان خلیج فارس، پلاک20', '144522815', '5', 'البرز', NULL, '<p>ساخت و تعمیرات مکانیکی الکتورموتورها و ژنراتورها&nbsp;</p>', NULL, NULL, '2023-10-21 09:41:48', '2023-10-21 09:53:59'),
(353, 2935, 'بازرگانی آران اطلس دادمان', NULL, 'company-default.png', '283', 'کرج', 'البرز مهر شهر', '09127300688', '5', 'البرز', NULL, '<p>شرکت بازرگانی&nbsp;</p>', NULL, NULL, '2023-10-21 10:25:49', '2023-10-21 10:35:59');
INSERT INTO `companies` (`id`, `user_id`, `name`, `size`, `logo`, `city_id`, `city_name`, `address`, `tel`, `province_id`, `province_name`, `gallery`, `intro`, `culture`, `advantages`, `created_at`, `updated_at`) VALUES
(354, 2936, 'نام شرکت شما', NULL, 'company-default.png', '153', 'مشهد', 'خراسان رضوی شهرک صنعتی بینالود', '09304548092', '11', 'خراسان رضوی', NULL, '<p>گروه تولیدی آداک در راستای هدف مقدس اشتغال زایی و تولید داخلی از سال 1375 واحدهای تولیدی خود را در صنایع مختلف ایجاد و در سال 1386 کارخانه آداک پوشش شرق را در صنعت سقف و دیوارهای کاذب در مساحتی بالغ بر 5000 متر مربع تاسیس نمود.<br>کارخانه آداک پوشش شرق، با ثبت برند صادراتی و بین المللی APS و تلاش جهت عرضه تایل های گچی و سازه های کلیک با کیفیت و مرغوب، از ابتدای فعالیت خود، مورد توجه بزرگان صنعت سقف های کاذب قرار گرفت و برنامه تولید اصلی خود را، تولید 24 ساعته انواع تایل گچی ساده و پانچ قرار داد.<br>هم اکنون، با افتخار و غررو این کارخانه تنها کارخانه ای در ایران عزیز است که تولید تایل های گچی را با بیش از 30 روکش متفاوت و 11 مدل پانچ و حدوداً 350 قلم کالا، انجام می دهد و به عنوان بزرگترین و برترین تولید کننده اختصاصی انواع تایل گچی شناخته می شود.<br>آداک پوشش شرق، در سال 1398 با سرمایه گزاری مجدد، اقدام به راه اندازی خط تولید سازه های کلیک نمود و در حال حاظر تنها کارخانه تولیدکننده سازه کلیک در ایران است که محصول نبشی را با عرض 25 میلیمتر واقعی تولید می کند.<br>مفتخریم که به یاری و اعتماد شما خریداران و همکاران ارجمند، در بازارهای داخلی و خارجی، برند APS به عنوان کیفیت برتر تایل های گچی و سازه های کلیک شناخته شده و ملاک و میزانی برای سنجش کیفیت سایر برندهای موجود در ایران، خاورمیانه و کشورهای آسیای میانه و کشورهای مشترک المنافع است.<br>این کارخانه با توجه به سیاست های اخیر خود، آماده اعطاء نمایندگی و عاملیت فروش فعال در سراسر ایران عزیز و اقصی نقاط دنیا می باشد لذا جهت اطلاع از شرایط نمایندگی، با شماره های دفتر مرکزی تماس حاصل فرمایید.</p>', NULL, NULL, '2023-10-21 10:54:18', '2023-10-21 10:58:25'),
(355, 2937, 'عاکف صنعت نوین مبتکران', NULL, 'company-default.png', '153', 'مشهد', 'مشهد محدوده میدان سپاد', '09337754700', '11', 'خراسان رضوی', NULL, '<p>با توجه به گسترش و تنوع بالا در عرضه تولید خودروی داخلی و نیاز روز افزون به استفاده از قطعات مکمل همچون <a href=\"https://psnmco.com/\">کیت نرم کننده کلاچ</a> جهت بهبود عملکرد خودرو و سلامت شما هموطنان گرامی، مهندسین <a href=\"https://psnmco.com/\">شرکت عاکف صنعت نوین مبتکران</a> به طراحی و ساخت این محصول ارزشمند پرداخته و با استفاده از تکنولوژی روز و استفاده از بهترین مواد اولیه تولید خود را آغاز نموده, و با بهره مندی از تائید و نظر ارزشمند مهندسین خبره پارک علمی و فناوری و دیگر مهندسین عالی رتبه در زمینه تولیدات و متعلقات خودرو، این محصول ارزشمند را به عموم مصرف کنندگان گرامی عرضه نمایند.</p>', NULL, NULL, '2023-10-21 11:09:03', '2023-10-21 11:15:02'),
(356, 2938, 'کارلو صنعت', NULL, 'company-default.png', '117', 'تهران', 'تهران منطقه 12 فردوسی', '(021)33531784', '8', 'تهران', NULL, '<p>در زمینه برق و صنعت فروش لوازم برقی صنعتی&nbsp;</p>', NULL, NULL, '2023-10-23 07:10:51', '2023-10-23 07:21:06'),
(357, 2939, 'آریا صنعت کهکشان', NULL, 'company-default.png', '117', 'تهران', 'تهران میدان انقلاب', '09375996686', '8', 'تهران', NULL, '<p>شرکت آریا صنعت کهکشان به شماره ثبت 555184 فعالیت خود را در سال 1398 با هدف توزیع و پخش محصولات غذایی و سلولزی آغاز نموده است.</p><p>این شرکت با استفاده از جدیدترین متدهای بازاریابی روز دنیا در زمینه پخش و فروش عمده و مویرگی تولیدات داخلی پا به عرصه بازارهای تهران و شهرستان ها گذاشت. ساختار کسب و کار این شرکت به گونه ای طراحی و اجرا می گردد تا نهایت اطمینان و رضایتمندی را برای مشتریان خود در بهترین شرایط کیفیتی فراهم نماید.</p><p>این شرکت علاوه بر فعالیتهای فوق در زمینه مشارکت مالی و استراتژیک در تولید شکلات با نام تجاری ماین ودر کارخانه ای به مساحت 600 متر مربع مجهز به آخرین ماشین آلات روز دنیا و با انباری به مساحت 1000 متر مربع با بهترین کیفیت و شکیل ترین بسته بندی فعال می باشد.</p>', NULL, NULL, '2023-10-23 07:52:28', '2023-10-23 07:59:45'),
(358, 2940, 'رهپویان آسیا پارت', NULL, 'company-default.png', '117', 'تهران', 'تهران، منطقه ۱۲، بهارستان', '33919099', '8', 'تهران', NULL, '<p>فروش قطعات خودرو&nbsp;</p>', NULL, NULL, '2023-10-23 08:20:56', '2023-10-23 08:28:11'),
(359, 2941, 'پروانه فراز', NULL, 'company-default.png', '117', 'تهران', 'تهران  خیام- پشت امامزاده سید نصرالدین- کوچه جزایری دوم- پلاک 12- واحد 1', '09122487364', '8', 'تهران', NULL, '<p>تولیدی و بازرگانی ساخت انواع پلاستیک&nbsp;</p>', NULL, NULL, '2023-10-23 08:59:19', '2023-10-23 09:03:24'),
(360, 2942, 'آریا تجارت انتخاب', NULL, 'company-default.png', '283', 'کرج', 'البرز - کرج', '09122684080', '5', 'البرز', NULL, '<p>لوازم خانگی&nbsp;</p>', NULL, NULL, '2023-10-23 09:24:32', '2023-10-23 09:28:35'),
(361, 2943, 'ام اف دیزاین', NULL, 'company-default.png', '283', 'کرج', 'البرز، کرج، منطقه ۴، فاز یک مهرشهر', '09103350226', '5', 'البرز', NULL, '<p>من در زمستان 1398 این فعالیت تجاری را شروع کردم فقط با یک آرزو خوشتیپ کردن تمام زنان کشور عزیزم ایران</p><p>با توجه به عدم وجود طرح ها و تنوع سلیقه ای مختلف محصولات زنان، تصمیم گرفتم پا به عرصه تولید محصولات مدرن و مورد نیاز این قشر از جامعه بگذارم. همچنین همزمان با افزایش قیمت شدید دلار و کاهش قدرت خرید مردم از برند های خارجی، تصمیم گرفتم تیمی از بهترین افراد توانمند تشکیل دهم تا طرح های خاص و زیبا را با بالا ترین کیفیت، در کشور خودمان ایران و با نیروی کار ایرانی تولید و عرضه کنیم، استراتژی ما تولید طرح های جدید روز دنیا است و با تولید در کارخانه به نقطه عطفی رسیدیم که این اتفاق در نهایت منجر به عرضه محصولات با قیمت بسیار بسیار عالی به مصرف کننده شد و برگ برنده ما در بازار ایران گردید.</p><p>امروز با حمایت مشتری های عزیزمان، خوشحال هستیم که افراد و پرسنل زیادی در کارخانه MF مشغول به کار هستند.</p>', NULL, NULL, '2023-10-23 10:15:43', '2023-10-23 10:22:44'),
(362, 2944, 'طوس تایماز', NULL, 'company-default.png', '153', 'مشهد', 'مشهد شهرک صنعتی فردوسی', '09155137331', '11', 'خراسان رضوی', NULL, '<p>کارخانه تولید مواد غذایی واقع در شهرک صنعتی فردوسی</p>', NULL, NULL, '2023-10-23 10:45:39', '2023-10-23 10:48:19'),
(363, 2945, 'گرم ایران', NULL, 'company-default.png', '153', 'مشهد', 'کارخانه: مشهد، بزرگراه آسیایی (پیامبر اعظم) نبش بلوار مهدیه', '(051)36516591', '11', 'خراسان رضوی', NULL, '<p>شرکت&nbsp;گرم ايران&nbsp;فعاليت خود را از سال 1359 با ساخت دو نوع مشعل گازسوز آغاز نمود و به تدريج ضمن بهره گیری از تکنولوژی و دانش، توانسته توانایی خود را در زمینه تولید انواع مشعل های گازسوز، گازوئيل سوز، مازوت سوز و چندگانه سوز از ظرفيت 20,000-30,000,000 kcal/h گسترش دهد بطوریکه امروز، گرم ایران پس از&nbsp;سی سال تلاش و تولید بیش از 700 هزار دستگاه انواع مشعل یکی از بزرگتربن و مطرح ترین تولیدکنندگان مشعل در سطح ملی می باشد.<br>&nbsp;</p>', NULL, NULL, '2023-10-23 11:08:23', '2023-10-23 11:19:40'),
(364, 2950, 'آراد نیک پی', NULL, 'company-default.png', '117', 'تهران', 'شرق تهران', '09127375286', '8', 'تهران', NULL, '<p>شرکت پیمانکاری و گود برداری&nbsp;</p>', NULL, NULL, '2023-10-29 09:07:48', '2023-10-29 09:30:37'),
(365, 2951, 'تولیدی پوشاک تینا', NULL, 'company-default.png', '117', 'تهران', 'تهران (منطقه ۷، خاقانی)', '(021)88842924', '8', 'تهران', NULL, '<p>تولیدی پوشاک تینا&nbsp;</p>', NULL, NULL, '2023-10-29 09:55:39', '2023-10-29 09:58:49'),
(366, 2952, 'صنایع ماشین سازی شاهین عدالت آرتا', NULL, 'company-default.png', '117', 'تهران', 'شهرک صنعتی صفادشت', '09303613283', '8', 'تهران', NULL, '<p>صنایع ماشین سازی</p><p>&nbsp;</p>', NULL, NULL, '2023-10-30 09:10:26', '2023-10-30 09:16:22'),
(367, 2954, 'پایاب بسپار', NULL, 'company-default.png', '153', 'مشهد', 'شهرک سازی ماشن سازی و فناوری های برتر', '09159298057', '11', 'خراسان رضوی', NULL, '<p>شرکت پایاب بسپار ایرانیان در زمینه تولید انواع قطعات مورد استفاده در صنعت آب و فاضلاب فعالیت می نماید. محصولات شرکت: - کیت انشعاب آب: دریچه کنتور، کمربند انشعاب و... - کیت انشعاب فاضلاب: درپوش فاضلابی، شیر خودکار فاضلابی و... - گروه تجهیزات فاضلاب شهری: منهول و دریچه منهول - گروه شیرآلات: شیر فلکه گازی برنجی، شیر خودکار برنجی و... - لوله و اتصالات: لوله و اتصالات پلی اتیلن، اتصالات لوله پنج لایه و... - گروه کنتورها: کنتورهای حجمی، کنتورهای خانگی و پیستونی - گروه تجهیزات کمکی: آچار انشعاب گیر فاضلاب، پلمپ کنتور و...</p>', NULL, NULL, '2023-11-01 07:28:52', '2023-11-01 07:40:26'),
(368, 2955, 'مواد غذائی فرد بهرنگ', NULL, 'company-default.png', '283', 'کرج', 'استان البرز، شهرستان چهار باغ، بخش رامجین، روستای دهکده طالقانی، خیابان 20متری دانش، خیابان دکترحسابی، پلاک 0، طبقه همکف', '09109308377', '5', 'البرز', NULL, '<p>تولیدی مواد غذایی فرد بهرنگ</p>', NULL, NULL, '2023-11-01 08:14:26', '2023-11-01 08:24:36'),
(369, 2956, 'بنیان ارتباط سهند فرهیختگان کیش', NULL, 'company-default.png', '283', 'کرج', 'کرج، ماهدشت، شهرک اقتصادی فرودگاه پیام، بلوار مادیران، فاز سوم، کوچه اول، شرکت بنیان ارتباط سهند', '09128237835', '5', 'البرز', NULL, '<h3><br>بستل تولیدکننده انواع تجهیزات مخابراتی پسیو و اکتیو رادیویی و نوری</h3><p>بستل تولیدکننده انواع تجهیزات مخابراتی پسیو و اکتیو رادیویی و نوری شامل انواع پیگتل و پچ کوردهای فیبرنوری سینگل مد و مالتی مد، انواع پچ پنل، آداپتور و اسپیلیتر فیبرنوری</p>', NULL, NULL, '2023-11-01 08:49:56', '2023-11-01 08:53:54'),
(370, 2957, 'رستوران چیز فکتوری', NULL, 'company-default.png', '117', 'تهران', 'منطقه ۴، حسین آباد', '09127600681', '8', 'تهران', NULL, '<p>رستوران</p>', NULL, NULL, '2023-11-01 09:27:40', '2023-11-01 09:29:42'),
(371, 2958, 'بازرگانی مدیران صنعت طاها', NULL, 'company-default.png', '117', 'تهران', 'منطقه ۲، سعادت آباد', '09122084296', '8', 'تهران', NULL, '<p><br>گروه <strong>بازرگانی</strong> ورزشی <strong>طاها</strong> با فعالیتی 18 ساله در <strong>صنعت</strong> ورزش، پس از واردات و پخش تجهیزات ورزشی خانگی (تردمیل و دوچرخه )و اعطای دهها نمایندگی به سراسر کشور، با توجه به نیاز روز افزون ورزشکاران و جامعه ورزش به لوازم بدنسازی با کیفیت باشگاهی، اقدام به واردات کلیه محصولات شرکت ام بی اچ اعم از هوازی و بدنسازی نمود</p>', NULL, NULL, '2023-11-01 11:14:41', '2023-11-01 11:18:03'),
(372, 2961, 'نام شرکت شما', NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2023-11-04 09:58:17', '2023-11-04 09:58:17'),
(373, 2962, 'واشر صنعت تندیس', NULL, 'company-default.png', '117', 'تهران', 'شهرک صنعتی دماوند 2، خیابان سعدی، پلاک 7', '02191318285', '8', 'تهران', NULL, '<p>شرکت واشر صنعت تندیس یا به اصطلاح STco با تجربه بیش از سه دهه فعالیت موفق در زمینه تولید و توزیع واشر خودروهای سواری افتخار دارد تا با همکاری با شرکت های بزرگ</p><p>خودروسازی کشور در زمینه تامین واشرهای خودرو با کیفیت و قیمت های رقابتی</p><p>گامی در جهت ارتقاء سطح کیفی واشرهای خودرو کشور بردارد.</p>', NULL, NULL, '2023-11-04 10:09:35', '2023-11-04 10:13:50'),
(374, 2963, 'توليدی نياكان', NULL, 'company-default.png', '117', 'تهران', 'تهران، ورامین، خیرآباد، خیابان بهرام مسیری، صنعت 8، پلاک 538', '09120351850', '8', 'تهران', NULL, '<p>تولید انواع چمدان ، کیف(کیف های زیارتی ، مسافرتی ، ورزشی ) ، همچنین کیف های مورد استفاده در سیستم حمل ونقل ریلی ، بیمارستانی</p>', NULL, NULL, '2023-11-04 10:31:32', '2023-11-04 10:34:09'),
