(378, 2971, 'فولاد گستر کیان جاودان', NULL, 'company-default.png', '153', 'مشهد', 'مشهد،بزرگراه چراغچی،خین عرب,بین طرح چی6و8مقابل بانک تجارت', '(051)36510000', '11', 'خراسان رضوی', NULL, '<p>لوله و اتصالات پروفیل</p>', NULL, NULL, '2023-11-06 11:20:46', '2023-11-06 11:27:26'),
(379, 2972, 'شاهان جهان آرا', NULL, 'company-default.png', '117', 'تهران', 'تهران محله آرژانتین ساعی تهران و خیابان بیست و هشتم', '09122166553', '8', 'تهران', NULL, '<p>شرکت فولاد&nbsp;</p>', NULL, NULL, '2023-11-06 11:55:58', '2023-11-06 12:04:51'),
(380, 2973, 'پولاد آبتین آرارات', NULL, 'company-default.png', '117', 'تهران', 'تهران بزرگراه شهید متوسلیان، فتح سیزدهم، مجتمع فولاد و استیل پایتخت، پلاک بی 30 و بی 31', '09939097236', '8', 'تهران', NULL, '<p>شرکت فناوران فولاد آبتین در سال 1389 با تصمیم و مشارکت جمعی از مدیران برگزیده صنعت فولاد کشور جهت ارائه انواع خدمات گسترده و متنوع جهت امور بهره برداری، نگهداری و تعمیرات، طراحی و مهندسی و همچنین تامین قطعات و تجهیزات در صنایع فولاد کشور خصوصاً آهن اسفنجی ایجادشده است. دیدگاه توسعه محور در ارتباط با ارتقای فرهنگ تولید و نگهداشت نیروی انسانی، پیشرو بودن در نوآوری و تمایز در ارائه خدمات به کارفرمایان، یک اصل حرفه‌ای بوده و به‌عنوان فلسفه وجودی سازمان دنبال می‌شود.</p>', NULL, NULL, '2023-11-06 12:53:56', '2023-11-06 12:59:52'),
(381, 2976, 'تعاونی آسا نگار پیشرو', NULL, 'company-default.png', '283', 'کرج', 'البرز، کرج، منطقه ۴، فاز چهار مهرشهر کرج، منطقه ۴، فاز چهار مهرشهر', '09125637366', '5', 'البرز', NULL, '<p>شرکت تعاونی آسانگار از سال ۱۳۹۳ با ایجاد یک کنسرسیوم متشکل از دانش آموختگان کارآفرینی و موسسات و مراکز مرتبط، اقدام به ایجاد یک شبکه حرفه ای جهت فعالیت به عنوان یک مرکز شتابدهی نموده است. بنیانگذاران احمد خیری – مشاور و نماینده شهردار کرج در مرکز توانمندسازی و تسهیل گری کسب و کارهای نوپای فاوا – مشاور رسانه ای شهردار کرج – دانشجوی دکترای کارآفرینی- مشاور بهبود و توسعه کسب و کار – عضو هیئت مدیره سازمان فرهنگی ورزشی شهرداری کرج و … حامد جمالی – مدیرعامل پست رسانه – رییس انجمن صنفی تبلیغات – مشاورتبلیغات، بازاریابی و فروش- فارغ التحصیل مدیریت ارشدMBA از دانشگاه وزارت بازرگانی- فارغ التحصیل دوره کارشناسی مدیریت فروش و بازاریابی دانشگاه تهران – موسس و صاحب امتیاز شبکه تبلیغات ایران (شَتا) – طراح و بهره بردار پروژه شبکه تبلیغات تلویزیونی مترو (مترو پیام) و … چشم انداز تاثیرگذاری بر افزایش نرخ اشتغال و رشد کارآفرینی در کشور و دستیابی به عنوان بهترین شتابدهنده منطقه از نظر تعداد و کیفیت استارتاپهای شتابدهی شده که ۲۰% از آنها قابلیت ارائه جهانی داشته باشند.</p>', NULL, NULL, '2023-11-07 08:40:36', '2023-11-07 08:45:29'),
(382, 2977, 'پرواستار', NULL, 'company-default.png', '284', 'نظر آباد', 'شهرک صنعتی نظر آباد، میدان کاج، قطعه g133', '09122715315', '5', 'البرز', NULL, '<p>دارویی، بهداشتی و سلامت - صنایع غذایی</p>', NULL, NULL, '2023-11-07 09:32:28', '2023-11-07 09:37:29'),
(383, 2978, 'نام شرکت شما', NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2023-11-08 09:02:47', '2023-11-08 09:02:47'),
(384, 2979, 'نام زعفران مصطفوی مهر ایرانیان', 'بیشتر از 200 نفر', 'company-default.png', '153', 'مشهد', 'شهرک صنعتی توس -فاز یک- نبش تلاش شمالی7', '05136226030', '11', 'خراسان رضوی', NULL, '<p>زعفران مصطفوی همانند بسیاری از تولید کننده های صنعتی بزرگ دنیا اهدافی چون رضایت مشتری، ارتقاء کیفیت، افزایش کمیت و کاهش قیمت را در دستور کار خود قرار داده است و با توجه به شرایط کنونی کشور و در راستای اجرای اهداف توسعه ای کشور عزیزمان ایران، ایجاد اشتغال و صدور تولیدات به سایر کشورها را نیز در برنامه خود قرار داده است و بر آن است تا با دستیابی به دانش و فن آوری روز جهان و ارائه کیفیت مطلوب تولیدات، آینده ای روشن را برای مجموعه تحت مدیریت خود رقم زند. ما اعتقاد راسخ داریم و خود را متعهد می دانیم که با تمام توان در نیل به اهداف از پیش تعیین شده تلاش نموده و محصولاتی ارائه دهیم که با استانداردهای جهانی مطابقت داشته باشد، ضمن برآورد نیاز بازارهای داخلی و خارجی به لحاظ کمی و کیفی، توان اقتصادی خود را با اتکا به تولیدات کارامد خود مستحکم تر نماییم و علاوه بر این خود را کانون آموزش و فراگیری سایر تولید کنندگان در این صنعت قرار دهیم.</p><p><br>&nbsp;</p><h2>بیانیه ماموریت شرکت زعفران مصطفوی:</h2><p><br>&nbsp;</p><p>ما به عنوان یک شرکت فعال در بزرگترین کشور تولید کننده و صادرکننده زعفران جهان، می خواهیم حامی و پرچم دار حرفه ای صنعت زعفران ایران در دنیا باشیم. می دانیم که موانع تجاری گوناگون، وجود تقلب و واسطه های متعدد و حضور رقبای مختلف، ما را با چالش های زیادی مواجه خواهد ساخت. ما در شرکت زعفران مصطفوی برای تحقق چشم انداز و رسالت خود عزمی راسخ داریم و رویکردهایی استراتژیک، بازارگرا، هم افزا و بین‌المللی اتخاذ کرده ایم. در همین راستا، نوآوری، تنوع در محصول و تمایز در خدمات را سرلوحه اقدامات خود قرار داده‌ایم. ما متعهد به نوآوری در کل زنجیره تامین زعفران؛ الگوگیری از برترین شرکت های جهان؛ بهره‌گیری از فناوری نوین فرآوری، انبارداری، توزیع و بازاریابی؛ رعایت ارزش‌های اساسی شرکت و توانمندسازی سرمایه انسانی خود هستیم. ما تلاش می‌کنیم بیشترین منافع تجاری، ارز‌آوری و اشتغال‌ زایی از «طلای سرخ ایران» را برای صنعت زعفران و مردم ایران به ارمغان بیاوریم.</p><p><br>&nbsp;</p>', NULL, NULL, '2023-11-08 12:55:42', '2023-11-08 13:06:16'),
(385, 2980, 'آمیتیس شیمی کار کیش', NULL, 'company-default.png', '117', 'تهران', 'منطقه سه جردن', '09128515493', '8', 'تهران', NULL, '<ul><li>تولید کننده انواع روانکار های مرغوب با فرمولاسیون اختصاصی</li><li>تولید بیش از ۱۳۰ قلم محصول از انواع روانکار شامل بنزینی و دیزلی و صنعتی</li><li>تحت نظارت و کنترل کیفیت روانکار ها از اتحادیه اروپا</li><li>لوبریفنت تمام استاندارد های ACEA را تحت پوشش دارد</li></ul><p><br>&nbsp;</p>', NULL, NULL, '2023-11-09 11:32:20', '2023-11-09 11:36:34'),
(386, 2981, 'مجموعه هشتگ کالا', NULL, 'company-default.png', '117', 'تهران', 'تهران،انقلاب،خ جمهوری اسلامی،پاساژ علاالدین،طبقه پنجم، پلاک 536.', '09121261666', '8', 'تهران', NULL, '<p>دفتر خدمات پس از فروش موبایل&nbsp;</p>', NULL, NULL, '2023-11-09 12:02:18', '2023-11-09 12:06:53'),
(387, 2982, 'کارتن سازی تاچ پک', NULL, 'company-default.png', '117', 'تهران', 'تهران محدوده سید خندان', '09395892237', '8', 'تهران', NULL, '<p>تولیدی انواع مختلف کارتن&nbsp;</p>', NULL, NULL, '2023-11-09 12:21:11', '2023-11-09 12:27:36'),
(388, 2983, 'غلات گستر شایان', NULL, 'company-default.png', '117', 'تهران', 'تهران بلوار نلسون ماندلا ، خیابان شهید بابک بهرامی ، پلاک 5 طبقه یک واحد دو', '02188646743', '8', 'تهران', NULL, '<p><br><strong>شرکت غلات گستر شایان در سال ۱۴۰۱ با محوریت تجارت روغن خام و نهاده های دام و طیور، توسط دکتر علیرضا شریفی (از مدیران با سابقه شرکت صنعتی بهپاک، شرکت صنعتی بهشهر، هلدینگ به پخش، شرکت روغن نباتی پارس قو، شرکت صادراتی زرین \"سرآمد صنایع بهشهر\"، مجتمع کشت و صنعت چین چین، شرکت توسعه کشت و صنعت اکسون، شرکت کیهان تجارت دایا \"یگانه خزر\"و شرکت صنایع غذایی دردانه) با مشارکت تعدادی سرمایه گذار تشکیل شد.</strong></p>', NULL, NULL, '2023-11-09 12:56:07', '2023-11-09 12:58:39'),
(389, 2984, 'محیط آب', 'کمتر از 20 نفر', 'company-default.png', '117', 'تهران', 'داراباد', '26120759', '8', 'تهران', NULL, '<p>شرکت مهندسین مشاور با پرسنل تحصیل‌کرده و جوان. محیطی آرام و صمیمی. پرسنل تحت پوشش بیمه تکمیلی. روزهای کاری شنبه تا چهارشنبه&nbsp;</p>', NULL, NULL, '2023-11-10 15:30:08', '2023-11-10 15:36:29'),
(390, 2985, 'پاک آرد', NULL, 'company-default.png', '283', 'کرج', 'شهرک صنعتی سیمین دشت، خیابان امید، بین خیابان سوم و چهارم شرقی، شرکت پاک آرد', '(026)36670972', '5', 'البرز', NULL, '<p>تولید ارد&nbsp;</p>', NULL, NULL, '2023-11-11 07:56:39', '2023-11-11 09:20:51'),
(391, 2986, 'آذین پوشش کوثر', NULL, 'company-default.png', '283', 'کرج', 'البرز، کرج، منطقه ۱، عظیمیه', '09363339973', '5', 'البرز', NULL, '<p>شرکت <strong>آذین پوشش کوثر</strong> از سال 1399 در تولید رنگ ، تینر و حلال <strong>های</strong> صنعتی <strong>فعالیت</strong> دارد.</p>', NULL, NULL, '2023-11-11 08:27:16', '2023-11-11 08:31:45'),
