(397, 2995, 'اطلس پود', 'تا 50 نفر', 'company-default.png', '117', 'تهران', 'ولیعصر پایین تر از پارک ساعی برج سپهر طبقه 7', '88554302', '8', 'تهران', NULL, '<p>&nbsp;اطلس پود با بیش از نیم قرن سابقه، بزرگترین تولید کننده و عرضه کننده بهترین منسوجات خانگی در ایران است. گفتنی است اطلس پود &nbsp;تولید کننده انواع پرده توری، پرده پارچه ای، رومیزی، روتختی، رو مبلی و .... می باشد.</p>', NULL, NULL, '2023-11-14 09:17:14', '2023-11-14 09:47:38'),
(398, 2996, 'آژانس گردشگری بادبان طلایی آسمان', 'کمتر از 20 نفر', '93f1309172722ded4115106e36a0a583.jpg', '117', 'تهران', 'بلوار میرداماد،میدان مادر، ابتدای خیابان شاه‌نظری، پلاک 59, طبقه اول واحد 1', '02191320030', '8', 'تهران', '40b4fce4d13390bd99077834c9fcf192.jpg', '<p>شرکت خدمات گردشگری بادبان طلایی آسمان بیش از 15 سال سابقه فعالیت در زمینه گردشگری دارد و مجری تورهای خارجی و داخلی، رزرو هتل و بلیط و اخذ ویزا است.</p>', NULL, NULL, '2023-11-14 10:29:17', '2023-11-21 10:25:48'),
