(401, 2999, 'فناوران دیار داریوش', NULL, 'company-default.png', '117', 'تهران', 'تهران – یوسف آباد - پله اول - خیابان شهید اکبری ( مستوفی ) پلاک 47 طبقه', '09398423574', '8', 'تهران', NULL, '<p>گروه دیار داریوش با هدف ارائه یک راهکار جامع و واحد به فعالان حوزه سلامت در امر تولید و تحقیق، و با اعتقاد به همکاری هرچه بیشتر بین واحد های مهندسی، طراحی، تامین، ساخت و اجرا، در سال 1394 با پشتوانه دانش و سوابق بیش از سه دهه فعالیت سهامداران و مدیران خود شکل گرفت. بر این اساس با همکاری تعدادی از شرکت ها بعنوان سهام دار و همکار عملا گروه ویژه ای تشکیل گردید تا ضمن تقسیم وظایف مدیریتی، پرسنلی و همچنین تقسیم فعالیت و امکانات، شرایطی فراهم گردد تا هر بخش با حفظ و توسعه توانایی های تخصصی ویژه خود، تضمین کننده فعالیت های گروه باشد.</p>', NULL, NULL, '2023-11-15 08:54:58', '2023-11-15 09:00:00'),
(402, 3000, 'کوماتسو برادران', NULL, 'company-default.png', '117', 'تهران', 'منطقه ۱۱، گمرک-هلال احمر خیابان قزوین، خیابان احمدی سخاء', '(021)55431675', '8', 'تهران', NULL, '<p>فروشگاه لوازم یدکی ماشین آلات</p>', NULL, NULL, '2023-11-15 09:21:03', '2023-11-15 09:33:16'),
(403, 3001, 'آریاپاکان بهنام', NULL, 'company-default.png', '117', 'تهران', 'تهران، منطقه ۲۲، شهرک راه آهن', '09195874002', '8', 'تهران', NULL, '<p>خدمات شهری و فضای سبز&nbsp;</p>', NULL, NULL, '2023-11-15 09:52:53', '2023-11-15 10:06:12'),
(404, 3002, 'الماس تراش غرب آسیا', NULL, 'company-default.png', '283', 'کرج', 'کرج کمال شهر.روبروی تامین اجتماعی.ساختمان فراز.طبقه3.واحد10', '09123669528', '5', 'البرز', NULL, '<p><br><strong>شرکت</strong> ارتباطات <strong>الماس آسیا</strong> در سال 1387 با هدف ارتقا و تسهیل ارتباطات، ایجاد سیتم ها امنیتی و نظارتی کارآمد و همچنین ایجاد شبکه های کامپیوتری با متد پیشرفته و بروز، <strong>فعالیت</strong> خود را آغاز کرد که در این راه موفق به اجرای پروژه های موفق و بزرگی شده و دستاوردهای ارزشمندی نیز کسب&nbsp;</p>', NULL, NULL, '2023-11-15 11:04:44', '2023-11-15 11:10:32'),
(405, 3003, 'شایان پمپ', NULL, 'company-default.png', '283', 'کرج', 'استان البرز کمالشهر', '34800066', '5', 'البرز', NULL, '<p>مرکز پخش و فروش پمپ شایان<br>فروش پمپ های آب خانگی صنعتی و کشاورزی<br>لوازم جانبی با کیفیت مناسب</p>', NULL, NULL, '2023-11-15 11:30:07', '2023-11-15 11:34:49'),
(406, 3004, 'آذر پاد مهر اسپندان', 'کمتر از 10 نفر', '8b01d45f7480cee9ac2ffd7b11aeb1ff.jpg', '134', 'شهریار', 'شهریار شهرک صنعتی گلگون خیابان اول جنوبی پلاک 41', '02165610698', '8', 'تهران', '', '<p>شرکت آذر پاد مهر اسپندان فعال در حوزه لوازم یدکی خودرو با سابقه ای بیش از 15 سال، دارای محیطی پویا و جوان می باشد که فرصتهای رشد و یادگیری برای نیروهای جوان و با انگیزه در این شرکت فراهم است.<br>در این شرکت روحیه کار تیمی و روابط دوستانه جاری است و کلیه پرسنل و مدیریت، پر انرژی جهت نیل به اهداف مجموعه مشغول به کار می باشند.</p>', NULL, NULL, '2023-11-18 07:25:23', '2023-11-18 07:56:04'),
(407, 3006, 'شرکت پخش سیلانه سبز', 'تا 200 نفر', 'company-default.png', '117', 'تهران', 'میدان نیلوفرخیابان سوم پلاک30', '021860300958', '8', 'تهران', NULL, '<p>شرکت پخش سیلانه سیبز درخصوص فروش محصولات بهداشتی ومراقبت ازپوست فعالیت میکند</p>', NULL, NULL, '2023-11-18 09:42:24', '2023-11-18 09:57:06'),
(408, 3008, 'گروه صنعتی آلتون رای', NULL, 'company-default.png', '283', 'کرج', 'ملارد، صفادشت، شهرک صنعتی صفادشت، بلوار فروردین، مابین خیابان پنجم و ششم غربی، پلاک 102', '02161945', '5', 'البرز', NULL, '<p>شرکت آلتون رای در سال 1374 فعالیت خود را با هدف توسعه اشتغال و ایجاد واحد های مختلف&nbsp; تحقیق و توسعه در زمینه الکترونیک آغاز کرد. این شرکت در سال 1377 خط مونتاژ قطعات الکترونیکی خود را راه اندازی کرد و با تقویت و تجهیز آن موفق به تولید انواع بردهای الکترونیک و دریافت مجوز تولید از وزارت صنایع و معادن شد و این برد ها را تاکنون در زمینه لوازم خانگی و صنایع روشنایی و الکترونیک تولید کرده است و هم چنان ادامه می دهد.</p><p>در سال 1379 این شرکت فعالیت خود را در زمینه و تولید تجهیزات ترافیکی آغاز کرد و در ادامه با تلاش مهندسان ایرانی و خلاق، تکنولوژی ساخت این محصول را از کشور تایوان گرفت و در کارخانه های شرکت خود تولید کرد.</p><p>در سال 1382 با روی کار آمدن استفاده از انرژی های پاک و انرژی خورشیدی، مجموعه آلتون رای تصمیم گرفت تا تکنولوژی انرژی خورشیدی را در محصولات خود اضافه کند و از شرکت های موفق در استفاده درست از این انرژی ها تبدیل شود.</p><p>در سال 1384 این شرکت تصمیم به استفاده از تکنولوژی LED در محصولات خود گرفت که مصرف انرژی بسیار کم ولی راندمان بسیار بالایی دارند.</p>', NULL, NULL, '2023-11-18 10:44:14', '2023-11-18 10:56:54'),
(409, 3009, 'نام شرکت شما', NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2023-11-18 11:13:49', '2023-11-18 11:13:49'),
(410, 3010, 'آذر شرق', NULL, 'company-default.png', '283', 'کرج', 'میدان سپاه ساختمان الوند', '09190330687', '5', 'البرز', NULL, '<p>مهندس مشاوره ای شهر سازی و راه سازی&nbsp;</p>', NULL, NULL, '2023-11-18 11:56:57', '2023-11-18 12:02:41'),
(411, 3013, 'پرچین تدبیر', 'کمتر از 20 نفر', 'company-default.png', '283', 'کرج', 'کرج گوهردشت بلوار شهرداری', '02634323860', '5', 'البرز', NULL, '<p>دارای رتبه ساختمان و تاسیسات و انجام پروژه های عمرانی و غیر عمرانی در بخشهای دولتی و خصوصی پروژه های اجرایی ساختمانی - صنعتی - لوله گذاری و بهره برداری صنعت آب و فاضلاب و قراردادهای خدماتی</p>', NULL, NULL, '2023-11-19 12:31:06', '2023-11-19 12:36:39'),
(412, 3014, 'مدیریت صادرات و تجارت داتیس البرز', NULL, 'company-default.png', '117', 'تهران', 'تهران یوسف اباد  بالاتر از پمپ بنزین ساختمان پارسا پلاک 449 طبقه 6 واحد 603', '09012828947', '8', 'تهران', NULL, '<p>شرکت داتیس البرز &nbsp;در زمینه فعالیت واردات و صادرات &nbsp;</p>', NULL, NULL, '2023-11-19 14:59:22', '2023-11-20 13:53:48'),
