(415, 3020, 'شرکت پایا کنترل الماس طوس', 'تا 150 نفر', 'company-default.png', '153', 'مشهد', 'مشهد-هاشمی رفسنجانی 34(میثاق سابق)-کاظمیه11-بعد از میدان ایمان-فضایلی8پلاک121', '09156624090', '11', 'خراسان رضوی', '908352058d98e548dd9720eba608da56.jpg', '<p>شرکت پایا کنترل الماس طوس دز زمینه ساخت تجهیزات آسانسور و پله برقی فعالیت دارد دفتر شرکت واقع در مشهد بلوار هاشمی رفسنجانی و کار خانه واقع در شهرک صنعتی کاویان می باشد.</p>', NULL, NULL, '2023-11-21 07:15:50', '2023-11-21 07:31:49'),
(416, 3021, 'آکواتیک استار ایرانیان', NULL, 'company-default.png', '117', 'تهران', 'تهران، منطقه ۳، قبا', '09128754398', '8', 'تهران', NULL, '<p><br>شرکت <strong>آکواتیک استار ایرانیان</strong> در سال 1384 به منظور تولید و توزیع آب آشامیدنی در بسته بندی <strong>های</strong> مختلف با نام تجاری سورپرایز آغاز گردید. هدف اصلی این شرکت برای ورود به بازار آب <strong>های</strong> بسته بندی ، ترویج بسته بندی 19 لیتری (5 گالن آمریکایی) با ارائه سرویس تحویل درب منازل و ادارات بوده است .</p>', NULL, NULL, '2023-11-21 07:28:20', '2023-11-21 07:31:26'),
(417, 3022, 'تولیدی و مهندسی شعله‌ صنعت', NULL, 'company-default.png', '117', 'تهران', 'تهران، خ ولیعصر، خ بزرگمهر، پ ۳۶ جدید', '09939661379', '8', 'تهران', NULL, '<p>شرکت تولیدی و مهندسی شعله‌صنعت با هدف پاسخگویی به این نیاز مبرم در سال ۱۳۶۷ توسط کارشناسانی با تجربه چندین ساله در صنایع نفت و گاز تشکیل شد و تاکنون به عنوان فعال‌ترین شرکت ایرانی نقش تعیین‌کننده‌ای در بهینه‌سازی سیستم سوخت‌رسانی و کنترل سوخت کوره‌های صنعتی ایران داشته است. این شرکت بعنوان بزرگترین تولیدکننده مشعل برای کوره‌های صنعتی در خاورمیانه با استفاده از تجربه شرکت‌های معتبر بین‌المللی، طراحی‌های خود را براساس آخرین پیشرفت‌های تکنولوژیک در زمینه سوخت و شعله‌دهی انجام می‌دهد.</p>', NULL, NULL, '2023-11-21 08:13:16', '2023-11-21 08:22:02'),
(418, 3023, 'آذین شیمی آرکا', NULL, 'company-default.png', '117', 'تهران', 'شهر تهران، محله پونک جنوبی ، کوچه شهید عباس مرادی [قدس] ، بلوار عدل ، پلاک 24 ، طبقه اول', '(021)44897245', '8', 'تهران', NULL, '<p>شرکت <strong>آذین شیمی آرکا</strong> تولید و وارد کننده نهاده <strong>های</strong> کشاورزی با بهترین کیفیت</p>', NULL, NULL, '2023-11-21 08:36:00', '2023-11-21 08:39:53'),
(419, 3024, 'بازرگانی ریور', NULL, 'company-default.png', '117', 'تهران', 'منطقه ۱۶، باغ آذری', '(021)55181483', '8', 'تهران', NULL, '<p>شرکت بازرگانی در زمینه لوازم اشپزخانه&nbsp;</p>', NULL, NULL, '2023-11-21 08:52:20', '2023-11-21 08:54:52'),
(420, 3025, 'دارویی بهداشتی لیوار', NULL, 'company-default.png', '117', 'تهران', 'تهران ، میدان ونک ، خیابان ملاصدرا، خیابان شیراز جنوبی ، خیابان گرمسار غربی ، کوچه بهار سوم ، پلاک 44', '(021)88607979', '8', 'تهران', NULL, '<ul><li>بهبود استانداردهای بهداشت و سلامت گروه‌های مختلف جامعه و کمک به تامین سلامت هموطنان عزیز از طریق معرفی، واردات، تولید و ارائه محصولات دارویی و&nbsp; بهداشتی و مکمل‌های تغذیه‌ای و طبیعی با کیفیت.</li><li>ایجاد اشتغال پایدار برای جوانان تحصیل کرده، متخصص و توانمند کشور.</li></ul><p>بازرگانی، تولید و پخش محصولات سلامت محور</p>', NULL, NULL, '2023-11-21 09:07:33', '2023-11-21 09:11:58'),
(421, 3026, 'مجتمع غذایی شبنم شکوهیه خاص', NULL, 'company-default.png', '117', 'تهران', 'تهران، منطقه ۶، سنایی میدان هفت تیر قائم مقام', '(021)88342085', '8', 'تهران', NULL, '<p>تولید کننده کنسرو ماهی&nbsp;</p>', NULL, NULL, '2023-11-21 10:31:01', '2023-11-21 11:42:55'),
(422, 3027, 'تراز ایده پرداز', NULL, 'ed5a3a578a50cb22a87c26fc7cee247b.png', '117', 'تهران', 'تهران ستارخان نرسیده به میدان توحید پلاک 168', '02149978000', '8', 'تهران', '7f5cf3397e8c41d1f0afd9b01610e575.png', '<p>شرکت تراز ایده پرداز تولید کننده ی نرم افزار حسابداری با نام تجاری «تیپ» میباشد نرم افزار حسابداری تیپ ویژه انجام امور مالی یک بنگاه اقتصادی شامل شرکتهای دولتی و خصوصی، تعاونی ها، کسب و کارهای بزرگ و کوچک و … می‌باشد که با توجه به نیاز شرکتها در حوزه های مختلف خدماتی، بازرگانی، تولیدی، پیمانکاری و همچنین مجموعه هایی که دارای فروش با حجم بالا می‌باشند طراحی و تولید شده است.</p>', NULL, NULL, '2023-11-21 13:19:55', '2023-11-21 13:33:04'),
(423, 3030, 'نام شرکت شما', NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2023-11-22 07:14:57', '2023-11-22 07:14:57'),
(424, 3031, 'شیدا پخش آدینه البرز', NULL, 'company-default.png', '283', 'کرج', 'کرج، خیابان چالوس (بلوار جانبازان)، کوچه شهید پهلوانی، پلاک 15 (شعبه مرکزی کرج)', '(026)91008484', '5', 'البرز', NULL, '<p>صنایع غذایی کیک و کلوچه</p>', NULL, NULL, '2023-11-22 07:21:27', '2023-11-22 07:28:05'),
