(430, 3037, 'نور تابان نور توس شرق', NULL, 'company-default.png', '153', 'مشهد', 'مشهد بلوار توس', '09155672198', '11', 'خراسان رضوی', NULL, '<p>تولید انواع چراغ های سقفی&nbsp;</p>', NULL, NULL, '2023-11-22 09:04:38', '2023-11-22 09:06:06'),
(431, 3038, 'پترو پمپ کیان', NULL, 'company-default.png', '117', 'تهران', 'منطقه ۱، ولنجک', '02134706', '8', 'تهران', NULL, '<p>شرکت کیان پترو صنعت خاورمیانه (KPS) با فعالیت مستمر در حوزه تعمیر و نگهداری تجهیزات و ماشین آلات صنایع نفت، گاز، پتروشیمی و معادن و همچنین تأمین کالاهای مورد نیاز صنایع آمادگی خورد را جهت همکاری اعلام می دارد.<br>فعالیتهای این شرکت عمدتاً در زمینه تامین و تعمیرات تجهیزات به شرح ذیل می باشد:<br>1. تعمیر تجهیزات مکانیکال، ماشین های دوار و تجهیزات ثابت پروژه های دریایی و خشکی: شامل انواع پمپها، کمپرسورها، توربین ها،انژکتور، گیربکس ها، الکتروموتورها و …</p>', NULL, NULL, '2023-11-22 09:17:18', '2023-11-22 09:21:25'),
(432, 3039, 'موسسه مدبران', NULL, 'company-default.png', '117', 'تهران', 'تهران_میدان انقلاب_خیابان انقلاب_نرسیده به 12 فروردین_پلاک 1330_طبقه سوم_واحد6', '66176350', '8', 'تهران', NULL, '<p>در حوزه <strong>فعالیت های</strong> حسابرسی ، حسابداری و ارائه خدمات مالی و مشاوره <strong>ای</strong> فعایت دارد</p>', NULL, NULL, '2023-11-22 09:28:08', '2023-11-22 09:30:14'),
(433, 3042, 'نام شرکت شما', NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2023-11-25 10:08:11', '2023-11-25 10:08:11'),
