(440, 3074, 'داروخانه دکترالیاسی', 'کمتر از 10 نفر', 'company-default.png', '117', 'تهران', 'تهران - م رسالت - خ ازادگان - قبل فرجام - پ 109', '02177274437', '8', 'تهران', NULL, '<p>داروخانه دکتر الیاسی&nbsp;</p>', NULL, NULL, '2023-12-04 15:15:48', '2023-12-05 16:18:49'),
