(447, 3092, 'صنعت ارتباطات و داده پردازی آسیا', NULL, 'company-default.png', '117', 'تهران', 'تهران پیروزی، جنب امام علی شمالی، خیابان کلینی، کوچه نوروزی شرقی، پلاک 16، واحد2', '09205760059', '8', 'تهران', NULL, '<p><strong>صنعت ارتباطات</strong> و <strong>داده پردازی آسیا</strong>,ایستگاه,ماکرویو,<strong>ارتباط</strong>,لینک,نگهداری,شارژر,طول موج,باطری,فیبرنوری,خاکی,هوایی,ماکروویو,رادیو,بیسیم, ترانک,48ولت,موج,مخابرات&nbsp;</p>', NULL, NULL, '2023-12-10 09:57:12', '2023-12-10 10:08:13'),
(448, 3094, 'نام شرکت شما   تدبیر محاسب', NULL, 'company-default.png', '283', 'کرج', 'کرح آزادگان خ مطهری - انتهای خ اردلان سوم', '02634610701', '5', 'البرز', NULL, '<p>شر کت ماارائه دهنده &nbsp;خدمات &nbsp;حسابداری &nbsp;و مالی و مالیاتی به اشخاص و مشا غل و شر کت ها &nbsp;می باشد .</p>', NULL, NULL, '2023-12-10 13:24:28', '2023-12-10 13:33:25'),
