(455, 3124, 'نان هانان', 'تا 50 نفر', '0e0a3fd08f57c1532a1bfba2cadf9a2a.jpg', '153', 'مشهد', 'بلوار امامت، امانت ۳۳، پلاک ۱', '05136037984', '11', 'خراسان رضوی', NULL, '<p>مجموعه تولیدی نان حجیم و نیمه حجیم(باگت و نیم باگت و مک‌دونالد) به صورت شبانه روزی با محیط امن و پرسنل عالی</p>', NULL, NULL, '2023-12-30 14:34:48', '2023-12-31 09:17:51'),
