(458, 3157, 'آرسا یدک ایرانیان گستر', 'کمتر از 20 نفر', '3c0d7ffaa84343133f8df02a92cd8c19.png', '117', 'تهران', 'بزرگراه آیت اله سعیدی، نرسیده به آزادگان، لنت پایتخت', '02155867234', '8', 'تهران', NULL, '<p>شرکت آرسا یدک ایرانیان گستر در زمینه فروش و توزیع عمده و خرده لنت ترمز و دیسک چرخ فعال می باشد</p>', NULL, NULL, '2024-01-08 13:50:49', '2024-01-08 14:06:56'),
(459, 3161, 'پیشگام انرژِی خاور', 'تا 50 نفر', '1bb9269e5c28bcc6f17806107f93f472.jpg', '153', 'مشهد', 'پارک علم و فناوری', '05135412354', '11', 'خراسان رضوی', NULL, '<p>شرکت دانش بنیان پیشگام انرژی خاور در پارک علم و فناوری خراسان در زمینه تولید و طراحی شیرآلات تقلیل فشار نفت و گاز پتروشیمی فعالیت دارد .</p><p>مزایای شغلی:</p><p>سرویس ایاب ذهاب-امنیت شغلی-محیط پویا -کارانه-هدایای مناسبتی-بیمه تکمیلی</p>', NULL, NULL, '2024-01-09 09:24:05', '2024-01-27 12:19:48'),
