(501, 3643, 'یونیک‌ کابین', 'کمتر از 20 نفر', 'f34396a0c123f638b177a8b020323ba1.png', '135', 'رباط کریم', 'سه راه آدران شهرک صنعتی زواره ای صنعت پنجم پلاک ۷۰', '09127600895', '8', 'تهران', '84dd2c161593b449c4d8287962bef3af.jpg,d9d915b87e5c1e8fad6b5bbd815adf61.jpg', '<p>طراح و تولید کننده انواع کابین آسانسور</p><p>طراح و تولید کننده انواع پایه موتور آسانسور</p><p>انواع براکت آسانسور&nbsp;</p>', NULL, NULL, '2024-04-17 12:33:01', '2024-04-17 12:41:19'),
(502, 3648, 'نام شرکت شما', NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-04-19 22:32:50', '2024-04-19 22:32:50'),
(503, 3649, 'نام شرکت شما', NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-04-20 05:05:57', '2024-04-20 05:05:57'),
(504, 3651, 'ایمن دیده بان شبکه', 'تا 100 نفر', '102ac4cad1a7914374c13aff82f30f1e.jpg', '117', 'تهران', 'مطهری - فجر - پ 34', '021-88493085', '8', 'تهران', NULL, '<p>بازرگان خرید و فروش قطعات کامپیوتری وارکننده برند hp</p><p>شركت ایمن دیده¬بان شبكه با هدف ارائه راه حل هاي جامع فن آوري اطلاعات، در سال 1388 تأسيس گردید و از زمان شروع به فعاليت، با بهره گيري از توانمندي همكاران خود و ارتباطات تجاري با شركاي خارجي توانسته<br>است گامهاي مؤثري را در پاسخ به نيازهاي مشتریان گرامي در حوزه هاي تأمين، پشتيباني و نگهداری تجهيزات و ارائه راه حلهاي فني بردارد .&nbsp;<br>در همين راستا این شركت با كوششي پيگير توانسته است امكان عرضه تجهيزات HP Server &amp; Storage&nbsp;<br>و خدمات پشتيباني سانيار را همگام با استاندارد هاي شركت Infortrend NASفراهم نماید .</p><p>&nbsp;</p>', NULL, NULL, '2024-04-20 10:02:38', '2024-04-20 10:24:27'),
(505, 3653, 'خانه مکمل', 'کمتر از 10 نفر', '85071e76546bca4ffbb1074440af27fa.jpg', '117', 'تهران', 'تهران ، صادقیه ، بلوار آیت الله کاشانی خیابان بهنام بعداز چهارراه فهیمی جنب فروشگاه افق کوروش پلاک ۱۶ واحد ۱۲', '02144976510', '8', 'تهران', NULL, '<p>شرکت پخش مکمل ورزشی از شما عزیزان در\n\nسمت حسابدار دعوت به همکاری می نماید\n\nجنسیت:&nbsp; خانم \n\nسن : تا ۴۰ سال \n\nمدرک تحصیلی :&nbsp; لیسانس\n\nمسلط به حسابداری فروش\n\nمسلط به وورد و اکسل\n\nدارای حداقل ۳ سال سابقه \n\nمسلط به هلو \n\nمحاسبه حقوق و دستمزد\n\nمزایا : \n\nحقوق ثابت \n\nبیمه تامین اجتماعی \n\nاضافه کاری \n\nمحیط کاملا اداری \n\nاتاق جداگانه \n\n\n\n\nمتقاضیان لطفاً رزومه خود را جهت بررسی و انجام مصاحبه در واتساپ ، تلگرام ، دیوار &nbsp;ارسال نمایید</p>', NULL, NULL, '2024-04-20 11:34:33', '2024-04-20 12:40:53'),
(507, 3666, 'نام شرکت شما', NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-04-20 20:17:23', '2024-04-20 20:17:23'),
(508, 3678, 'نام شرکت شما', NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-04-21 11:53:35', '2024-04-21 11:53:35'),
(509, 3679, 'آب‌نبات‌چوبی', 'تا 100 نفر', 'aedb7cd5a7f56efb7852382265f96f61.png', '117', 'تهران', 'سعادت آباد، میدان کتاب', '09102049309', '8', 'تهران', NULL, '<p>گروه آبنبات چوبی بزرگ‌ترین و تنها مجموعه شکلات فروشی زنجیره‌ای با چندین شعبه در تهران و شهرهای دیگر در زمینه فروش انواع پاستیل، شکلات، آبنبات،پک های هدیه و... می باشد.</p><p>&nbsp;با توجه به تجربه چندین ساله مدیران گروه آبنبات چوبی در کشور سوئد در زمینه فروش پاستیل و شکلات و همکاری با برندهای معتبر و آشنایی با استانداردهای روز دنیا، ایده ایجاد فروشگاه هایی مشابه با فروشگاه های بزرگ خارجی در ایران شکل گرفت و اولین شعبه در سال 1394 افتتاح گردید. استقبال بی نظیر مشتریان از ایده فروشگاه آبنبات چوبی زمینه را جهت افزایش تعداد شعب و تنوع محصولات فراهم آورد به طوری‌که هم اکنون حدود 100 هزار نفر در باشگاه مشتریان مجموعه آبنبات چوبی عضو بوده و بیش از 210 هزار نفر در صفحه اینستاگرام ما را دنبال می‌کنند.</p>', NULL, NULL, '2024-04-21 12:56:31', '2024-04-23 12:31:53'),
(510, 3690, 'سلامت پوست من', 'کمتر از 10 نفر', 'company-default.png', '283', 'کرج', 'کرج هفت تیر', '۰۹۱۰۲۳۳۰۳۰۷', '5', 'البرز', NULL, '<h2>فعال در زمینه لوازم آرایشی بهداشتی</h2>', NULL, NULL, '2024-04-22 10:48:17', '2024-04-22 11:02:33'),
