(523, 3897, 'عایق گسترچهلستون', NULL, 'fa4156a073359d92e3e1103758752a26.png', '117', 'تهران', 'میرداماد خیابان سنجابی کوچه هشتم پلاک دو طبقه سوم', '26709513', '8', 'تهران', '', '<p>شرکت چهلستون تولیدکننده انواع&nbsp; در و پنجره آلومینیومی، UPVC با شیشه‌های دو جداره، فعالیت خود را &nbsp;در سال ۱۳۴۵با تولید در و پنجره‌های آهنی &nbsp;آغاز کرد و در سال ۱۳۵۸ با ساخت و نصب در و پنجره‌های آلومینیومی، حوزه فعالیتش را گسترش داد.در حال حاضر شرکت چهلستون علاوه بر در و پنجره آلومینیومی، upvc &nbsp;&nbsp;و شیشه، برای تامین نیاز مشتریان و تکمیل محصولاتش، خدمات خم&nbsp; و لمینیت&nbsp; پروفیل و توری را هم در اختیار سفارش‌دهندگان قرار می‌دهد.</p>', NULL, NULL, '2024-05-11 08:48:02', '2024-05-11 09:03:39'),
