(585, 4073, 'جی ام آی', NULL, 'company-default.png', '117', 'تهران', 'خ ۲۷ آزادگان ش ۳۵', '۰۲۱۸۸۳۵۸۶۳۱', '8', 'تهران', NULL, '<p>شعبه شرکت خارجی آلمانی بازرگانی است &nbsp;همچنین پروژه هم داریم تولیدی و صنعتی&nbsp;</p>', NULL, NULL, '2024-06-19 17:16:14', '2024-08-23 16:26:51'),
(586, 4074, 'بازرگانی یراق ام دی اف', NULL, 'company-default.png', '153', 'مشهد', 'خین عرب کشاورز', '09151183714', '11', 'خراسان رضوی', NULL, '<p>حسابدار&nbsp;</p>', NULL, NULL, '2024-06-19 18:52:12', '2024-06-19 18:57:00'),
(587, 4075, 'آژانس هواپیمایی ملیکاسیر', NULL, '64ffd97854cba8d90de50aaa6343f709.jpg', '117', 'تهران', 'تهران بلوار میرداماد،بین شمس تبریزی و نفت شمالی پلاک 203', '021-91005404', '8', 'تهران', NULL, '<p>دفتر خدمات مسافرتی <strong>ملیکاسیر</strong> با بیش از ۲۰ سال تجربه در صنعت گردشگری و جهانگردی مفتخر است که با پشتیبانی مسئولین گرامی خود توانسته است به عنوان یکی از معتبرترین دفاتر خدمات مسافرتی کشور در خدمتگزاری در این بخش ارزشمند کوشا باشد.فعالیت شرکت در داخل و خارج از کشور و …. می باشد که اطمینان دارد با پشتیبانی همیشگی در این راه موفقیت های بیشتری را کسب خواهیم نمود. <strong>برخی از فعالیتهای این شرکت عبارتند از:</strong> • امکان عقد قرارداد ویژه با شرکت های بزرگ با شرایط پرداخت و تخفیفات ویژه&nbsp; • استفاده پرسنل شرکت ها از تورهای داخلی و خارجی با اقساط ۴ تا ۹ ماهه فقط با چک بدون ضامن • ارائه خدمات به سایر دفاتر خدمات مسافرتی در چهارچوب قانونی&nbsp; • ارائه خدمات اخذ ویزای شنگن از آلمان , فرانسه , پرتغال , اتریش&nbsp; • ارائه خدمات اخذ ویزا مولتی شنگن&nbsp; • ارائه خدمات اخذ ویزای ۵ ساله (مولتی)کانادا با دعوتنامه معتبر از سمت ملیکاسیر&nbsp; • اخذ اقامت کشور کانادا&nbsp; • اخذ پذیرش تحصیلی تضمینی از کانادا (دبستان تا دانشگاه)&nbsp; • ارائه خدمات پیکاپ ویزای آمریکا , کانادا&nbsp; • اخذ اقامت کشور آلمان&nbsp; • ارائه خدمات جهت رفع ویزای ریجکت شده و اخذ مجدد ویزا از طریق کشور آلمان&nbsp; • مجری مستقیم کلیه تورهای تخصصی نمایشگاهی آلمان&nbsp; • تنظیم پروازهای چارتر داخلی و خارجی&nbsp; • مجری تورهای متنوع اروپایی , روسیه و کلیه ی کشورهای آسیایی&nbsp; • ارائه خدمات راهنمایان مجرب آشنا به زبانهای مختلف از جمله انگلیسی ، آلمانی ، اسپانیایی و …. • تنظیم و برگزاری تورهای داخلی طبیعت گردی , ماجراجویی، فرهنگی ، تاریخی&nbsp; • فعالیت گسترده در جذب توریستهای خارجی به ایران&nbsp; • امکان صدور گواهینامه بین المللی • استفاده از سیستم های انلاین جهت رزرو هتل در سراسر دنیا حداقل ۱۰% ارزانتر از نرخ های بازار • رزرو هتل در سراسر ایران&nbsp; • استفاده از سیستم های آنلاین جهت صدور کلیه بلیط های خارجی که مبدا و مقصد خارج از ایران باشند&nbsp; • برگزارکننده همایش ها و سمینارهای تخصصی در ایران&nbsp; • ترانسفر فرودگاه امام خمینی با هزینه مناسب تومان از سرتاسر تهران و شهرستان کرج&nbsp; • امکان صدور بلیط کلیه شرکتهای هواپیمایی خارجی که مبدا و مقصد از ایران باشد • نماینده فروش سیستم شرکت های هواپیمایی :&nbsp; • لوفت هانزا , ایرفرانس , ترکیش ایرلاین , امارات , قطر ایرویز , الاتحاد , ایران ایر , ماهان , هواپیمایی یونان , عمان ایر، کی ال ام</p>', NULL, NULL, '2024-06-20 08:18:48', '2024-06-20 08:42:53'),
(588, 4076, 'بنیان فولاد شبستری', 'کمتر از 10 نفر', 'company-default.png', '117', 'تهران', 'صادقیه بلوار آیت الله کاشانی تقاطع بلوار اباذر ساختمان بانک کشاورزی پلاک 49 طبقه 4 واحد 45', '44962573', '8', 'تهران', NULL, '<p>شرکت بنیان فولاد شبستری از سال 1398 تأسیس شده که فعال در حوزه عمده فروشی آهن آلات است در حال رشد و پیشرفت می باشد ، نیروی انسانی برای ما بسیار اهمیت دارد و امنیت شغلی از نکات مثبت همکاری با این مجموعه است.&nbsp;</p><p>ما در این مجموعه به همکاران پرتلاش و پر انرژی ، خلاق و تعالی محور نیاز داریم .</p><p>برخورداری از حقوق قانونی همکاران برای ما اهمیت دارد.</p>', NULL, NULL, '2024-06-20 09:33:05', '2024-06-26 09:47:22'),
(589, 4083, 'نام شرکت شما', NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-06-23 08:13:40', '2024-06-23 08:13:40'),
(590, 4085, 'مانا بتن سخت اسپادانا', NULL, 'company-default.png', '117', 'تهران', 'خیابان قائم مقام فراهانی- میدان شعاع', '02188317608-11', '8', 'تهران', NULL, '<p>شرکت مانا بتن سخت اسپادانا با بیش از 18 سال تجربه در زمینه کف سازی و اجرای هزاران پروژه در سطح کشور یکی از پیشرو ترین شرکت های فعال صنعت کف سازی در ایران می باشد.</p>', NULL, NULL, '2024-06-23 11:30:52', '2024-06-24 05:56:27'),
(591, 4086, 'نام شرکت شماشرکت بازرگانی پرگاس شیمی راشین', NULL, 'company-default.png', '117', 'تهران', 'پاسداران دشتستان پنجم پلاک۲۸', '۲۲۸۹۰۵۰۵', '8', 'تهران', NULL, '<p>خرید و فروش وبازاریابی محصولات شیمیایی</p>', NULL, NULL, '2024-06-23 12:45:22', '2024-06-23 12:49:43'),
(592, 4092, 'گروه کاشی و سرامیک ایمانی', 'کمتر از 20 نفر', 'bf093e9034d3ccd4cd61c0ba767e5ca0.jpg', '283', 'کرج', 'کرج جاده ملارد خیابان گلستان ۲۹ نیلوفر ۱۱', '09362353800', '5', 'البرز', '7af6de57752d4913b34d6d93419d1ccc.jpg,87139412b84d8dba7039a6b0b941c0d5.jpg', '<h2>گروه کاشی و سرامیک ایمانی</h2>', NULL, NULL, '2024-06-24 13:56:38', '2024-06-24 14:05:18'),
(593, 4093, 'نام شرکت شما', NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-06-24 18:03:06', '2024-06-24 18:03:06'),
(594, 4101, 'نام شرکت شما', NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-06-26 08:26:52', '2024-06-26 08:26:52'),
(595, 4104, 'عسل تغذیه خراسان', 'تا 150 نفر', '91075f188e3484843d1d472e4bdc0b97.jpeg', '153', 'مشهد', 'شهرک صنعتی توس، فاز یک', '35412042', '11', 'خراسان رضوی', '7ae944f61892e520cd5e3862a2d93860.png', '<p>شرکت تولیدی عسل تغذیه خراسان، تولید کننده انواع بستنی و فرآورده های کنجدی مفتخر است با پشتوانه نزدیک به نیم قرن تجربه و دارا بودن دانش و تکنولوژی روز دنیا، تولیدات خود را در دو دسته سنتی با برند حاج حسن و صنعتی با برند بلوط با بهترین کیفیت، تولید وعرضه نماید؛ و بر این اساس ضمن استفاده از مرغوب ترین مواد اولیه و همچنین بهترین کنجد ایرانی، بروزترین و پیشرفته ترین تجهیزات تولید و کنترل را تحت نظارت کارشناسان مجرب و آزمایشگاه های پیشرفته بکار گرفته تا علاوه بر افزایش رضایت مشتریان خود، با ارائه محصولات با کیفیت برتر، سلامت را به هموطنان عزیز هدیه دهد.</p>', NULL, NULL, '2024-06-26 11:21:58', '2024-06-26 11:56:24'),
(596, 4105, 'تصمیم سبز هوشمند', 'کمتر از 10 نفر', 'd1373cd149e606bc049db4a6773f8875.png', '117', 'تهران', 'تهران، ضلع جنوبی ميدان وليعصر، خیابان ولدی، پلاک 38، واحد 4', '88851105', '8', 'تهران', NULL, '<p><a href=\"http://tasmimsabz.com/\"><strong>شرکت تصمیم سبز هوشمند</strong></a><strong> به عنوان یک شرکت فعال در زمینه آموزش الکترونیک در سال ۱۳۸۸ توسط یک هیئت مدیره با تجربه مدیریت بالا و سابقه طولانی در امر آموزش و مرتبط با فناوری های روز دنیا با هدف تولید و ارائه تجهیزات جدید آموزشی و ابداع تکنولوژی های آموزشی نوین بنیانگذاری شده است.</strong></p><p>&nbsp;</p><h3><strong>چشم انداز های ما</strong></h3><p>سرمایه گذاری در راستای تولید محصولات دانش بنیان و نیز ارائه خدمات آموزشی، تکنیکی و مشاوره ای در حوزه آموزش و پرورش و مطابق با استاندارهای وزارت آموزش و پرورش گام های بلندی را در جهت توسعه و بهبود ابزارها و سیستمهای تدریس هوشمند برداشته و همچنین سعی بر آن داشته تا در جهت ارتقاء و تعالی سطح دانش فناوری اطلاعات مدرسان و دانش آموزان و سایر اساتید فعال در بخش آموزش، قدمی هر چند کوچک بردارد.</p><p>&nbsp;</p><h3><strong>هوشمند سازی آموزش</strong></h3><p>تصمیم سبز یک مجموعه کامل از هوشمند سازی و متد های شناخته شده روز دنیا در حیطه آموزش هوشمند را در اختیار مدارس، دانشگاه ها و مراکز آموزشی با شرایط ویژه و منحصر به فرد قرار می دهد. نرم افزار تصمیم سبز خود یک نرم افزار منحصر به فرد برای تدریس الکترونیکی می باشد این نرم افزار مبتکرانه مبتنی بر کتاب بوده و انجام هر نوع تدریس هوشمند را امکان پذیر می سازد.</p><p>&nbsp;</p><h3><strong>فعالیت های شرکت</strong></h3><p>از جمله فعالیت های تصمیم سبز می توان به موارد زیر اشاره کرد:</p><p>۱- تولید و گسترش تکنولوژی های جدید لمسی و تصویری<br>۲- تولید نرم افزار تدریس الکترونیکی<br>۳- ارتباطات با مدارس و دانشگاه ها<br>۴- تجهیزات هوشمند سازی و لوازم جانبی مورد نیاز</p><p>&nbsp;</p><h3><strong>شعار همیشگی ما</strong></h3><p>در شرکت <strong>تصمیم سبز</strong> ما می خواهیم محصولات و راهکارهایی کیفی ارائه نماییم که پاسخگوی تمامی نیازهای شما در <strong>آموزش هوشمند</strong>، برگزاری <strong>جلسات ارائه موفق و تبلیغات به شیوه های نوین</strong> امروز باشد.</p>', NULL, NULL, '2024-06-26 11:34:38', '2024-06-30 10:14:56'),
