(601, 4122, 'شرکت معماری کنام دال', NULL, 'company-default.png', '283', 'کرج', 'عظیمیه ، بلوار شریعتی ،روبروی پمپ بنزین مهران ،برج تجاری و اداری مهراد', '09369184162', '5', 'البرز', NULL, '<p>شرکت طراحی و نظارت و اجرا در حوزه ابنیه</p>', NULL, NULL, '2024-06-30 14:23:23', '2024-06-30 14:27:56'),
