(615, 4167, 'کمپرسورسازان سپهر پارس', NULL, '01707588e2d83913c7a2f8192c669255.jpeg', '153', 'مشهد', 'مشهد فلسطین 12 ساختمان کندو  طبقه دوم واحد 6', '05137663042', '11', 'خراسان رضوی', NULL, '<p>یک مجموعه معتبر در <strong>استان خراسان رضوی، شهر مشهد</strong> جهت تکمیل کادر خود از متقاضیان ساکن <strong>استان خراسان رضوی</strong> استخدام می‌نماید</p>', NULL, NULL, '2024-07-25 10:23:44', '2024-07-25 10:28:18'),
(616, 4173, 'بنیان درمان', 'تا 50 نفر', 'bc290e82f059b2009a20df3ad4ab13ae.jpg', '117', 'تهران', 'ولیعصر پایین تر از پارک ساعی روبروی کوچه بیستم برج نگین ساعی طبقه 5 واحد 504', '02188703050', '8', 'تهران', 'da92d75c1689c0742ecdd233ef628f17.jpg', '<p><strong>شرکت بنیان درمان</strong> در سال 1383(2004) &nbsp;توسط یک تیم مهندس پزشک تأسیس و طی سالهای اخیر با فعالیت گسترده در زمینه بازاریابی ، فروش و خدمات پس از فروش و با حضور در بسیاری از نمایشگاههای داخلی و بین المللی توانسته جایگاه خیلی خوبی برای خود در بازار ایران ایجاد نماید. شرکت بنیان درمان با در اختیار داشتن توان علمی و فنی و با تکیه بر نیروهای خود موفق به رسیدن به بالاترین سطح رضایتمندی مشتریان شده است.</p><p>این شرکت در سال 2010 موفق به اخذ نشان استانداردهای ISO 9001 و ISO 13485 &nbsp;شده است و قبل از آن برای افزایش راندمان و ارتباط با مشتریان و کنترل و مدیریت بهتر خدمات شرکت مجهز به نرم افزار CRM و سایر نرم افزارها و ادوات مورد نیاز جهت بخش خدمات پس از فروش شده است. هم اکنون شرکت بنیان درمان در دو زمینه آزمایشگاهی و پزشکی فعالیت می نماید.</p><p>این شرکت با همکاری با نمایندگان فعال و معتبر در استانهای مختلف سراسر کشور تلاش می نماید تا در سریعترین زمان ممکن بهترین خدمات را به مشتریان خود ارائه نماید.همچنین محصولات این شرکت از معتبرترین تامین کنندگان جهانی تامین میشوند.</p>', NULL, NULL, '2024-07-27 09:46:26', '2024-07-27 09:55:42'),
(618, 4178, 'شرکت بازرگانی ساریکا', 'تا 50 نفر', 'company-default.png', '153', 'مشهد', 'مشهد میدان شهدا', '09152238093', '11', 'خراسان رضوی', NULL, '<p>شرکت بازرگانی در زمینه فروش و لیزینگ لوازم خانگی و تجهیزات آشپرخانه و کالای دیجیتال</p>', NULL, NULL, '2024-07-30 10:59:33', '2024-07-30 11:02:09'),
