(622, 4219, 'گروه ساختمان سازی لاکچری', 'تا 50 نفر', '213f89c83815174b885baca9bfffc052.png', '60', 'اصفهان', 'سعادت آباد', '03131315151', '4', 'اصفهان', NULL, '<p>گروه ساختمان سازی لاکچری واقع در خیابان سعادت آباد اصفهان از حسابداران دعوت به همکاری می نماید</p>', NULL, NULL, '2024-08-18 13:22:09', '2024-08-18 13:31:34'),
