(626, 4333, 'بلسیبسی', NULL, 'company-default.png', '51', 'پارس آباد', 'سبسیبسیبسیب', 'سیبسیبسی', '3', 'اردبیل', NULL, '<p>سیبسیبشسیبسیبشسیبشسیبسشیبسیشبشسیبشسیب</p>', NULL, NULL, '2024-11-11 12:53:57', '2024-11-11 12:54:20'),
(627, 4350, 'کاربرگ', 'کمتر از 10 نفر', 'company-default.png', '1', 'تبریز', 'هاشمیه', '8688904', '1', 'آذربایجان شرقی', NULL, '<p>ما به دنبال ایجاد ارتباط واضح و شفاف بین کارفرمایان و کارجویان هستیم تا هر دو طرف بتوانند نیازهای خود را به بهترین شکل برآورده کنند. هدف ما در های‌حساب ارائه محیطی است که کاربران به راحتی بتوانند اطلاعات مربوط به شغل‌های مختلف را مشاهده کرده و به آسانی به فرصت‌های شغلی مناسب برای خود دست پیدا کنند.</p>', NULL, NULL, '2024-12-16 12:25:44', '2024-12-16 12:27:16'),
(629, 4355, 'پخش  فراگیر ایران', 'تا 100 نفر', 'company-default.png', '179', 'اهواز', 'جاده اهواز  اندیمشک روبه روی رهگشا', '09375394995', '13', 'خوزستان', NULL, '<p>استخدام &nbsp;حسابدار &nbsp;دارای &nbsp;پیش زمینه &nbsp;از &nbsp;حسابداری &nbsp;و رشته تحصیلی &nbsp;مرتبط ساعت کاری &nbsp;7/30 لغایت &nbsp;16/30 حقوق &nbsp;طبق اداره کار &nbsp;</p>', NULL, NULL, '2024-12-24 11:55:36', '2024-12-24 11:58:09'),
(630, 4360, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-01-12 12:30:20', '2025-01-12 12:30:20'),
(631, 4372, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-01-12 13:55:12', '2025-01-12 13:55:12'),
(632, 4382, 'ایلیا زیست فناور', NULL, 'company-default.png', '117', 'تهران', 'تهران، خیابان شریعتی، پایین‌تر از حسینیه ارشاد، کوچه ویرا، پلاک ۱، واحد ۵', '09357016001', '8', 'تهران', NULL, '<p>شرکت ایلیا زیست فناور یک مجموعه تخصصی در حوزه زیست‌فناوری و خدمات ژنومیکس است که با هدف ارائه راهکارهای نوآورانه در زمینه‌های مرتبط با علوم زیستی، سلامت، و فناوری‌های پیشرفته تأسیس شده است. این شرکت با بهره‌گیری از تیمی مجرب و متخصص و به‌کارگیری دانش روز دنیا، در طراحی و تولید محصولات زیست‌فناوری، ارائه خدمات تحقیق و توسعه (R&amp;D)، و انتقال فناوری فعالیت می‌کند. آزمایشگاه ژنتیک پزشکی ویرا به عنوان یکی از &nbsp;آزمایشگاه‌های مرجع در ایران، یکی از زیر مجموعه‌های شرکت ایلیا زیست فناور می‌باشد.</p><p>ایلیا زیست فناور با تمرکز بر حوزه‌های کلیدی مانند زیست‌داروها، کیت‌های تشخیصی، و تجهیزات آزمایشگاهی، به‌دنبال بهبود کیفیت زندگی افراد و توسعه پایدار در صنعت زیست‌فناوری است. این شرکت با همکاری نزدیک با دانشگاه‌ها، مراکز تحقیقاتی و صنایع مرتبط، به دنبال ایجاد ارزش افزوده و تأمین نیازهای داخلی و بین‌المللی است.</p><p>چشم‌انداز ایلیا زیست فناور، تبدیل شدن به یکی از پیشگامان زیست‌فناوری و خدمات ژنومیکس در منطقه است. این مجموعه با تعهد به کیفیت، نوآوری، و مسئولیت‌پذیری اجتماعی، در مسیر تحقق اهداف خود گام برمی‌دارد.&nbsp;</p><p><br>&nbsp;</p>', NULL, NULL, '2025-01-18 19:47:35', '2025-01-18 19:52:49'),
(633, 4394, 'پدیده تجارت شکیبا', 'تا 50 نفر', '9bca6fbef9c8a1a19c8361592ff3e42a.png', '117', 'تهران', 'خیابان مقدس اردبیلی', '52316', '8', 'تهران', NULL, '<p><strong>شرکت پدیده تجارت شکیبا” در سال ۱۳۸۵ با هدف تامین مصالح ساختمانی به ویژه در زمینه کاشی و </strong><a href=\"https://seraset.com/product-category/slab-ceramic/\"><strong>سرامیک اسلب</strong></a><strong> و چینی بهداشتی درجهت پاسخگویی مشتریان تاسیس گردیده است .پس از گذشت یک دهه و جذب مخاطبان خاص در سال&nbsp; ۱۳۹۵ و به منظور ارتقاء سطح کیفی و کمی محصولات&nbsp; برند “سِراسِت”&nbsp; ثبت گردید</strong></p>', NULL, NULL, '2025-01-25 08:27:00', '2025-01-25 08:29:48'),
(634, 4411, 'هیراب سان', 'تا 150 نفر', '7dc162f365bacf296947d6e90bb27847.jpg', '117', 'تهران', 'تهران خیابان بهشتی - خیابان قائم مقام کوچه میرزا حسنی پلاک 2 طبقه 2', '88705045', '8', 'تهران', NULL, '<p>شـركـت هیـراب سـان با هـدف انتقـال تكنـولـوژی روز دنیـا در زمینـه شیـوه هـای مـدرن تصفیـه آب برای امـاکـن مسـكونـی ، تجـاری و صنـایع مختلف توسـط گـروهـی از مهندسـان كـار آزمـوده در سـال ۱۳۸۲ پایـه گـذاری گردیـد و از سال 1400 مشغول به تولید در داخل کشور می باشد.&nbsp;</p>', NULL, NULL, '2025-02-06 18:27:32', '2025-02-06 18:41:08'),
(636, 4435, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-03-09 14:18:33', '2025-03-09 14:18:33'),
(637, 4442, 'زی ما کاژه', NULL, 'company-default.png', '117', 'تهران', 'باللتر از چهار راه پارک وی نرسیده به تجریش خیابان کیارستمی کوچه دلبر پلاک۹', '02122208886', '8', 'تهران', NULL, '<p>شرکت زیما در زمینه طراحی نظارت ساخت و اجرا فعالیت میکند،و در دو بخش فاز 1 و 2 معماری به صورت تخصصی خدمات ارائه میدهد، از سال 1398 فعالیت خود را شروع کرده و با پایان رساندن پروژه های گوناگون در سراسر ایران، به صورت ویژه توانمدی خود در حوزه ی بازسازی و ساخت انواع واحد های تجاری و مسکونی به اثبات رسانده. این مجموعه از ابتدا تا آخرین لحظه با فراهم آوردن بهترین شرایط و با استفاده از گروه های اجرایی قوی خود با استاندارد بالا تحویل پروژه را به صورت کاملا حرفه ای محقق میسازه.&nbsp;<br>مجموعه زیما در تلاش هست با تکیه بر نیروهای توانمند و حرفه ای مسیر روشن تر و دقیق تری را برای اهداف سازمانی خود ایجاد کند و همواره بکوشد تا در اجرای خواسته ها و سلایق کارفرمایان پروژه ها بهترین خود را به نمایش بگذارد.<br>روح طراحی کردن همه جا ی اینجا هست امیدواریم چشماتون درخششیو که ما به عنوان نشونه (رد پا) به جا گذاشتیم ببینه.</p>', NULL, NULL, '2025-03-14 00:03:48', '2025-03-14 00:05:56'),
