(651, 4509, 'آزماپژوهان کامیاب صنعت', NULL, 'db23b7579248421f5968e36009e58811.jpg', '117', 'تهران', 'حکیمیه ، دانشگاه ازاد واحد تهران شمال ، ساختمان پژوهشگاه ، طبقه منفی یک ، واحد ۱۲۶/۲', '02177319346', '8', 'تهران', NULL, '<p>شرکت تجهیزات پزشکی&nbsp;</p>', NULL, NULL, '2025-04-11 19:21:03', '2025-04-11 19:25:48'),
