(655, 4534, 'پیشتاز صنعت', NULL, '6b2dbf08acb2957ecc2ece02748aae65.jpeg', '117', 'تهران', 'تهران دکتر شریعتی کوچه آهور پلاک 30/1 ط 4 واحد 403', '36429009', '8', 'تهران', NULL, '<p>شرکت در زمینه تولیدی فعالیت دارد&nbsp;</p><p>ریخته گری قطعات منگنزی و ضد سایش</p>', NULL, NULL, '2025-04-21 09:18:34', '2025-04-21 09:39:12');
