(656, 4536, 'دیوانچو', 'کمتر از 10 نفر', '37c62c4d319bb2bc6615580e423a540b.jpeg', '232', 'شیراز', 'شهرک صنعتی بزرگ شیراز', '09199081397', '17', 'فارس', NULL, '<p>تولید کننده کلیه مصنوعات چوب و ام دی اف ، دکوراسیون داخلی و بازسازی…</p>', NULL, NULL, '2025-04-21 11:14:29', '2025-04-21 11:22:16'),
(657, 4541, 'محمد قبول حسابدار رسمی', 'تا 50 نفر', '0765ee2324254740fe70822827e61aaf.jfif', '117', 'تهران', 'صادقیه', '09931895872', '8', 'تهران', '3c6221923bf2e8d2531b331161dbb0c0.jfif,2b56bdc05cd76a5296e6bc4c4b2c2520.jfif,edd1a94497861db4720c968b04e700d9.jfif,ffbadcc3edc2871eeda5820fe086bc51.jfif,5219a866222c89b9b567a6b0b310f394.jfif,b5c2073b99e4412fbc1d1fa68228ecfc.jfif', '<p>حسابدار رسمی / کارشناس رسمی دادگستری / مشاور مالی و مالیاتی ، عضو کارگرو های تخصصی&nbsp;</p>', NULL, NULL, '2025-04-22 14:13:38', '2025-04-22 14:35:53'),
(658, 4557, 'تدارکات پیشرفته تک فارمد آسیا', 'تا 50 نفر', '0faffeba58b2fceb17df7ba2873e4203.png', '117', 'تهران', 'ایران، تهران، خیابان سهروردی شمالی، بالاتر از اپادانا، کوچه سراب، پلاک ۶، واحد ۸', '88505587', '8', 'تهران', NULL, '<p>تامین قطعات الکترونیک صنایع خودرو و پزشکی مواد اولیه دارویی</p><p>مزایای کاری: بسته های رفاهی ، پاداش ، دورکاری روزهای خاص …</p><p>فرهنگ کاری : اولویت ما نظم ،تعهد به تخصص ، تیم ورک ، دقت عمل ، رفتار سازمانی</p>', NULL, NULL, '2025-04-27 12:06:52', '2025-04-27 12:26:04'),
(659, 4568, 'ایرانیان دوخت تندی', 'تا 50 نفر', '8689e932b531ca1af93214f4315c9674.jpeg', '118', 'ورامین', 'ورامین شهرک صنعتی خیراباد صنعت اول کوچه اول سمت چپ پلاک۹', '09121196212', '8', 'تهران', NULL, '<p>اشنا به سپیدار واکسل حقوق ودستمزد</p><p>انبارگردانی</p>', NULL, NULL, '2025-04-29 16:44:33', '2025-04-29 16:48:00'),
(660, 4573, 'شرکت زرتاب ایرانیان', 'تا 50 نفر', 'company-default.png', '1', 'تبریز', 'تبریز بازار', '04133333333', '1', 'آذربایجان شرقی', NULL, '<p>جذب افراد متخصص و کاربلد</p>', NULL, NULL, '2025-05-01 22:42:12', '2025-05-01 22:45:16'),
(661, 4578, 'صنایع چوبی آرنا', 'کمتر از 20 نفر', 'company-default.png', '130', 'چهاردانگه', 'چهاردونگه خیابان زارع کوچه امین پلک ۲', '۰۹۱۰۶۵۰۰۵۷۵', '8', 'تهران', NULL, '<p>ما به عنوان عضو کوچکی از این صنعت بزرگ از سال ۱۳۸۱ در رشته فروش و تولید مبلمان اتاق خواب نوجوان و بزرگسال مشغول فعالیت می باشیم و در سال ۱۳۸۶ کار حرفه ای خود را با برند سرای ماندگار آغاز نمودیم. در سال ۱۳۸۹ جزء سهامداران اصلی کارخانه‌ای به مساحت ۷۵۰۰ مترمربع واقع در شهرک بهسازی صنایع چوب ایران بوده ایم &nbsp;و پس از آن به صورت مستقل از سال ۱۳۹۱ تولید حرفه ای سرویس خواب دو نفره و نوجوان را تحت برند سرای ماندگار پیش بردیم و این بار در جهت تولید با کیفیت و استفاده از مواد اولیه مرغوب و نیروهای کارآزموده و از همه مهمتر به روز رسانی تجهیزات &nbsp;و طرح های قابل ارائه به صورت مستقل و مجزا با شعار صادقانه: « ما می توانیم » تحت برند آرنا سهم کوچکی از اقتصاد ایران عزیز را خواهیم داشت..</p>', NULL, NULL, '2025-05-03 09:54:16', '2025-05-11 16:32:00'),
(663, 4588, 'شرکت تولیدی ، بسته بندی', 'تا 150 نفر', 'd27f7e6864302d348bbfd2db88c0a7e3.jpg', '117', 'تهران', 'آفریقای شمالی (جردن )', '88779365', '8', 'تهران', '', '<p>با بهره گیری و آموزش کادر مجرب فنی و واحد تحقیق و توسعه موفق به کارگیری بالاترین استانداردهای رایج تولید و محصول مطابق کشورهای پیشرفته گردیده و این تلاش مستمراٌ ادامه دارد.<br>&nbsp;</p>', NULL, NULL, '2025-05-12 14:31:16', '2025-07-30 17:29:19'),
(665, 4602, 'فناوری آینده سپید پارس(فیوتک)', NULL, 'cc75e69c33c847ff289244e9cc34d25a.jpeg', '153', 'مشهد', 'بولوار پاسداران', '051-5150', '11', 'خراسان رضوی', NULL, '<h4><strong>معرفی شرکت</strong></h4><p>شرکت فناوری آینده سپید پارس (فیوتک )<br>از 1398 شروع به کار کردیم , زمینه اصلی شرکت کارهای مخابراتی می باشد:<br><br>*فروش محصولات باند پهن مخابرات (ADSL , VDSL , FTTH )<br>*تحویل و پشتیبانی مشترکین مخابرات خراسان رضوی<br>*فروش و نصب و راه اندازی RADIO<br>*تامین تجهیزات مخابراتی<br>*طراحی شبکه های مخابراتی<br>*توسعه فیبر نوری (پروژه های مخابراتی )در شهر مشهد<br>و ...<br>تمامی این فعالیت ها در محیطی کاملا پویا و پرتلاش با هماهنگی های منظم و دقیق بین همکاران در حال انجام می باشد.</p>', NULL, NULL, '2025-05-18 12:03:23', '2025-05-18 12:28:40'),
(666, 4603, 'موسسه حسابداری همراه یار خردمند', 'کمتر از 20 نفر', 'cc1ee6852963e70ff7c184517853148e.jpg', '117', 'تهران', 'شهران شمالی - خیابان یکم (شهید نعمت الهی) - ساختمان سامان - طبقه 4 - واحد 21', '02144326908', '8', 'تهران', NULL, '<p>موسسه حسابداری و آموزشی همراه یار خردمند به عنوان یک موسسه حسابداری علاوه بر ارائه خدمات مالی و مالیاتی و حسابرسی داخلی برای پرسنل شاغل در موسسه کلاسهای آموزشی متنوع و رایگان برگزار نموده و علاوه بر بهره مندی دانش و تجربه کارکنان محیط مناسب جهت ارتقاء سطح علمی و عملی فراهم می آورد.</p>', NULL, NULL, '2025-05-18 17:29:56', '2025-05-18 17:37:54'),
(668, 4614, 'ماهان ترانس', 'تا 200 نفر', 'company-default.png', '117', 'تهران', 'میدان آرژانتین خ بخارست مابین خ 19 و 21 پلاک 24 طبقه سوم واحد جنوبی', '88703576', '8', 'تهران', NULL, '<p>این شرکت در زمینه حمل و نقل بین المللی فعالیت دارد&nbsp;</p>', NULL, NULL, '2025-05-24 13:52:00', '2025-05-24 13:54:24'),
(670, 4636, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-06-01 11:48:28', '2025-06-01 11:48:28'),
(671, 4649, 'گرین وب سامانه نوین', 'بیشتر از 200 نفر', 'a92c096789883c4e56e95f2d771fa4e2.png', '153', 'مشهد', 'مشهد، حاشیه بلوار خیام، بین خیام 31 و 33', '05137638100', '11', 'خراسان رضوی', NULL, '<p>شرکت گرین‌وب با سرمایه نیروی انسانی نخبه و متخصص و با پشتوانه مشتریانی وفادار و ماندگار و در کنار توکل بر خدا مسیر طولانی پیشرفت را با سرعتی زیاد طی کرده است و هم اکنون در کنار بزرگان صنعت فناوری اطلاعات و با در نظر گرفتن پیشرفت و توسعه کشور عزیزمان در حوزه‌های فناوری اطلاعات چشم به افق‌هایی دوخته است که در آن صادرات خدمات فنی و مهندسی فناوری اطلاعات به بزرگترین قدرت‌های این حوزه انجام پذیرد و در این مسیر بعنوان صادرکننده برتر خدمات فنی و مهندسی در حوزه فناوری اطلاعات در سال 95 و صادر کننده نمونه ملی در حوزه فناوری اطلاعات در سال 1401 انتخاب گردید.</p>', NULL, NULL, '2025-06-08 14:35:44', '2025-06-10 10:05:07'),
(672, 4652, 'شرکت پدیده پارسیان توس', 'تا 100 نفر', 'b97441915e707b45f6035c9dd622dc37.jpg', '153', 'مشهد', 'شاندیز - نبش ولیعصر 11 - رستوران پدیده شاندیز', '05134281701', '11', 'خراسان رضوی', 'e5fc621ae05027a5c2e388809ddd0678.jpg,e2630620e350857dfc4821e598fc3243.jpg,5045834784001fbb776c1495abded399.jpg', '<p>شرکت پدیده پارسیان توس</p><p>مالک برند رستوران پدیده شاندیز</p><p>&nbsp;</p>', NULL, NULL, '2025-06-09 18:04:20', '2025-06-09 18:12:26'),
(673, 4672, 'خدمات نیرو گاهی آهار شرق', NULL, '8c06f29c7d69d7c2dba3d608908b3dbf.jpg', '153', 'مشهد', 'خراسان رضوی - مشهد - کیلومتر 12 جاده آسیایی، پارک علم و فناوری خراسان، ساختمان آهار', '۰۵۱-۳۵۴۲۴۱۰۰', '11', 'خراسان رضوی', NULL, '<p>شرکت خدمات نیروگاهی آهار از سال 1379 فعالیت خود را در زمینه اتوماسیون صنعتی و ساخت کارت‌های الکترونیکی آغاز نموده است. از همان ابتدا بخش عمده‌ای از فعالیت‌های شرکت در بخش انرژی معطوف بود. از سال 1385 شرکت سیاست تخصص‌گرایی را اتخاذ نموده و با تشخیص نیازهای عمده کشور در صنایع بالادستی، فعالیت‌های خود را در سایر صنایع متوقف و با سرمایه‌گذاری در حوزه تولید دانش دارای تکنولوژی‌های بالا و بومی‌سازی این بخش در صنایع انرژی ماموریت خود را تعریف نمود. اهداف میان‌مدت انتخاب شده در این مسیر، بومی‌سازی کامل سیستم‌های کنترل مورد نیاز صنایع انرژی‌محور شامل نیروگاه، پالایشگاه، پتروشیمی و نفت و گاز می‌باشد. سیستم‌های کنترل انواع توربین‌های گازی و بخار، سیستم‌های تحریک ژنراتور و تجهیزات جنبی مربوطه از این دست بوده است. هم‌اکنون ساختمان شرکت آهار با وسعت 1800 متر مربع در پارک علم و فناوری خراسان مستقر بوده و از شرکت‌های دانش‌بنیان پیش‌رو محسوب می‌گردد.</p>', NULL, NULL, '2025-06-16 08:38:00', '2025-06-16 09:31:49'),
(674, 4676, 'گروه صنعتی چیکا', 'تا 200 نفر', 'company-default.png', '75', 'مبارکه', 'شهرک صنعتی مبارکه', '09308550520', '4', 'اصفهان', NULL, '<p>شرکت صنایع غذایی چیکا تولید کننده پیشرو محصولات غذایی با کیفیت مستقر در شهرک صنعتی مبارکه با چندین شرکت زیرمجموعه و با هدف توسعه &nbsp;محصول و بازار خود از فناوری پیشرفتع برای خلق غذاهای اماده و انواع سالاد و کنسرو فعالیت مینماید &nbsp;</p><p>به تیمی پویا با فرصت های رشد و مزایای رقابتی بپیوندید..</p>', NULL, NULL, '2025-06-27 19:42:47', '2025-06-27 19:47:46'),
(676, 4685, 'Bv', NULL, 'company-default.png', '53', 'مشکین شهر', 'Hggv', '09136568988', '3', 'اردبیل', NULL, '<p>Jhug</p>', NULL, NULL, '2025-07-03 00:03:53', '2025-07-03 00:04:45'),
(677, 4693, 'هوای مطبوع خاور', 'کمتر از 20 نفر', 'company-default.png', '153', 'مشهد', 'بین سناباد 60و 58 پلاک 882 واحد 1', '05138455444', '11', 'خراسان رضوی', NULL, '<p>شرکت هوای مطبوع در زمینه تاسیسات و تهویه مطبوع با پیش از 30 سال قدمت و تجربه</p>', NULL, NULL, '2025-07-13 08:15:21', '2025-07-13 08:21:58'),
(678, 4700, 'نوشین شهد گلسان توس', 'تا 100 نفر', 'db37860c8374c01a5b96a18494f48f4c.jpg', '167', 'چناران', 'شهرک صنعتی چناران فاز 2 دانش 3 سمت چپ قطعه سوم', '05146188566', '11', 'خراسان رضوی', NULL, '<p>تولید کننده قند و نبات&nbsp;</p>', NULL, NULL, '2025-07-16 07:54:31', '2025-07-16 08:56:00'),
(679, 4705, 'نوشین شهد گلسان توس', NULL, 'company-default.png', '167', 'چناران', 'شهرک صنعتی چناران فاز 2 دانش 3', '05146188566', '11', 'خراسان رضوی', NULL, '<p>تولیدی قند و نبات&nbsp;</p>', NULL, NULL, '2025-07-19 13:57:08', '2025-07-19 13:59:04'),
(680, 4708, 'نت لوب ایران ( کاسترول )', 'تا 200 نفر', 'company-default.png', '117', 'تهران', 'میدان آرژانتین - خیابان الوند', '88643388', '8', 'تهران', NULL, '<p>شرکتی فعال و پویا در زمینه تولید روغن موتور با کیفیت بسیار بالا و با استانداردهای کاسترول بین الملل با حدود 150 نیروی کارآمد در زمینه های تولید ، بازاریابی ، فروش ، مالی و اداری</p>', NULL, NULL, '2025-07-20 09:10:26', '2025-07-20 09:15:05'),
(682, 4711, 'های حساب', 'کمتر از 20 نفر', 'company-default.png', '153', 'مشهد', 'امامت۴۰', '91012030', '11', 'خراسان رضوی', NULL, '<p>شرکت های حساب به نیروی حسابدار نیازمند است</p>', NULL, NULL, '2025-07-20 17:15:09', '2025-07-20 17:18:15'),
(683, 4713, 'گستران فولاد', NULL, 'company-default.png', '117', 'تهران', 'اهن مکان  نبش فاز ۷ شرقی', '٠٩٢٠١٢٣٨٥١٥', '8', 'تهران', NULL, '<p><strong>نيازمند حسابدار خانوم به صورت غير رسمى</strong></p><p>منطقه صالح اباد شرقى مسلط به برنامه هلو&nbsp; و مسلط به دفتر نويسى</p>', NULL, NULL, '2025-07-21 15:30:13', '2025-07-21 15:32:54'),
(684, 4714, 'نوین کابل همراه', 'تا 50 نفر', 'f3312ae2cd60ecd993ebf8c32e2671c4.jpg', '117', 'تهران', 'تهران،جمهوری،خیابان شیخ هادی،خیابان رجب بیگی،کوچه عبدوس،پلاک 43،طبقه3 واحد 5', '02166979862', '8', 'تهران', '', '<p>شرکت ما در زمینه تولید کابل‌های موبایل و لوازم جانبی فعالیت می‌کند. با بهره‌گیری از تیمی متخصص و تجربه‌ی گسترده، عملیات تولید، خدمات بازرگانی، واردات و حمل‌ونقل را ارائه می‌دهیم. خطوط تولید ما با بهره‌گیری از فناوری‌های پیشرفته و رعایت استانداردهای بین‌المللی، محصولاتی با کیفیت بالا را عرضه می‌کنند. شرکت خارجی ما در چین، نقش کلیدی در تأمین و واردات کالاهای باکیفیت دارد. همچنین، فروشگاه ما در بازار چارسو، مرکز ارائه‌ی محصولات متنوع و خدمات مشتری‌محور است. هدف ما ارائه محصولات برتر و خدمات حرفه‌ای در صنعت موبایل است.</p>', NULL, NULL, '2025-07-21 16:03:48', '2025-09-20 09:28:00'),
(685, 4723, 'مرجان کهسار', NULL, 'company-default.png', '244', 'جهرم', 'شهرک صنعتی کوثر', '07154483083', '17', 'فارس', NULL, '<p>تولید قند&nbsp;</p>', NULL, NULL, '2025-07-23 18:16:26', '2025-07-23 18:22:13'),
(686, 4732, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-07-24 13:12:03', '2025-07-24 13:12:03'),
(688, 4747, 'شرکت بهین تجارت کیان پارس', 'کمتر از 10 نفر', 'company-default.png', '60', 'اصفهان', 'اصفهان خیابان امام خمینی خیابان امیرکبیر پلاک ۱۶۲', '۳۳۸۶۶۷۴۸', '4', 'اصفهان', NULL, '<p>بهین تجارت کیان پارس یک مجموعه خانوادگی و در حال رشد در حوزه توزیع رینگ و لاستیک خودروهای سواری و سنگین در اصفهان است. با تکیه بر تجربه، تعهد و شناخت بازار، در مسیر تبدیل به سازمانی ساختارمند و شفاف گام برمی‌داریم. محیط کاری ما صمیمی، منظم و رو‌به‌توسعه است و فرصت یادگیری و رشد در آن فراهم می‌باشد.</p><p><br>&nbsp;</p>', NULL, NULL, '2025-07-26 11:21:34', '2025-07-26 11:32:11'),
(689, 4760, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-07-26 15:06:31', '2025-07-26 15:06:31'),
(690, 4762, 'مشاوران مالی اطمینان بخش', 'کمتر از 10 نفر', 'ac840e68e62f5c37acbc85ecc4d736c3.jpg', '153', 'مشهد', 'توس 103 ساختمان باراد پلاک 2', '09150333715', '11', 'خراسان رضوی', NULL, '<p>شرکت <strong>مشاوران مالی اطمینان‌بخش</strong> در سال ۱۴۰۳ با ابتکار و تأسیس<br><strong>الیاس دائمی</strong> و <strong>علی روشندل</strong> – از فعالان و متخصصان حوزه مالی، حسابداری و مشاوره کسب‌وکار – فعالیت خود را آغاز نمود.</p><p>این شرکت با هدف <strong>ایجاد سودآوری پایدار برای کسب‌وکارها</strong> و <strong>ایجاد اطمینان خاطر برای مدیران نسبت به عملکرد واحد مالی</strong> شکل گرفته است. ما باور داریم نام «اطمینان‌بخش» گویای رسالت ماست:<br>ارائه <strong>راهکارهای مطمئن</strong> برای تصمیم‌گیری‌های مالی مدیران.</p><p><strong>شعار ما:</strong><br><i>راهکارهای مطمئن</i></p><h3>حوزه فعالیت و خدمات</h3><p>شرکت مشاوران مالی اطمینان‌بخش، ارائه‌دهنده جامع خدمات مالی، مالیاتی و مشاوره‌ای به کسب‌وکارهای پویا و در حال رشد است، از جمله:</p><p>ارائه خدمات <strong>مشاوره مالی و مالیاتی</strong></p><p>استقرار، پیاده‌سازی و بهینه‌سازی <strong>سیستم‌های مالی</strong></p><p>تهیه اصولی و استاندارد <strong>صورت‌های مالی جداگانه و تلفیقی</strong></p><p>تهیه و ارائه گزارش‌های کلیدی مالی شامل:</p><p>بودجه‌های عملیاتی، نقدی، تولید و فروش</p><p>گزارش‌های تحلیلی و مدیریتی</p><p><strong>جذب، آموزش و پرورش نیروی انسانی متخصص مالی</strong></p><p>نظارت حرفه‌ای بر عملکرد واحدهای مالی</p><p>سیستم‌سازی و طراحی فرآیندهای مالی در شرکت‌ها</p><p>آماده‌سازی حساب‌ها جهت:</p><p>حسابرسی مستقل</p><p>حسابرسی و رسیدگی تأمین اجتماعی</p><p>انجام <strong>حسابرسی داخلی</strong></p><p>استقرار و ارائه خدمات <strong>سامانه مودیان</strong></p><p>تهیه و تنظیم <strong>لوایح دفاعیه</strong> و حضور در هیأت‌های حل اختلاف مالیاتی و بیمه‌ای</p><p>تحلیل گزارش‌های مالی و بررسی جریان‌های نقدی</p><p>طراحی و استقرار <strong>سیستم بهای تمام‌شده و کنترل هزینه (Cost Control)</strong></p><p>تهیه آیین‌نامه‌ها و دستورالعمل‌های مالی و معاملاتی شرکت‌ها</p><p>تهیه و ارائه گزارش‌های:</p><p>پایداری و تداوم فعالیت</p><p>مدیریت ریسک</p><p>تحلیل عملکرد مالی و ارزیابی سودآوری</p><p><strong>تأمین مالی</strong> و مشاوره در ساختار سرمایه</p><p>تعیین و تدوین <strong>استراتژی مالی</strong></p><p>کمک به <strong>حل اختلافات مالی و تجاری کسب‌وکارها</strong></p><p>و سایر خدمات تخصصی مورد نیاز کسب‌وکارهای حرفه‌ای در حوزه مالی</p><p><strong>مشاوران مالی اطمینان‌بخش</strong> همراه مدیران است تا واحد مالی را از یک بخش اجرایی صرف، به <strong>مرکز تصمیم‌سازی، کنترل و خلق ارزش</strong> در کسب‌وکار تبدیل کند.</p>', NULL, NULL, '2025-07-26 17:18:59', '2025-12-21 10:50:44'),
