(696, 4784, 'نسیم صادرات راد', NULL, 'cada1f857f63b14f4e10dbfb3de835fb.jpg', '117', 'تهران', 'خ ولی عصر روبروی پارک ملت نبش خ انصاری برج ملت طبقه ۱۰ واحد ۷', '۲۶۲۳۰۹۹۸', '8', 'تهران', NULL, '<p>ساعت کاری شرکت از ساعت ۸:۳۰ تا 17:45 ، پنجشنبه ها تعطیل</p>', NULL, NULL, '2025-07-28 10:09:17', '2025-07-28 13:30:29'),
(697, 4786, 'فناوران هوشمند نیکان', 'تا 50 نفر', '251385d2696b165af2680f1ea4916724.png', '153', 'مشهد', 'جاده مشهد فریمان ۴ کیلومتر بعد از تپه سلام  جاده نیروگاهی نیکان', '05133534040', '11', 'خراسان رضوی', NULL, '<p>شرکت نیروگاهی نیکان تنها شرکت دانش‌بنیان در زمینه موتور ژنراتور در ایران می باشد. این شرکت در سال ۱۳۸۹ فعالیت خود را در زمینه مشاوره واحدهای نیروگاهی و صنعتی در تبریز آغاز کرده و در سال ۱۳۹۲ با تاسیس دفتر مرکزی فروش در مشهد پا به عرصه احداث نیروگاه های مقیاس کوچک chp گذاشت. و همچنان فعالیت خود را در زمینه خدمات مشاوره ای تجدید ساختار و بهینه سازی سیستم های برقی و سنکرون سازی و … ادامه داده است. شرکت نیکان دارای پنج محصول که تاییدیه دانش بنیان دریافت کرده اند، از جمله سیستم کنترلی (برد ECU) موتور ژنراتورهای گازسوز، دیزلی و دوگانه سوز می باشد.</p><p>مفتخریم اعلام کنیم که شرکت نیکان برای نخستین بار در کشور طراحی و تولید سیستم‌های کنترل ECU را انجام و به مدت هفت سال بر روی موتور ژنراتورهای خود نصب و در حالت دائم کار در نیروگاه خود مورد بهره برداری قرار داده که باعث افزایش ۲۰ درصدی راندمان موتور می شود. و جای خوشبختی است که این محصول هم اکنون به تولید انبوه رسیده و بیش از صدها نمونه از آن روانه بازار شده است. شرکت نیکان تنها شرکت دانش‌بنیان در زمینه تولید و مونتاژ انواع موتور ژنراتور با برندهای معتبر دورمن، مان، ولوو، ایویکو، بنز، اسکانیا و … که دارای نمایندگی‌هایی در شهرهای تهران، مشهد، تبریز، اهواز و اصفهان می باشد، <a href=\"http://www.motorsazan.ir/?PageID=76&amp;StateID=11\"><strong>دارای نمایندگی فروش پرکینز موتورسازان</strong></a> و همچنین دارای کارخانه تولید موتورهای دیزلی در تبریز (بنیان دیزل سابق) و تولید موتور ژنراتورهای پایه گازسوز در مشهد است.</p><p>با توجه به تحریم ها امکان مانیتورینگ موتور ژنراتور در ایران وجود ندارد و شرکت نیکان تنها تولید کننده این کالای استراتژیک کنترل از راه دور موتور ژنراتور، در ایران می باشد.</p><p>در پی این امکان (مانیتورینگ) مفتخریم با بهترین تکنسین های فنی در ۲۴ ساعت شبانه روز، از راه دور موتور ژنراتور شما را عیب یابی و در کمترین زمان ممکن به ارائه خدمات پشتیبانی فنی و خدمات پس از فروش بپردازیم….</p><h3><strong>دستاوردها:</strong></h3><p>طراحی و تولید نخستین برد سنکرون موتور ژنراتور<br>طراحی و تولید نخستین برد دوسوخته موتور ژنراتور<br>طراحی و تولید نخستین پاورمتر<br>طراحی و تولید نخستین برد کنترل گاورنر<br>طراحی و تولید نخستین برد محافظ شیربرقی<br>طراحی و تولید برد کنترلی ECU<br>طراحی و تولید سامانه مانیتیورینگ موتور ژنراتور<br>طراحی و تولید نخستین موتور ژنراتور گازسوز</p>', NULL, NULL, '2025-07-28 12:25:58', '2025-12-16 09:52:42'),
(698, 4795, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-07-28 21:42:10', '2025-07-28 21:42:10'),
