(714, 4950, 'تاوبن سازه', 'تا 100 نفر', 'company-default.png', '117', 'تهران', 'خیابان ظفر بعد از نفت شمالی پلاک 177 واحد 36', '02122262070', '8', 'تهران', NULL, '<p>فعالیت ما در زمینه پیمانکاری ساخت و ساز و تاسیسات می‌باشد اکثریت نیروهای شاغل شرکت در کارگاه‌ها مشغول بکار هستند. مدیریت، بسیار توانمند در زمینه کار خود هستند و شخصیت ذاتی آنان محیط امنی را برای نیروها در بخشهای مختلف ایجاد کرده</p>', NULL, NULL, '2025-08-08 13:08:28', '2025-08-08 13:16:00'),
