(733, 4984, 'هومان پردازش لوتوس', NULL, 'company-default.png', '117', 'تهران', 'کریم خان خردمند جنوبی نبش سمندریان پ 22', '42641', '8', 'تهران', NULL, '<p>شرکت هومان پردازش لوتوس به عنوان یکی از بزرگترین وارد کننده ماشینهای اداری و قطعات مربوط به آن در صنف کامپیوتر و ماشین اداری فعالیت دارد تعداد کارمندان شرکت در حال حاضر 25 نفر میباشد که از مزایای بیمه تکمیلی و پاداش علاوه بر مزایای قانونی برخوردار هستند و کارمندان در حیطی کاملا دوستانه در حال کار میباشند&nbsp;</p>', NULL, NULL, '2025-08-10 11:38:21', '2025-08-10 11:44:07'),
