(747, 5056, 'گروه توسعه آروند', NULL, '09b0e4a8e6880c2d22291d52ee353887.jpg', '117', 'تهران', 'بلوار فرحزادی - بعد از بزرگراه یادگار امام - بلوار ایثارگران شمالی - پلاک 10 - طبقه 1 - واحد 3', '02122071796', '8', 'تهران', NULL, '<p>گروه توسعه آروند یک شرکت بازرگانی برپایه تبلیغات است</p><p>که خدمات رفاهی برای سازمانهای دولتی را تسهیل میبخشد</p>', NULL, NULL, '2025-08-18 10:33:11', '2025-08-18 10:42:03'),
