(789, 5494, 'گروه توسعه اقتصادی گهر', 'بیشتر از 200 نفر', '56d62beb695b89311fea4eab37e314fa.jpg', '153', 'مشهد', 'دفتر مرکزی : میدان راهنمایی صادقی 12 توفیق 9 پلاک 24 طبقه 1', '05137075', '11', 'خراسان رضوی', '0624f85a17cd757e9a90482f8cfb54e6.jpg,5b57a395fcbe25a947a09a4629a7987b.jpg,5d88f48b8749ba0deba615d2a6e28592.jpg,78979b27eb502a64e76a19f88cd40c94.png,49233439293c903e731fe34a0c00c547.jpg,9aebc2b6ca0a86db8141a86b931b5cb6.jpg', '<p>گروه اقتصادی توسعه گهر&nbsp;در سال 1388 با توجه به نیاز مبرم انسان به غذا و تهیه غذای انسان از دام، طیور و آبزیان، با پیشنهاد آقای دکتر احمد سلحشور راه‌اندازی شد و در این زمینه شروع به فعالیت نمود. این گروه با راه‌اندازی 13 کارخانه زیر مجموعه در زمینه واردات نهاده‌های دائمی وتولید انواع خوراک آماده دام، طیور و آبزیان، تولید انواع مکمل‌های معدنی، ویتامینه و کنسانتره‌های دام، طیور و آبزیان، تولید تخم‌ مرغ نطفه‌دار و جوجه یک روزه، تولید تخم مرغ خوراکی، پرورش مرغ گوشتی، تولید قارچ خوراکی و پروتئین قارچ، حمل و نقل داخلی، حمل و نقل بین المللی و کشتیرانی، ماشین‌آلات و تجهیزات زیر ربط و همچنین ایجاد مراکز کارآفرینی و مرکز امور خیریه و بیش از 500 پرسنل به طور مستقیم هم‌اکنون در حال فعالیت و توسعه می‌باشد. از مهمترین وظائف و رسالت‌های این هلدینگ، استفاده از دانش و فناوری‌های نوین در طرح‌های تولید و توسعه‌ای بخش دامپروری است. استفاده از متخصصین مختلف داخلی و خارجی جهت بهینه‌سازی تولید و افزایش بهره‌وری مورد توجه جدی مدیران این مجموعه بوده و خواهد بود. تمرکز بر توانمندی‌های تولیدکنندگان داخلی سازنده ماشین‌آلات، تجهیزات و نرم‌افزار و همچنین استفاده از دانش فنی و سخت‌افزار روز دنیا در جهت نیل به اهداف فوق مورد تاکید مدیران مجموعه است.</p><p>امید است با همت مدیران مجرب و پرتلاش و کادر علمی متبحر فعالیت خود را برای تحقق اهداف تولیدی و بهبود فضای کسب وکار و خدمت‌رسانی به جامعه تولید کننده در پیش گیرد.</p>', NULL, NULL, '2025-09-08 12:59:01', '2025-09-08 14:03:56'),
(790, 5507, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-08 22:08:55', '2025-09-08 22:08:55'),
(791, 5517, 'فنی مهندسی آتیه الکترونیک فولاد ایرانیان', NULL, 'company-default.png', '117', 'تهران', 'تهران خیابان فاطمی روبروی سازمان آب برج ساعت طبقه 3 واحد 32', '42214', '8', 'تهران', NULL, '<p>ما فولاد ایرانیان هستیم، مجموعه‌ای پیشرو با هدف تأمین انواع مقاطع صنعتی و ساختمانی که نیازهای صنعتگران و سازندگان ایران را برطرف می‌کند. هدف اصلی ما تأمین تمامی نیازهای صنعتی با تمرکز بر ارائه خدمات به موقع و در مکان مناسب است. ما ارزش زمان را به خوبی می‌شناسیم و باور داریم که تأمین نیازها تنها در صورت انجام به‌موقع و در جایگاه درست، ارزشمند است.<br>تخصص و نگاه مهندسی به فولاد، از اصول بنیادین ما در فولاد ایرانیان است. ما معتقدیم که ارائه مشاوره و پاسخگویی به نیازهای مشتریان برای به حداکثر رساندن امنیت خرید و کاهش هزینه‌ها، مهم‌ترین مسئولیت ماست. به همین منظور، تیمی از فارغ‌التحصیلان مقاطع کارشناسی ارشد و دکتری در رشته‌های مهندسی متالورژی، عمران، مکانیک و دیگر رشته‌های مرتبط، در فولاد ایرانیان آماده ارائه مشاوره‌های تخصصی به شما هستند<br>اما داستان ما تنها به اینجا ختم نمی‌شود. فولاد ایرانیان با نگاه به آینده، همواره در پی ارتقاء کیفیت خدمات و محصولات خود است تا به بهترین نحو ممکن پاسخگوی نیازهای روزافزون صنعت کشور باشد.</p>', NULL, NULL, '2025-09-09 16:43:07', '2025-09-15 10:58:49'),
(792, 5525, 'سیمان جوین', 'بیشتر از 200 نفر', 'company-default.png', '117', 'تهران', 'خیابان احمدقصیر ، احمدقصیر ۱۲ ، پلاک ۲۴ ، طبقه اول', '02188557044', '8', 'تهران', NULL, '<p>شرکت سیمان جوین ، یک شرکت تولید سیمان است ، محل اصلی کارخانه در استان خراسان رضوی ، &nbsp;شهرستان سبزوار ، روستای الله آباد جغتای می باشد و دارای یک دفتر در مشهد ، و یک دفتر هم در تهران دارد .</p><p>&nbsp;</p>', NULL, NULL, '2025-09-11 00:11:54', '2025-09-11 00:16:33'),
(793, 5529, 'آروین پاژ هومت', NULL, 'company-default.png', '153', 'مشهد', 'احمدآباد_ابوذرغفاری', '05138459798', '11', 'خراسان رضوی', NULL, '<p>آروین پاژ هومت یکی از شرکت‌های فعال در صنعت کشور است که با تکیه بر تجربه و دانش روز، خدمات با کیفیت ارائه می‌دهد. ما با هدف ارتقای سطح خدمات و رضایت مشتریان، در مسیر توسعه پایدار قدم برمی‌داریم. ارائه خدمات با بالاترین کیفیت و استانداردهای روز دنیا کادری مجرب و متخصص برای ارائه بهترین راهکارها<br>سال تاسیس 1398<br>حوزه فعالیت ساختمانی<br>تعداد پرسنل 6 نفر</p>', NULL, NULL, '2025-09-11 11:54:56', '2025-09-11 12:38:22'),
(794, 5531, 'هلدینگ رسانه ای خبرفوری', 'تا 200 نفر', 'company-default.png', '153', 'مشهد', 'مشهد بلوار شاهد شاهد 33 برج ایلما', '09023001844', '11', 'خراسان رضوی', NULL, '<p>هلدینگ خبر فوری، مجموعه‌ای جوان و پویاست که به شما فرصت رشد، ارتقاء و کسب مهارت‌های جدید را خواهد داد&nbsp;</p>', NULL, NULL, '2025-09-11 13:07:41', '2025-09-11 18:46:54'),
(795, 5535, 'فردید', 'تا 100 نفر', 'company-default.png', '153', 'مشهد', 'مشهد', '09303070552', '11', 'خراسان رضوی', NULL, '<p>امور مالی</p>', NULL, NULL, '2025-09-11 18:28:52', '2025-09-11 18:31:03'),
(796, 5547, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-13 00:20:28', '2025-09-13 00:20:28'),
(797, 5548, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-13 00:28:10', '2025-09-13 00:28:10'),
(798, 5549, 'آرین راد شمال', 'کمتر از 10 نفر', 'company-default.png', '117', 'تهران', 'جردن، کوچه مروارید', '26232443', '8', 'تهران', NULL, '<p>مجموعه ای از شرکت‌های پویا و تخصصی در زمینه واردات و توزیع مواد اولیه کشاورزی و پرورش طیور، کارخانجات تولید غذای دام، انبارهای زنجیره ای، باریری ها و تامین و توزیع محصولات فولادی است. با حضور قوی در چند شهر و کشور، ما متعهد به ارائه منابع و خدمات با کیفیت بالا به صنایع مختلف از جمله کشاورزی، دامداری و ساخت و ساز هستیم.</p><p>ما به رویکرد مشتری‌مداری خود افتخار می‌کنیم و اطمینان می‌دهیم که با مدیریت کارآمد زنجیره تأمین و تخصص صنعت، نیازهای بازارهای داخلی و بین‌المللی را برآورده می‌کنیم. با تمرکز بر نوآوری، پایداری و قابلیت اطمینان، گروه آرین راد خود را به عنوان یک شریک قابل اعتماد در بخش‌های مختلف تثبیت کرده است</p>', NULL, NULL, '2025-09-13 09:21:00', '2025-11-30 12:06:25'),
(799, 5555, 'نیرو بتن شرق', 'کمتر از 20 نفر', 'company-default.png', '153', 'مشهد', 'بلوار معلم ، بین معلم 10و 12 پلاک 212 طبقه اول واحد 103.', '09150094417', '11', 'خراسان رضوی', NULL, '<p>تولید کننده بتن و ماسه و …</p>', NULL, NULL, '2025-09-13 14:19:00', '2025-09-13 14:31:27'),
