(804, 5574, 'ایمن درب', NULL, 'company-default.png', '153', 'مشهد', 'شهرک صنعتی توس فاز ۱ روبروی صنعت ۵', '09373223690', '11', 'خراسان رضوی', NULL, '<p>فعالیت شرکت تولید درب هست</p><p>به یک حسابداری مالی و مالیاتی نیاز داریم جهت رشد و گسترش مجموعه</p><p>حداقل ۳ سال سابقه کار حسابداری</p>', NULL, NULL, '2025-09-14 10:22:52', '2025-09-14 10:24:48'),
(805, 5580, 'موسسه حسابرسی رایان بهروش پارس', 'تا 50 نفر', 'company-default.png', '153', 'مشهد', 'مشهد، هاشمیه ۳۲ ، پلاک ۴۱', '38704200', '11', 'خراسان رضوی', 'dc6de7b58bb3cca2b97fe03c3e6587f0.jpg,e8ebf05732586e145e9b5a392dd19220.jpg', '<p>عضو جامعه حسابداران رسمی ایران</p><p>عضو انجمن حسابداران خبره ایران</p><p>عضو انجمن حسابداری ایران</p><p>کارشناسان رسمی دادگستری</p><p>حسابرسی سالیانه بیش از ۱۰۰ سازمان دولتی و واحدهای تجاری خصوصی</p>', NULL, NULL, '2025-09-14 15:48:03', '2025-09-14 15:57:53'),
