(808, 5592, 'مهرتاب', NULL, 'company-default.png', '153', 'مشهد', 'مشهد. مجتمع اداری مرمر', '09125011387', '11', 'خراسان رضوی', NULL, '<p>شرکت مهرتاب یک شرکت تولیدی در حوزه لوازم سرمایشی و گرمایشی است. دفتر مرکزی شرکت در مجتمع اداری مرمر مشهد واقع شده است. واحد تولیدی شرکت درشهرک صنعتی توس است. ۵۰ نفر نیروی کار دارد. &nbsp;</p>', NULL, NULL, '2025-09-15 11:33:31', '2025-09-18 11:15:36'),
(809, 5598, 'آژانس تبلیغاتی آداک', NULL, 'company-default.png', '153', 'مشهد', 'هاشمیه', '09158701544', '11', 'خراسان رضوی', NULL, '<p><a href=\"https://adakads.com/\"><strong>آژانس تبلیغاتی آداک</strong></a><br>&nbsp;در فرایند تحلیل کسب و کار مشتریان خود، با بررسی بازار و رقبا، استراتژی‌هایی برای تبلیغ و برندینگ به وجود می‌آورد. در این مرحله، مشاوره و ارائه‌ی محتوای مناسب، از جمله وظایف پایه‌ای آداک است. پس از شناخت بهتر محصول و بازار، آداک، با استفاده از خلاقیت و نوآوری، یک کمپین تبلیغات محیطی در مشهد مناسب را طراحی و به دلیل اینکه ارزیابی عملکرد برای هر کمپین بسیار مهم است، هرگونه تغییر در کمپین را به منظور بهبود و افزایش بازده، آنالیز و ارزیابی می‌کند. در پایان، آداک با توجه به تجربه بیش از ۱۴ ساله‌ی خود و دیدگاه نوآورانه ،<br>&nbsp;برای بازدیدکنندگان تلاش می‌کند تا یک تجربه بهتر را ارائه دهد و این امر موجب ارتقاء شناخت و شناسایی برند مشتری می‌گردد.</p>', NULL, NULL, '2025-09-15 22:30:14', '2025-11-15 12:54:14'),
(810, 5600, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-16 03:50:48', '2025-09-16 03:50:48'),
