(828, 5668, 'مکسان', 'تا 50 نفر', '0eaa46b8af18edf1fed29f62046878f4.jpg', '117', 'تهران', 'شهرک صنعتی پرند ، بلوار فناوری خیابان گلزار، کوچه گل آذین ، پلاک ۵', '02156418647', '8', 'تهران', NULL, '<p>صنعت : خودرو و صنایع وابسته</p><p>تولید ، مونتاژ و رنگ انواع سپر خودرو های داخلی ، در شهرک صنعتی پرند</p>', NULL, NULL, '2025-09-21 12:41:12', '2025-09-21 13:48:39');
