(829, 5669, 'آرمان کوشش', NULL, 'company-default.png', '117', 'تهران', 'منطقه ۴، تهرانپارس غربی', '09120058362', '8', 'تهران', NULL, '<p>تولید کننده دیگ‌های بخار و روغن داغ و آبداغ و خطوط تولید مواد غذایی و تجهیزات نفت،گاز و پتروشیمی</p>', NULL, NULL, '2025-09-21 13:12:00', '2025-09-22 11:43:55'),
(830, 5677, 'نام آور پلیمر', NULL, 'company-default.png', '60', 'اصفهان', 'اصفهان، بلوار دانشگاه صنعتی، شهرک علمی و تحقیقاتی اصفهان، خیابان ۱۲، ساختمان فراتحقیق، طبقه همکف', '09133657345', '4', 'اصفهان', NULL, '<p>گروه صنعتی امگا تولید کننده انواع قطعات پلیمری (لاستیک و پلاستیک) می‌باشد که از سال ۱۳۷۸ فعالیت خود را در شهر اصفهان شروع نموده است. گروه تولیدی و صنعتی امگا از موفق‌ترین تولیدکنندگان قطعات پلیمری می‌باشد که با استفاده از تجربیات خود توانسته بهترین کیفیت محصولات تولیدی را برای مصرف کنندگان خود به همراه داشته باشد.&nbsp;</p>', NULL, NULL, '2025-09-21 16:18:43', '2025-09-21 16:24:51'),
(833, 5683, 'رول شیت باقری', 'کمتر از 20 نفر', 'company-default.png', '128', 'کهریزک', 'شهرری کهریزک شورآباد بلوار امام حسین خ معدن یازدهم کوچه سلمان فارسی پلاک۱۴', '09121716134', '8', 'تهران', NULL, '<p>فعالیت: برش رول کاغذ و مقوا</p><p>&nbsp;</p>', NULL, NULL, '2025-09-22 10:24:40', '2025-10-01 13:59:08'),
(834, 5684, 'کاردان', NULL, 'company-default.png', '117', 'تهران', 'کاردان', '02156230851', '8', 'تهران', NULL, '<p>شرکت کاردان واقع در شهرک صنعتی شمس اباد فشافویه</p><p>تولیدی الومینیوم&nbsp;</p><p>&nbsp;</p>', NULL, NULL, '2025-09-22 10:47:57', '2025-10-01 14:03:35'),
(835, 5685, 'سراج سبز', NULL, 'company-default.png', '117', 'تهران', 'سهروردی شمالی میرزای زینالی پ ۳۱۲', '02188541822', '8', 'تهران', NULL, '<p>شرکت سراج سبز نمایندگی نرم افزار هلو&nbsp;</p><p>مزایا: بیمه و حقوق ، پاداش ، آموزش&nbsp;</p>', NULL, NULL, '2025-09-22 11:08:01', '2025-09-22 15:33:36'),
