(837, 5689, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-22 15:50:22', '2025-09-22 15:50:22'),
(839, 5699, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-23 15:18:07', '2025-09-23 15:18:07'),
(840, 5712, 'نقش محیط', 'تا 50 نفر', 'company-default.png', '117', 'تهران', 'ونک کاندی شمالی پ30', '88658335', '8', 'تهران', NULL, '<p>خدمات معماری وشهرسازی&nbsp;</p>', NULL, NULL, '2025-09-24 18:06:15', '2025-09-24 18:07:57'),
(841, 5713, 'میراب لوله طوس', 'تا 50 نفر', 'bc0ff19f6a7a79a6e1778e9febb87117.png', '167', 'چناران', 'شهرک صنعتی چناران صنعت ۱۷', '05146139550', '11', 'خراسان رضوی', NULL, '<p>شرکت میراب لوله طوس در سال 1389 با توجه به زیر ساخت های تولید لوله های پلی اتیلن و همچنین نیاز رو به افزایش بخش های مختلف جامعه به محصولات پلیمری و رویکرد صادرات با بهترین قیمت به همسایگان شمال شرق کشور با سه خط تولید شروع به فعالیت نمود.ثبات و بهبود کیفیت محصولات پلی اتیلن از ابتدا مورد توجه مدیران شرکت میراب لوله طوس بوده که این مهم در کنار تعامل سازنده با مشتریان، در کنار فروش با بهترین قیمت، به سرعت باعث توسعه شرکت گردید، تا آنجا که در سال 1391 ظرفیت تولید به 2 برابر افزایش پیدا کرد. بی شک پویایی مجموعه میراب لوله طوس مرحون زحمات تمامی پرسنل و نیز اعتماد مشتریان عزیزی بوده که در این مسیر ما را یاری کرده اند و فروش بالایی برای شرکت به ارمغان آورده اند.</p>', NULL, NULL, '2025-09-24 21:30:03', '2025-12-16 11:39:13'),
(842, 5716, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-25 07:28:54', '2025-09-25 07:28:54'),
(843, 5725, 'پارسیا گستر مهر برزین', NULL, 'company-default.png', '153', 'مشهد', 'بین وکیل اباد ۲۵ و ۲۷', '۰۵۱۳۶۰۱۶۵۴۰', '11', 'خراسان رضوی', NULL, '<p>شرکت بازرگانی فعال در حوزه فورش مصالح ساختمانی و محصولات برند کی ضلاس</p>', NULL, NULL, '2025-09-25 11:50:48', '2025-09-27 15:37:31'),
