(846, 5780, 'شرکت کشاورزی و صنایع قند شیرین', NULL, 'company-default.png', '153', 'مشهد', 'مشهد ابتدای اتوبان مشهد نیشابور', '09151117958', '11', 'خراسان رضوی', NULL, '<p>تولیدشکر از چغندر و بخش های کشاورزی</p>', NULL, NULL, '2025-09-27 14:53:49', '2025-09-27 14:55:57'),
(847, 5781, 'آباد بایر', 'تا 50 نفر', 'company-default.png', '153', 'مشهد', 'ابتدا جاده طرقبه امام رضای ۸ بنفشه ۳/۱ روبروی بنفشه ۶ پلاک ۱۰', '05191091510', '11', 'خراسان رضوی', NULL, '<p>شرکت آباد بایر نزدیک به دو دهه تولید کننده کود های کشاورزی و دارای سه شعبه در مشهد کوهسنگی و طرقبه امام رضا و تهران خیابان کاشانی میباشد</p>', NULL, NULL, '2025-09-27 15:04:12', '2025-09-27 15:10:23'),
(848, 5784, 'قند شیرین خراسان', 'بیشتر از 200 نفر', 'company-default.png', '153', 'مشهد', 'طرق', '05134693440', '11', 'خراسان رضوی', NULL, '<p>کارخانه قند شیرین خراسان از بزرگترین شرکت های حوزه قند در سطح کشور می باشد که قدمتی بیش از 60 سال دارد.</p>', NULL, NULL, '2025-09-27 20:01:47', '2025-09-27 20:25:31'),
