(854, 5803, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-29 07:18:08', '2025-09-29 07:18:08'),
(855, 5804, 'پارت آریا نیرو - پانیر', 'تا 100 نفر', 'company-default.png', '134', 'شهریار', 'تهران - جاده قدیم - جاده شهریار - سعید آباد خیابان چمران خیابان 15 متری سلمان پلاک 7', '021-62999926', '8', 'تهران', 'c171d3b8a0cef93b20dca366fa215434.jpg', '<p>شرکت پارت آریا نیرو پانیر از سال 1385 در صنعت ساخت یاتاقان های لغزشی فعالیت خود را آغاز نموده و طی سالیان گذشته با کسب دانش روز و تکیه بر توانایی پرسنل مجرب و بروز رسانی محصولات خود سعی نموده تا بتواند گامی در راستای رفع نیاز صنایع مختلف کشور بردارد.<br>انواع یاتاقان های یک لایه (Mono-Metal)، دو لایه (Bi-Metal) و سه لایه (Tri-Metal) به علاوه لابیرنت سیل ها گروه محصولات تولیدی این شرکت را تشکیل می دهند.</p>', NULL, NULL, '2025-09-29 08:55:49', '2025-10-06 15:45:18'),
(856, 5805, 'خدمات حسابداری انفرادی', NULL, 'company-default.png', '117', 'تهران', 'تهران حکیمیه خیابان سحر', '765224', '8', 'تهران', NULL, '<p>حوزه فعالیت :انجام عملیات حسابداری، حسابرسی و انواع مشاوره های مالیاتی مالی و حقوقی&nbsp;</p><p>سال تاسیس : 1392</p><p>محل کار اشخاص حقیقی و حقوقی طرف قرارداد در سطح تهران و استان های همجوار(به صورت خاص و محدود باهماهنگی قبلي با کارمند) که حق ماموریت و در صورت رضایت پاداش هم تعلق خواهد گرفت .</p>', NULL, NULL, '2025-09-29 09:08:24', '2025-10-02 13:53:57'),
(857, 5806, 'گروه صنعتی سارا', NULL, 'company-default.png', '117', 'تهران', 'خ دکتر بهشتی بعد از چهارراه قائم مقام فراهانی پلاک 412 ط دوم', '02188717890', '8', 'تهران', NULL, '<p>گروه صنعتی سارا از سال 1359 مشغول به کار بوده و تولید کننده انواع ترانسفورماتو و محافظ برق و … فعالیت داشته و دارد</p>', NULL, NULL, '2025-09-29 10:28:25', '2025-09-29 10:31:26'),
(858, 5807, 'مهند', NULL, 'company-default.png', '153', 'مشهد', 'تقاطع مجد ساختمان ساینا', '09155119470', '11', 'خراسان رضوی', 'bd30faeecca550feee8936819ca5a010.jpg', '<p>شرکت مهند در طول 39 سال فعالیت در صنایع کانی های غیرفلزی خصوصا صنایع کاشی و سرامیک وچینی بهداشتی موفق به تولید انواع ماشین آلات مورد نیاز در تولید محصولات داخلی با کیفیت گشته است . در این میان از سال 1364 تا کنون در صنایع مختلف و در رشته تخصصی خود ،در مجموع بیش از 200 نوع دستگاه با ویرایش ها و تنوع خاص خود طراحی ، تولید و نصب و راه اندازی کرده است . همچنین در راستای بالابردن راندمان تولید کانی های غیرفلزی همیشه سعی در کیفیت بخشیدن به محصولات و ماشین آلات تولیدی خود داشته و با اتکا به قوانین و دستورالعملهای استاندارد ازجمله دستورالعمل های ISO 9001 در این مهم کوشیده است .رضایت مندی مشتریان و بالا رفتن سریع تعداد مشتریان این شرکت گواه این ادعاست . در حال حاضر اکثر کارخانجات کاشی و سرامیک وجمع کثیری ازکارخانجات چینی و بهداشتی کشورمان ایران جزو مشتریان ایران مهند نیز می باشند . در صنایع کاشی و سرامیک تنوع تولیدات ایران مهند به گونه ای است که این شرکت هم اکنون تنها با اتکا به محصولات خود قادر به تولید ونصب تمام دستگاه های تولیدی یک کارخانه پیشرفته به استثنای پرس است شرکت ایران مهند در حوزه تولید و تامین قطعات یدکی خط و ماشین آلات نیز دارای تنوع درمحصولات خود است .به گونه ای که نزدیک به 850 نوع قطعه یدکی جهت خطوط لعاب و ماشین آلات ، اعم از ماشین آلات ساخت خود شرکت یا ماشین آلات خارجی طراحی و تولید نموده است . مشاوره ، طراحی ، تامین و نصب ازدیگر فعالیتهای کارشناسی شرکت ایران مهند است.با داشتن کارشناسان زبده و آزموده ، این شرکت قادر به گسترش خدمات خود در سطح ملی و بین المللی در زمینه های فوق است .</p>', NULL, NULL, '2025-09-29 12:02:38', '2025-10-01 14:29:32'),
(859, 5811, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-29 14:23:39', '2025-09-29 14:23:39'),
(860, 5813, 'موسسه آموزشی غیر دولتی ندای مفید', 'بیشتر از 200 نفر', 'b0cd036d5035a1310bedafab39d502a9.JPG', '117', 'تهران', 'تهران، ستارخان، خیابان شادمان، خیابان ذوالفقاری، بلوار سیادت، پلاک 39', '09106814811', '8', 'تهران', NULL, '<p>موسسه آموزشی غیر دولتی ندای مفید در حوزه مدارس غیر انتفاعی فعالیت دارد.</p>', NULL, NULL, '2025-09-29 15:49:16', '2025-09-29 15:58:28'),
(862, 5819, 'زردانه', NULL, 'company-default.png', '153', 'مشهد', 'خیابان سناباد۵۵', '۰۹۱۵۳۱۱۵۷۳۹', '11', 'خراسان رضوی', NULL, '<p>یک شرکت معتبر تولیدی جهت کادر اداری خود نیازمندیک نفر خانم حسابدار جهت بخش بازرگانی میباشد.ترجیحا آشنا به نرم افزار پایا دارای روابط عمومی بالا&nbsp;</p>', NULL, NULL, '2025-09-29 21:00:27', '2025-09-29 21:03:31'),
