(865, 5823, 'برودتی و حرارتی نیک', 'تا 50 نفر', 'e57593e1d0792bb363964253da7bf6b4.png', '117', 'تهران', 'هفت تیر خيابان قائم مقام فرهانی کوچه گلریز', '88847609', '8', 'تهران', 'c2552ca2984794a41bc75178a1983d94.png', '<p>شرکت نیک، به‌عنوان یک شرکت دانش‌بنیان و با بیش از ۶۰ سال تجربه در صنعت، از سال ۱۳۳۹ فعالیت خود را در زمینه طراحی و تولید تجهیزات سردخانه صنعتی، تهویه مطبوع و دستگاه‌های بستنی‌ساز آغاز کرده است. ما در نیک، همواره کیفیت، نوآوری و رضایت مشتری را سرلوحه کار خود قرار داده‌ایم.</p>', NULL, NULL, '2025-09-30 09:52:22', '2025-10-01 11:36:41'),
(867, 5825, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-30 12:12:04', '2025-09-30 12:12:04'),
(869, 5836, 'فرامنطقه', 'کمتر از 20 نفر', 'company-default.png', '153', 'مشهد', 'مشهد - خیابان سنایی - بین سنایی 8.1 و 10 فروشگاه فرامنطقه', '05137111152', '11', 'خراسان رضوی', NULL, '<p><strong>شرکت فرامنطقه</strong> با هدف ارائه راهکارهای نوین و کارآمد در حوزه‌های برق صنعتی شکل گرفته و امروز به عنوان مجموعه‌ای پویا و رو به رشد شناخته می‌شود. فعالیت اصلی این شرکت بر پایه ارائه خدمات حرفه‌ای، ایجاد بسترهای مطمئن برای مشتریان و توسعه پروژه‌هایی است که همسو با نیاز روز بازار طراحی و اجرا می‌شوند.</p><p>ما در فرامنطقه تلاش می‌کنیم تا با بهره‌گیری از دانش روز، نیروی انسانی متخصص و نگاهی آینده‌نگر، به مشتریان خود تجربه‌ای متفاوت از همکاری ارائه دهیم. رسالت ما تنها انجام پروژه نیست، بلکه ایجاد ارزش پایدار، اعتماد و همراهی بلندمدت با سازمان‌ها و افراد است.</p><p>فرامنطقه با رویکردی انعطاف‌پذیر، خدمات خود را در حوزه‌های مختلف توسعه داده و همواره به دنبال نوآوری، کیفیت و بهبود مداوم است.</p>', NULL, NULL, '2025-10-01 09:44:43', '2025-10-01 09:47:35'),
(870, 5844, 'شرکت فولادسازان معدن یار آروین', NULL, 'company-default.png', '167', 'چناران', 'شهرک صنعتی چناران ابتدای نوآوری ساختمان نمای مشکی  شرکت فولادسازان آروین', '۰۹۱۵۴۷۱۲۶۹۶', '11', 'خراسان رضوی', NULL, '<p>شرکت شامل ریخته گری و تولید قطعات و دارای کوره ذوب فولاد&nbsp;<br><br>شرکت سهامی خاص فولاد سازان معدن یار آروین در تاریخ ۱۳۹۷/۱۱/۰۳ تأسیس شد. این شرکت در زمینه ارائه خدمات پشتیبانی قابل واگذاری به بخش خصوصی، انجام فعالیت‌های بازرگانی داخلی و خارجی، تجارت هوایی، زمینی و دریایی، نصب، خرید، فروش، توزیع و تهیه قطعات و اجزاء ماشین‌آلات صنعتی و راه‌سازی، و تأمین و واردات تجهیزات و مواد اولیه ماشین‌آلات و صنایع تبدیلی فعالیت می‌کند.</p><p>آدرس فولاد سازان معدن یار آروین</p><p>خراسان رضوی، چناران، شهرک صنعتی چناران ، بلوار صنعت</p>', NULL, NULL, '2025-10-01 14:28:01', '2025-10-05 11:55:38'),
(871, 5849, 'پویاتراز محاسب', 'کمتر از 10 نفر', 'cb90a4d833200204e588d2cd98d6abac.png', '394', 'اراک', 'مجتمع پارس', '34030271', '28', 'مرکزی', NULL, '<p>مجموعه حسابداری ثلاثه، یک شرکت حسابداری مالی مالیاتی می باشد که در سال 1400 تاسیس شده است و بعنوان واحد مالی به کسب و کارهای کوچک و متوسط کمک می کند</p>', NULL, NULL, '2025-10-02 13:01:41', '2025-10-02 13:09:54'),
