(880, 5889, 'زرین ستاره مسما', NULL, '05fbc4bd7c1362aa310c5a0f126350c5.jpg', '153', 'مشهد', 'شهرک صنعتی توس فاز 2 اندیشه 9', '05135414381', '11', 'خراسان رضوی', NULL, '<p>شرکت تولید و بسته بندی مواد غذایی با 50 سال &nbsp;قدمت<br>شرکت زرين ستاره مسماپس از تاسیس در سال 1358، فعاليت بازرگانی خود را در زمينه مواد غذايی به ویژه چای آغاز نموده و پس از گذشت چند سال، با توجه به نياز کشور در تحول بسته بندی مواد غذايی به ويژه چای، با دارا بودن تجربه و امکانات لازم از سال 1377، به بسته بندی انواع متنوع چای با نام ثبتی مسما اقدام نموده و در این زمینه موفق به ایجاد تحولی مثبت در زمينه بسته بندی انواع چای داخله و خارجه گردیده است. اکنون، پس از گذشت چند دهه، محصولات اين شرکت با توجه به دارا بودن تنوع و کيفيت بالا، از جمله شناخته شده ترين نام ها در صنعت چای کشور می باشد. در حال حاضر نيز این مجموعه محصولات جديدی از قبيل زعفران، ادويه جات، پودرجات، حبوبات، نبات و بيسکوئيت را به سبد کالايی خود اضافه نموده است. همچنين واحد تحقیقات اين شرکت در سال 1389 ، با تلاش های انجام شده، موفق به ثبت اختراع انحصاری تی بگ شيرين و رژيمی گرديده است</p>', NULL, NULL, '2025-10-05 11:24:01', '2025-10-05 12:04:48'),
(881, 5896, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-06 09:59:07', '2025-10-06 09:59:07'),
(882, 5898, 'اندیشه های ماندگار خوارزمی', NULL, 'company-default.png', '117', 'تهران', 'خیابان جمهوری', '66912171', '8', 'تهران', NULL, '<p>شرکت اندیشه های ماندگار خوارزمی تولید کننده نرم افزار حسابداری</p>', NULL, NULL, '2025-10-06 13:38:29', '2025-10-06 13:40:54'),
(883, 5899, 'پیشگامان پلاستیک خراسان', 'تا 100 نفر', 'a3b2522e96f0b7af33e4e3c01cf6d644.jpg', '153', 'مشهد', 'مشهد بلوار رسالت شمالی129', '33016', '11', 'خراسان رضوی', NULL, '<p>تولیدکننده، توزیع کننده و صادرکننده انواع محصولات یکبارمصرف و بسته بندی از جنس پلاستیکی،گیاهی و کاغذی<br>با حدود دو دهه تلاش مستمر به عنوان يکي از فعالترين واحدهاي توليدي ظروف بهداشتي يکبار مصرف در شمال شرق کشور بوده که با تولید بيش از يکصد نوع محصول و تکمیل سبدی حدود 2500 محصولی از بهترین تولید کنندگان ، داراي متنوع ترين وبا کيفيت ترين محصولات پلاستیکی در ایران همیشه سربلند مي باشد.<br>اين شرکت همواره سعي و تلاش نموده است که محصولات خود را با استفاده از مواد اوليه با ارزش غذايي و نيز با رعايت اصول يهداشتي توليد و به شما مصرف کننده عزيز عرضه نمايد، تا بدينگونه رسالت خود را در اين عرصه انجام و پاسدار سلامت و بهداشت جامعه باشد .<br>اکنون محصولات توليدي اين شرکت در زمينه بسته بندي فرآورده هاي لبني صنعتي، آلايش مرغ و گوشت، خشکبار و نيز در دانشگاه ها، بيمارستان ها، رستوران ها، آشپزخانه ها و… مورد استفاده قرار مي گيرد.</p>', NULL, NULL, '2025-10-06 13:57:37', '2025-10-06 14:58:54'),
(884, 5904, 'پیشرو حمل کالا', NULL, 'company-default.png', '117', 'تهران', 'خیابان بهشتی نرسیده به تقاطع سهروردی جنب داروخانه صبا پلاک 112 طبقه 5 واحد 15', '86196170', '8', 'تهران', NULL, '<p>شرکت پیشرو حمل کالا با سالها تجربه در امور بازرگانی بین الملل ، حمل و نقل و ترانزیت با توانمندیها و پیشنهادهای منحصر به فرد آماده خدمت رسانی می باشد.</p>', NULL, NULL, '2025-10-06 15:41:36', '2025-10-06 15:44:50'),
(885, 5906, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-06 20:19:09', '2025-10-06 20:19:09'),
(886, 5908, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-07 07:56:14', '2025-10-07 07:56:14'),
(887, 5911, 'مجتمع فولاد کاویان', NULL, 'a9a35dea97f267f9e8ce2aa3b989a046.jpg', '153', 'مشهد', 'کیلومتر 45 جاده مشهد-فریمان، شهرک صنعتی کاویان، فاز 2، تلاش 4/4', '051-34693566-9', '11', 'خراسان رضوی', NULL, '<p>مجتمع فولاد کاویان شرق آسیا به شماره ملی ۱۰۳۸۰۵۴۶۳۲۲ و با شماره ثبت ۶۹۱، اولین و مجهزترین واحد صنعتی ایران با محوریت خردایش و ذوب سرباره‌های کوره‌های ذوب است که در سال ۱۳۸۰ راه‌اندازی شد و مورد بهره برداری قرار گرفت.</p><p>میزان تولید سالانه مجتمع فولاد کاویان شرق آسیا در واحد خردایش جداسازی یک میلیون تن سرباره می‌باشد که شامل محصولات فراوری شده فولادی مانند خاک آهن اکسید آهن پولکی متال با خلوص ۹۵ درصد، شلاکه آهن، خرسک و نیز تولید مواد اولیه کارخانه‌های سیمان و همچنین مواد اولیه راهسازی است. با اجرای طرح توسعه‌ای در دو سال آینده این تولیدات بالغ بر ۲ میلیون تن در سال خواهد بود.</p><p>&nbsp;مجتمع فولاد کاویان شرق آسیا با تمرکز بر ذوب محصولات خردایش شده در کوره‌های قوس الکتریکی و تبدیل فولاد مذاب به شمش‌های فولادی اشتغالزایی مناسبی به وجود آمده است<br>مجتمع فولاد کاویان شرق آسیا دارای ظرفیت تولید سالانه ۳۰ هزار تن انواع محصولات شمش فولادی در سایزهای ۶ متری و ۱۲ متری با آنالیز sp3 و sp5 و sp4 در مقطع 100*100 و 120*120 و 160*150 می‌باشد که شمش فولادی با بهره‌گیری از فناوری ccm توسط کوره‌های القایی حاصل می‌شود.</p>', NULL, NULL, '2025-10-07 10:23:57', '2025-10-07 11:27:16'),
(888, 5913, 'مجتمع سینمایی اطلس', NULL, 'company-default.png', '153', 'مشهد', 'بزرگراه کلانتری، میدان حافظ، بازار بزرگ اطلس', '05133898700', '11', 'خراسان رضوی', NULL, '<p>پردیس سینمایی اطلس مشهد که دارای 13 سالن و با گنجایش 1063 نفر است در اطلس مال قرار دارد و در ۱۳ بهمن ۱۳۹۶ افتتاح شده‌ است. سینما اطلس مال مشهد با دارا بودن سالن های مجهز یکی از پرفروش‌ترین سینماهای کشور می‌باشد.&nbsp;</p>', NULL, NULL, '2025-10-07 12:16:53', '2025-10-07 12:24:34'),
