(894, 5956, 'فراز فنون مرکزی', NULL, 'company-default.png', '117', 'تهران', 'طرشت - بلوار صالحی', '1111111111', '8', 'تهران', NULL, '<p>شرکت دانش بنیان فراز فنون با هدف فعالیت و خدمت در بستر فناوری اطلاعات و ارتباطات، چاپ و تکثیر، بازاریابی و تبلیغات، نشر دیجیتال و…، تشکیل گردیده و به واسطه در اختیار داشتن متخصصین و نیروهای مجرب در زمینه خدمات فنی، مهندسی و بازرگانی امور انفورماتیکی، در صدد ایجاد تغییراتی نوین، در این حوزه ها، برآمده است.<br>شرکت فراز فنون عضوی از گروه فراز، متشکل از مجموعه های معدنی، صنعتی، فناوری اطلاعات، بازرگانی و خدماتی می باشد که با لحاظ نمودن رویکرد نظام علمی، فنی و اقتصادی مدرن، موفق به پیمودن گام های مؤثر و قابل توجهی گشته است.</p>', NULL, NULL, '2025-10-08 15:30:20', '2025-10-09 13:01:39'),
(896, 5985, 'هلدینگ هشت پنجره اتشگاه', 'کمتر از 10 نفر', 'company-default.png', '117', 'تهران', 'تهران خیابان خرمشهر خیابان عرب علی خیابان ۷  پلاک ۷واحد ۴۰۷', '۰۲۱۸۸۵۳۰۸۵۱', '8', 'تهران', NULL, '<p>هلدینگ هشت پنجره اتشگاه یک شرکت بازرگانی وتولیدی وخدماتی است دفتر مرکزی اصفهان میباشد که این دفتر جهت ارایه خدمات مالی به شرکتهای وابسته وشرکتهای خصوصی وشرکت دانش بنیان در دفتر فراگیر صنعت مهر بین دایر شده است&nbsp;</p>', NULL, NULL, '2025-10-09 18:31:00', '2025-10-09 18:49:25'),
(897, 5994, 'آذرمهرصنعت', 'کمتر از 20 نفر', 'company-default.png', '117', 'تهران', 'خ۱۵ خرداد غربی نبش ک شیخ فضل اله نوری ساختمان سهیل پ۳۰۵', '02155636364', '8', 'تهران', NULL, '<p>فعال در امور صادرات و &nbsp;واردات مواد غذایی&nbsp;<br>شرکت آذر مهر صنعت از سال ۱۳۷۹ فعالیت خود را آغاز کرده و در حوزه واردات و بسته‌بندی چای مشغول به کار است. این شرکت با تجربه و تخصص خود، محصولات باکیفیتی را در بازار چای ارائه می‌دهد.</p>', NULL, NULL, '2025-10-09 23:37:51', '2025-10-19 13:13:37'),
(898, 6008, 'پروفا', 'کمتر از 10 نفر', 'company-default.png', '117', 'تهران', 'تهران چیتگر', '09157180070', '8', 'تهران', '49cf22a1a0392a4ea27ab305bea6fd3e.jpg', '<p>شرکت طراحی نرم افزار.&nbsp;</p>', NULL, NULL, '2025-10-10 17:38:18', '2025-10-10 17:41:58'),
(899, 6012, 'ماژان صنعت ارشیا', NULL, 'ad7774a70a8f97b838d0d4b43848e771.jpg', '153', 'مشهد', 'میثاق 34، بین کاظمیه 3 و 5 ، ایستگاه خدمات شهری ، شرکت ماژان صنعت ارشیا', '09368941695', '11', 'خراسان رضوی', '0672aaecbac6099fdbc6b84d1eab4f20.jpg,83d0ce00b04bc22868be2c215e233b27.jpg', '<p>شرکت ماژان صنعت با توجه به نیاز روز جامعه بشـــــری و با شعار تفكیك از مبدا به طراحی و ساخت ماشین آلات صنعتی بازیافت و امحا در استان خراسان رضوی پرداخت و خوشبختانه تا به امروز توانســته با استفاده از مهندسین داخلی به طراحی و ساخت خطوط بازیافت اعم از بازیافت پلاستیك و لاستیك و مواد پلیمری بپردازد.<br>همچنین برای اولین بار به طراحی ماشـین آلات ریموك سـیار بازیافت روغن پرداخته اسـت.لازم به ذکر اسـت این شــرکت در نمایشگاه های مختلف داخلی و خارجی شرکت داشته است.</p><p>با توجه به آمار سازمان محیط زیسـت کشـور سالانه 93 درصد زباله ها به دلیل کمبود ماشین آلات داخلی به صورت سنتی دفن می شود،که امروزه ما توانستیم کشور را&nbsp; در این صنعت به مرز خودکفایی برسانیم.</p>', NULL, NULL, '2025-10-10 20:43:21', '2025-10-10 21:34:35'),
(900, 6023, 'سپهر تجارت اتحاد البرز', NULL, 'company-default.png', '283', 'کرج', 'میدان سپاه نبش خیابان گلستان روبروی درب استخر سپاه ساختمان تیام', '02634480147', '5', 'البرز', NULL, '<p>شرکت سپهر تجارت اتحاد البرز به عنوان یکی از مجموعه های فعال در حوزه &nbsp;بازرگانی (واردات و صادرات) با هدف تکمیل کادر مالی خود از افراد برای همکاری دعوت به عمل می آورد.</p>', NULL, NULL, '2025-10-11 12:58:43', '2025-10-11 13:06:01'),
