(904, 6049, 'آرام گستران آوای جاوید', 'کمتر از 10 نفر', 'company-default.png', '153', 'مشهد', 'مشهد - بلوار نمایشگاه', '09055301656', '11', 'خراسان رضوی', NULL, '<p>پیمانکاری ، خدمات پشتیبانی و حمل نقل</p>', NULL, NULL, '2025-10-12 13:54:54', '2025-10-12 13:56:38'),
(905, 6051, 'ژیک پارسیان الکترونیک', NULL, 'company-default.png', '117', 'تهران', 'جمهوری بعد از پل حافظ به سمت بهارستان بعد از سی تیر کوچه نوبهار ساختمان طوبی طبقه ۳واحد۷ نام خدا', '۰۲۱۶۶۷۱۸۵۴۸', '8', 'تهران', NULL, '<p>احتراماً،<br>بدین‌وسیله شرکت ژیک پارسیان الکترونیک به عنوان یک مجموعه بازرگانی فعال در زمینه تأمین، فروش تجهیزات نظارتی و حفاظتی از جمله دوربین‌های مدار بسته، دستگاه‌های ضبط تصویر (DVR/NVR)، تجهیزات شبکه، کنترل دسترسی و سیستم‌های هوشمند امنیتی، معرفی می‌گردد.</p><p>این شرکت با بهره‌گیری از تیمی متخصص و با تجربه در حوزه سیستم‌های امنیتی و نظارتی، توانسته است طی سال‌های اخیر پروژه‌های متعددی را در بخش‌های خصوصی و دولتی با موفقیت اجرا نماید.<br>اهداف اصلی شرکت ژیک پارسیان الکترونیک، ارائه محصولات با کیفیت، خدمات فنی سریع و پشتیبانی مستمر به مشتریان گرامی می‌باشد.<br>&nbsp;</p>', NULL, NULL, '2025-10-12 14:18:36', '2025-10-12 14:22:04'),
(906, 6074, 'سپهر نیرا نور', 'تا 100 نفر', '10d786ccc442fe91b68b93acc8f014b3.png', '153', 'مشهد', 'کیلومتر 16 جاده کالت 500 متر بالاتر از روستاي پاژ نرسیده به کمربند سبز سمت چپ', '32600218', '11', 'خراسان رضوی', NULL, '<p>شرکت نیرانور از سال ۱۳۹۳ با نگاهی خلاقانه و تخصصی در زمینه‌ی طراحی و تولید لوسترهای سفارشی و اکسسوری‌های خاص فعالیت خود را آغاز کرده است. فرهنگ سازمانی ما بر پایه‌ی نوآوری، دقت، همکاری و تعهد به کیفیت استوار است. در نیرانور، هر عضو تیم بخشی از یک خانواده‌ی حرفه‌ای و پویاست که هدف مشترک ما را دنبال می‌کند: خلق آثاری که فراتر از روشنایی، احساس، زیبایی و هویت را به فضا می‌بخشند. ما باور داریم که موفقیت در تلفیق هنر و فناوری نهفته است؛ از این‌رو، با بهره‌گیری از تجهیزات پیشرفته، طراحی‌های منحصربه‌فرد و هنر دست استادکاران توانمند، در مسیر ارائه‌ی تجربه‌ای متمایز به کارفرمایان، معماران و طراحان داخلی گام برمی‌داریم.</p><p>نیرانور؛ جایی که همکاری، خلاقیت و نور در کنار هم معنا پیدا می‌کنند.</p>', NULL, NULL, '2025-10-13 09:32:24', '2025-11-13 11:49:06'),
(908, 6101, 'آرش بازرگان', 'کمتر از 20 نفر', 'company-default.png', '153', 'مشهد', 'بلوار ملک آباد . ملک آباد ۱۳', '۰۹۱۵۳۲۰۲۸۴۳', '11', 'خراسان رضوی', NULL, '<p>شرکت پخش محصولات آرایشی و بهداشتی</p>', NULL, NULL, '2025-10-14 09:42:06', '2025-10-14 09:45:20'),
(909, 6104, 'آرتا پیوند اکسیر', NULL, '78699aea5b13265b92593bd0a3571968.jpeg', '117', 'تهران', 'تهران منطقه ۲۲ میدان موج بلوار علامه قزوینی برج کنتراست ( اوست مال) طبقه ۶ واحد ۸', '09129672377', '8', 'تهران', NULL, '<p>شرکت آرتا پیوند اکسیر، تنها نماینده رسمی فروش و تضمین اصالت محصولات برند معتبر KESENS - SSAT در ایران، از سال ۱۴۰۰ با هدف تحول در بازار قطعات یدکی خودرو فعالیت خود را آغاز کرده است. ما با تکیه بر اصالت کالا، کیفیت بی‌نظیر و قیمت‌گذاری رقابتی، افتخار داریم انتخاب اول متخصصان و فروشندگان قطعات خودرو باشیم.</p><p>برند KESENS با بیش از ۱۵ سال حضور موفق در تأمین قطعات حیاتی و باکیفیت برای بزرگ‌ترین خودروسازان کشور، حتی در سخت‌ترین شرایط تحریم، همواره پشتیبان صنعت خودرو ایران بوده و نقشی کلیدی در پایداری چرخه تولید ایفا کرده است.</p><p>آرتا پیوند اکسیر، تضمین اصالت، کیفیت و قیمت—همراهی مطمئن در مسیر حرکت صنعت خودرو</p>', NULL, NULL, '2025-10-14 13:07:23', '2025-10-14 13:50:32'),
(910, 6106, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-14 13:45:17', '2025-10-14 13:45:17'),
(911, 6109, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-14 16:46:05', '2025-10-14 16:46:05'),
(912, 6203, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-17 23:55:31', '2025-10-17 23:55:31'),
(914, 6228, 'پتروپالایش فردیس شیمی', NULL, 'company-default.png', '153', 'مشهد', 'شهرک صنعتی کاویان ،کیلومتر45 جاده فریمان', '05134693270-71', '11', 'خراسان رضوی', NULL, '<p>شرکت پترو پالایش فردیس شیمی ، شرکتی است که در زمینه تهیه، تولید، توزیع، بسته‌بندی و خرید و فروش تینر و انواع حلال‌های شیمیایی مجاز و انواع چسب‌ها فعالیت می‌کند. این شرکت همچنین در ارائه خدمات مشاوره در زمینه انجام فعالیت‌های تجاری و بازرگانی از جمله: خرید و فروش، واردات و صادرات کالاهای مجاز و ترخیص کالا از گمرکات کشور، اخذ و اعطای نمایندگی به شرکت‌های داخلی و خارجی، ایجاد شعب و نمایندگی در داخل و خارج از کشور، برگزاری و شرکت در نمایشگاه‌های داخلی و بین‌المللی، و عقد قرارداد با اشخاص حقیقی و حقوقی، ارگان‌ها و نهادهای دولتی و خصوصی، داخلی و خارجی فعال است. طبق آخرین تغییرات، محل شرکت به آدرس استان خراسان رضوی، شهرستان فریمان، بخش مرکزی، دهستان سنگ بست، روستای شهرک صنعتی کاویان، شهرک صنعتی کاویان، خیابان مسیر فشار قوی برق، کوچه صنعت 1/12، پلاک 4، طبقه همکف تغییر یافته است.</p>', NULL, NULL, '2025-10-18 15:34:33', '2025-10-18 15:45:29'),
(915, 6277, 'نیوان مشاور اورامان', NULL, 'company-default.png', '153', 'مشهد', 'دندانپزشکان ۱۳ ( دادگستر ۱۴ ) _ پلاک ۱۱', '۰۵۱۹۱۶۹۰۶۶۴', '11', 'خراسان رضوی', NULL, '<p>مؤسسه حسابرسی و خدمات مدیریت نیوان مشاور اورامان در تاریخ ۲۴ اردیبهشت ۱۳۹۱، با نام “فرزین مشاور شرق” و به شماره ثبت ۳۴۶۸ در اداره ثبت شرکت‌های خراسان رضوی به ثبت رسید و فعالیت‌های حرفه‌ای خود را در چارچوب موضوع اساسنامه آغاز کرد. این مؤسسه پس از اخذ مجوز از جامعه حسابداران رسمی و تغییر نام به “مؤسسه حسابرسی و خدمات مدیریت نیوان مشاور اورامان”، با تدوین استراتژی جدید و بازنگری در ساختار سازمانی مطابق با ساختارهای حاکم بر مؤسسات حسابرسی، در پاسخ به نیازهای حرفه‌ای ذی‌نفعان و با هدف گسترش حوزه‌های فعالیت و تنوع در ارائه خدمات تخصصی، اقدام به توسعه حوزه جغرافیایی و ایجاد شعبه تهران نمود تا امکان ارائه خدمات حرفه‌ای در سطح ملی و بین‌المللی تقویت شود.</p><p>این مؤسسه با اتکا به سوابق حرفه‌ای درخشان و متنوع شرکا، مدیران و همکاران حرفه‌ای در چارچوب اساسنامه، به‌سوی تحقق استراتژی‌های کلان خود حرکت می‌کند و مسیر رشد و توسعه کسب‌وکار خود را هموار ساخته است.</p>', NULL, NULL, '2025-10-20 13:09:10', '2025-10-27 14:51:04'),
(916, 6283, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-20 15:43:55', '2025-10-20 15:43:55'),
(917, 6285, 'داناراهبرد به روش مانا', 'کمتر از 10 نفر', 'company-default.png', '117', 'تهران', 'هفت تیر', '02188844191', '8', 'تهران', NULL, '<p>موسسه خدمات مالیات و حسابداری داناراهبرد با بیش از 27 سال تجربه وکالت موفق در زمینه پرونده های مالیاتی در اصناف مختلف از قبیل پارچه ، پوشاک ، کفش ، لوازم یدکی خودرو ، آهن، رستوران ، تالار ، خرازی ، لوازم الکتریکی ، و ...... در کارنامه خود دارد.</p><p>کلیه مودیان محترم با مراجعه به یکی از دفاتر اسناد رسمی و تفویض وکالت در زمینه مالیات به این موسسه ,&nbsp; &nbsp;خود را تا پایان قرارداد از هرگونه مراجعه در هر زمینه ای به سازمان امور مالیاتی مربوطه معاف و بی نیاز می نماید.&nbsp;</p><p><br>&nbsp;</p>', NULL, NULL, '2025-10-20 16:15:38', '2025-10-21 11:59:38'),
(918, 6299, 'نکا پلاستیک', NULL, '85bc992041b890475c56aabfba327e34.png', '117', 'تهران', 'تهران ، خیابان طالقانی پلاک 60 طبقه سوم', '77627483', '8', 'تهران', NULL, '<p>شرکت نکا پلاستیک در سال 1353با نام ایران سیپاکس در اداره ثبت شرکت ها و موسسات تاسیس و به ثبت رسیده است که بعد از انقلاب جمهوری اسلامی از ایران سیپاکس به نکا پلاستیک تغییر پیدا کرد . این شرکت به عنوان اولین و بزرگترین تولید کننده محصولات پلی اتیلن در ایران و خاورمیانه فعالیت خودرا در سال 1356 با ظرفیت تولید500 تن در سال آغاز نمود .</p>', NULL, NULL, '2025-10-21 11:10:08', '2025-12-25 13:57:01'),
(919, 6301, 'دفتر پیشخوان دولت و امور مشترکین', 'کمتر از 10 نفر', '015a0452d44a66321801a352625499e0.jpg', '153', 'مشهد', 'مشهد میدان بار نوغان نبش رسالت 55/3', '05132700219', '11', 'خراسان رضوی', '3f40ef01bb6b47dbaa312fafae6bf8f8.jpg,f6ecea4b7d8679d7c5d20a3f38fee460.jpg,6f38d000dc6785deb33edba8417f0d73.jpg,0eff04fb19267415daf26fd9cc559a0d.jpg,5103bad08f929d84fbe8a28ac1bf2daf.jpg,97d03f67d6ce8668e6e0649f2c007e1d.jpg', '<p>دفتر پیشخوان دولت و امور مشترکین و خدمات اینترنتی و پستی و ایرانسل همراه اول و رایتل اپراتور شرکت تالیا&nbsp;</p>', NULL, NULL, '2025-10-21 11:53:00', '2025-10-21 11:57:45'),
