(922, 6329, 'پخش سراسری طناز طلایی جنوب', NULL, 'company-default.png', '153', 'مشهد', 'پیامبر اعظم ۸۵ خلیلی ۸', '09151599455', '11', 'خراسان رضوی', NULL, '<p>پخش سراسری طناز طلایی جنوب یکی از شرکت‌های فعال در صنعت کشور است که با تکیه بر تجربه و دانش روز، خدمات با کیفیت ارائه می‌دهد. ما با هدف ارتقای سطح خدمات و رضایت مشتریان، در مسیر توسعه پایدار قدم برمی‌داریم.</p>', NULL, NULL, '2025-10-22 13:39:40', '2025-10-22 13:56:30'),
(923, 6336, 'مدرن بتن پاژ', NULL, 'company-default.png', '153', 'مشهد', 'فلسطین 21 پلاک 50', '38331052', '11', 'خراسان رضوی', NULL, '<p>شرکت پیمانکاری ساختمان در زمینه انبوه سازی فعالیت دارد&nbsp;</p>', NULL, NULL, '2025-10-22 15:12:44', '2025-10-22 15:46:21'),
(924, 6338, 'کارگزاری شعبه ۲', NULL, 'company-default.png', '117', 'تهران', 'کارگر جنوبی کوچه شهید حیدری', '۵۵۴۲۵۵۶۷', '8', 'تهران', NULL, '<p>کارگزاری در زمینه بیمه و حسابرسی فعالیت دارد.</p>', NULL, NULL, '2025-10-22 16:18:07', '2025-10-22 16:22:16'),
(925, 6349, 'روبین', NULL, 'company-default.png', '153', 'مشهد', 'تعبدی ۱۰ پلاک ۵/۲', '۰۹۱۵۴۱۵۷۵۶۵', '11', 'خراسان رضوی', NULL, '<p>مجموعه ما فعالیت خود را از سال <strong>۱۳۹۲</strong> در حوزه <strong>تولید و عرضه انواع پرده</strong> آغاز کرده است. این فعالیت‌ها در دو بخش <strong>B2B</strong> (همکاری با کسب‌وکارها) و <strong>B2C</strong> (فروش مستقیم به مصرف‌کننده) انجام می‌شود.</p><p>در حال حاضر، مجموعه با <strong>سه برند تجاری</strong> در بازار حضور دارد:</p><p><strong>دکوربرتر</strong> – برند تخصصی در بخش <strong>B2B</strong> که تمرکز آن بر همکاری با همکاران، طراحان دکوراسیون داخلی و فروشندگان فعال در صنعت پرده است.</p><p><strong>الو زبرا</strong> – برند <strong>B2C</strong> مجموعه که بیشتر بر بازار مصرف‌کننده نهایی تمرکز دارد. مخاطبان این برند عمدتاً مشتریانی هستند که به دنبال خرید اقتصادی و مقرون‌به‌صرفه‌اند. از آنجا که ما تولیدکننده مستقیم هستیم و محصولات خود را با قیمت مناسب عرضه می‌کنیم، توان رقابت بالایی در این بخش از بازار داریم.</p><p><strong>روبین</strong> – برند <strong>B2B</strong> سطح‌بالای مجموعه که خدمات و محصولات ممتاز و باکیفیتی ارائه می‌دهد، ویژه مشتریانی که به دنبال طراحی خاص، کیفیت بالا و تجربه‌ای متمایز هستند. این برند بر روی حدود ۵٪ از بازار متمرکز است که ارزش و کیفیت برایشان اولویت دارد.</p>', NULL, NULL, '2025-10-23 15:37:23', '2025-10-27 11:24:32'),
(927, 6363, 'گالری طلا و جواهر ارفعی', NULL, 'company-default.png', '153', 'مشهد', 'چهار طبقه', '09154124016', '11', 'خراسان رضوی', NULL, '<p>خرده فروشی طلا و جواهرات<br>گالرى طلا و جواهر كاوه (ارفعي) در مشهد، ارائه‌دهنده‌ی زیورآلات و طلا جواهر نقره با امکان خرید آنلاین و کارت خوان. ما به عنوان یک خرده‌فروش طلا و جواهرات، بهترین محصولات را با کیفیت بالا و قیمت مناسب ارائه می‌دهیم.</p><p>&nbsp;</p>', NULL, NULL, '2025-10-25 13:56:55', '2025-10-25 14:51:00'),
(928, 6383, 'تولیدی آهن پوش', NULL, 'company-default.png', '117', 'تهران', 'حکیمییه خیابان سازمان آب کوچه دوم غربی', '02177339083', '8', 'تهران', NULL, '<p>شرکت تولیدی آهن پوش با سابقه 50 ساله در تولید و برش ورق های &nbsp;گالوانیزه و رنگی<br><br>این شرکت با هدف تولید ورق‌های پوششی سقف برای سازه‌های صنعتی، مسکونی و ویلایی و همچنین ارائه لوازم جانبی مربوطه تأسیس گردیده است.</p><p>مجموعه ما با بهره‌مندی از سالن‌های مجهز به خطوط تمام اتوماتیک و استاندارد، محصولات خود را به عنوان اولین تولیدکننده پوشش فلزی با طرح سفال در شرق تهران، به مشتریان محترم عرضه می‌کند.</p><p>محصولات این شرکت قابلیت نصب یکپارچه در سقف‌های چندشیب و قوسی را دارند. انواع طرح‌های سینوسی (کرکره‌ای)، ذوزنقه‌ای، طرح‌های سفال (ژاپنی و ایتالیایی)، طرح لمبه (دامپا) و متعلقات مربوطه، به صورت ورق‌های گالوانیزه و رنگی ارائه می‌شوند.</p>', NULL, NULL, '2025-10-26 10:18:37', '2025-10-28 12:58:01'),
(929, 6414, 'محاسب پرواز ماندگار', NULL, '0ace49ad16509047f37869245af6b454.jpeg', '153', 'مشهد', 'سجاد ۲۴پلاک ۴۴۲', '05136023021', '11', 'خراسان رضوی', '', '<p>شرکت مالی و مالیاتی آژانس های هواپیمایی</p><p>تاریخ تاسیس: 1401/12/07</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p><br><br>&nbsp;</p><p>&nbsp;</p>', NULL, NULL, '2025-10-27 11:00:21', '2025-10-27 12:40:28'),
(930, 6415, 'همسفران مشهد', NULL, 'company-default.png', '153', 'مشهد', 'فلسطین 18', '09155025309', '11', 'خراسان رضوی', NULL, '<p>شرکت خدمات مسافرتی، هوایی، جهانگردی و زیارتی <strong>همسفران مشهد</strong> از سال ۱۳۷۴ با اخذ مجوز از <strong>سازمان میراث فرهنگی، صنایع دستی و گردشگری</strong>، <strong>سازمان هواپیمایی کشوری</strong> و <strong>سازمان حج و زیارت</strong> فعالیت خود را آغاز نمود.<br>این شرکت در زمینه جذب گردشگران از <strong>کشورهای حوزه خلیج فارس</strong> و <strong>کشورهای مستقل مشترک‌المنافع (CIS)</strong> فعالیت دارد.<br>از جمله فعالیت‌های شاخص و هدفمند شرکت، <strong>گردشگری سلامت</strong> است که خوشبختانه با <strong>استقبال چشمگیر متقاضیان از سراسر جهان</strong> روبه‌رو شده است.</p>', NULL, NULL, '2025-10-27 11:06:16', '2025-10-27 12:34:28'),
(931, 6466, 'شرکت مالی و مالیاتی مالی گستر', NULL, '77138590655728ea849273a0f0d2fc13.jpeg', '117', 'تهران', 'تهران - میدان ازادی - بزرگراه جناح - بلوار صالحی - تقاطع صفا', '02191011911', '8', 'تهران', NULL, '<p>شرکت خدمات مالی و مالیاتی مالی گستر</p><p>با 10 سال سابقه کاری در زمینه خدمات تخصصی مالیاتی و مالی در زمینه سرپرستی، مشاوره و انجام امور اشخاص حقیقی و حقوقی</p><p>&nbsp;</p>', NULL, NULL, '2025-10-28 17:52:20', '2025-10-28 18:33:54'),
(932, 6479, 'Gallent', 'تا 50 نفر', '2bd0d8b411a50a4ed4b172bbd8822d69.jpg', '133', 'باقرشهر', 'باقرشهر شهر سنگ', '09027065714', '8', 'تهران', 'd7575b6d7f08d4c30bcbb8b058aea902.jpg,c9df3c2a0a59786d82a179c2848a15d4.jpg,27d3af85a26f43a5c233ce28e75cbb80.jpg,d4c6b04f48956913a5d847623e717b99.jpg', '<p>تولیدی پوشاک مردانه</p><p>تاریخ تأسیس: ۱۳۹۸</p><p>&nbsp;عمده‌فروشی در بازارهای <strong>فردوسی</strong> و <strong>سینا</strong></p><p>محل کار: باقرشهر (شهر ری)</p>', NULL, NULL, '2025-10-29 12:49:38', '2025-10-29 13:55:01'),
(935, 6495, 'جلگه قلب باغستان', 'کمتر از 20 نفر', '9c52bb5bfda928be6f39a59d1902a9f4.png', '134', 'شهریار', 'شهریار شهرک باباسلمان', '09127647758', '8', 'تهران', NULL, '<p>در کنار شما برای پرورش سلامت<br>شرکت جلگه قلب باغستان با سالها تجربه و روز آمدترین فن آوری ها و پیشرفته ترین سیستم های کامپیوتری در زمینه پرورش قارچ بهره گرفته می شود و هر روزه کیفیت محصول در تمامی فرآیندهای پرورش و تولید از لحظه بستر رویش قارچ بذر زده تا مرحله برداشت نهایی محصول ، زیر نظر متخصصان کارآزموده کنترل می شود. جلگه قلب باغستان رسالت و ماموریـت ملی خود را فقط در پرورش و عرضه قارچ با حداکثر کیفیت ممکن می داند و می کوشد تا بر همین اساس به کسب اعتماد بازار و جلب رضایت مصرف کننده اقدام کند.</p>', NULL, NULL, '2025-10-30 12:56:00', '2025-11-01 15:14:44'),
(936, 6525, 'مهندسی رسام تجارت ورنا', 'کمتر از 20 نفر', 'company-default.png', '117', 'تهران', 'میدان  توحید خیابان نصرت غربی', '02166437942', '8', 'تهران', NULL, '<p>شرکت مهندسی رسام تجارت ورنا در زمینه خدمات مهندسی اعلام و اطفا حریق و حفاظت الکترونیک فعالیت مینماید</p>', NULL, NULL, '2025-10-31 12:30:55', '2025-10-31 12:36:34'),
(937, 6532, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-31 18:55:11', '2025-10-31 18:55:11'),
(938, 6545, 'زمزمه سفرطوس', NULL, '13d3fa67cb26e828b861dd0ca4d58002.jpeg', '153', 'مشهد', 'خیابان کاشانی بین کاشانی 4و6پلاک 80', '09157878782', '11', 'خراسان رضوی', '', '<p><i>کاربری این شرکت خدمات گردشگری و مسافرتی بلیت قطار هواپیما تور داخلی و خارجی میباشد</i></p>', NULL, NULL, '2025-11-01 13:39:06', '2025-11-01 15:33:56'),
(939, 6547, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-01 14:25:11', '2025-11-01 14:25:11'),
(940, 6560, 'مجتمع خدماتی رفاهی گردشگری هشت بهشت', 'کمتر از 20 نفر', 'e32f37c4b16e28cd53d69a9512382f34.jpg', '161', 'تربت جام', 'کیلومتر ۳ محور تربت جام به مشهد مجتمع خدماتی رفاهی گردشگری هشت بهشت', '09151262711', '11', 'خراسان رضوی', 'cd67c3245a0fa6878ea9f13ab37968c2.jpg,841ef233c6d37e196d30cab94631b308.jpg,632531b1d6ef4fb4e630e6fc2f6715d4.jpg', '<p>مجتمع خدماتی رفاهی هشت بهشت دارای امکانات دو سالن پذیرایی &nbsp;و مسجد وسرویس های بهداشتی و &nbsp;رستوران و سوپر مارکت و کافی شاپ و محوطه فضا سبز و بازی کودکان وآلاچیق و محل استراحت رانندگان و مسافران می باشد&nbsp;</p>', NULL, NULL, '2025-11-02 07:28:27', '2025-11-02 07:39:33'),
(941, 6563, 'ماداستیل آسیا', NULL, 'company-default.png', '153', 'مشهد', 'مشهد . سه کیلومتر بعد از شهرک صنعتی مشهد . بعد از تقاطع کمربندی سبز و جاده کلات . سمت راست مجتمع صنعتی صدف . کارخانه شرکت ماد استیل', '09029674701', '11', 'خراسان رضوی', NULL, '<p>شرکت ماد استیل آسیا با مدیریت مهندس محمد معینی مخترع و کار آفرین ملی از سال ۱۳۸۴ فعالیت خود را در زمینه های مهندسی مکانیک و شیمی آغاز کرده و مفتخر به ثبت اختراع در زمینه سیستم های حفاظت کاتدی در تاریخ ۱۳۸۵/۰۹/۲۲ به شماره ثبت ۳۷۸۸۴ و کولر آبی صوتی در تاریخ ۱۳۸۶/۰۹/۲۱ به شماره ثبت ۴۴۷۵۶ و چندین اختراع دیگر شده و موفق به کسب گواهی علمی از پارک علم و فن آوری به شماره ثبت ۷۱۲/۹۱ و شماره پرونده ۴۹۰۸۷۰۱۷ شده است و از سال ۱۳۸۶ در راستای ارتقاء سطح بهداشت و سلامت جامعه و با هدف ایجاد اشتغال هموطنان گرامی و کمک به تولید کننده های داخلی اقدامبه ارائه فرمولاسیون های مواد شوینده قابل رقابت با محصولات خارجی نموده و با تولید و عرضه ماشین آلات خط تولید شوینده با کیفیت عالی و قیمت مناسب در جهت نیل به اهداف گام برداشته است. شرکت ماد استیل آسیا متشکل از کادر مجرب و متخصص در زمینه های مکانیک جامدات، مکانیک جوشکاری ، شیمی، برق الکترونیک و کامپیوتر می باشد.فرمولاسیون های ارائه شده و ماشین آلات خط تولید مواد شوینده ساخته شده توسط این شرکت مطابق با جدیدترین دستاوردهای جهانی است و خط تولیدهای راه اندازی شده توسط متخصصین و کارشناسان شرکت ماد استیل آسیا کاملا مورد تایید بازرسین مجرب وزارت صنایع و معادن ، وزارت بهداشت و درمان و سازمان استاندارد ملی ایران می باشد.</p>', NULL, NULL, '2025-11-02 09:57:17', '2025-11-02 10:01:40'),
(943, 6654, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-06 13:51:36', '2025-11-06 13:51:36'),
(944, 6667, 'وستا تجهیز پارت', 'تا 100 نفر', 'c48bd493c7c84e4204ac327ebf8d464c.jpg', '117', 'تهران', 'جردن، ناهید غربی ، روبروی بانک کار آفرین پلاک 57 هلدینگ وستا', '02172801', '8', 'تهران', NULL, '<p>شرکت وستا تجهیز پارت در مرداد ماه سال 1390، با هدف فعالیت در زمینه علوم آزمایشگاهی در ایران تاسیس گردید. این شرکت همواره در تلاش بوده است که با عرضه برندهای مطرح دنیا در زمینه فروش، خدمات پس از فروش و همچنین ارائه مشاوره تخصصی، در خدمت مخاطبین عام و خاص خود باشد. در طی گذشت سالیان متوالی از فعالیت تخصصی در حوزه تشخیص و آزمایشگاه، شرکت وستا تجهیز پارت همواره سعی بر آن داشته تا با افزایش میزان کیفیت و گستردگی زمینه فعالیت خود، بیشترین میزان رضایتمندی را از جامعه هدف کسب نماید.فعالیت اصلی شرکت ما تجهیز مراکز تحقیقاتی و آزمایشگاه‌های تشخیصی با عرضه طیف گسترده‌ای از ابزار، معرف‌ها و سایر مواد و تجهیزات مصرفی در زمینه‌های هورمون، بیوشیمی، ایمونواسی، تشخیص مولکولی و همچنین ژنتیک مولکولی است.</p><p>وستا همچنین یکی از معدود شرکت هایی است که از سوی وزارت بهداشت، درمان و آموزش پزشکی (MOHME) ایران مجاز به ارائه خدمات پس از فروش، کالیبراسیون و کنترل کیفی تجهیزات آزمایشگاهی می باشد.</p><p>این شرکت دارای مدیران برجسته در زمینه علوم آزمایشگاهی و پزشکی و همچنین در زمینه مدیریت با کادری مجرب و تحصیلکرده می باشد که یکی از عوامل اصلی موفقیت شرکت وستا تجهیز پارت می باشد.</p><p>این شرکت بر اساس دانش اعضای خود موفق به اخذ نمایندگی انحصاری فروش و خدمات پس از فروش از بزرگترین شرکت های جهان در خاورمیانه شده است و به همین دلیل به عنوان یکی از بهترین کارآفرینان در زمینه تجهیزات آزمایشگاهی در ایران شناخته می شود.</p><p>برگزاری سمینارها، کارگاه ها و کنفرانس های علمی در دانشگاه ها و مراکز تحقیقاتی بزرگ از دیگر فعالیت های مهم وستا است.</p><p>تعهد اخلاقی، فرهنگ سازمانی شایسته، پوشش رسمی، و تعهد اخلاقی از مواردی است که در این سازمان در تعهد پرسنل می باشد</p><p>ارائه خدمات پس از فروش رایگان به موسسات خیریه و آزمایشگاه ها در نقاط دور دست از دیگر افتخارات این شرکت می باشد.</p>', NULL, NULL, '2025-11-07 13:35:28', '2025-11-08 14:22:24'),
(946, 6673, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-07 19:04:30', '2025-11-07 19:04:30'),
(947, 6675, 'صنایع غذایی تژین', 'کمتر از 20 نفر', 'company-default.png', '117', 'تهران', 'شهرک غرب', '09021818546', '8', 'تهران', NULL, '<p>تولید محصولات گیاه پایه مانند انواع مکمل های غذایی مانند پودر جوانه گندم<br>دردنیای گسترده علم تغذیه، این جوانه ها هستند که به این شعار معنی و مفهوم می دهند: \"جوانه های غلات و بقولات و دانه های سبزیهای خوراکی که همه سرشار از ویتامینها و مواد غذایی و سایر ترکیبات مفید غذایی هستنددر تندرستی انسان نقش بسیار مهمی بازی می کنند\". بر پایه همین پندار و یافته های علمی بود که شرکت صنایع غذایی تژین در سال 1373 پایه گذاری و آغاز بکار نمود. پیش از آن با انجام آزمایشات و بررسیهای لازم در یک کارگاه کوچک خانگی تجربیات کافی و مفید به دست آمده بود و موسس تژین مهندس ایرج نصیری طوسی، با علاقه زیاد و پشتکار و همت خود توانست این نهاد را با هدف بالا بردن تندرستی هم میهنان عزیز (همان طور که در اساسنامه شرکت آمده) پایه گذاری نماید.البته شرکت تژین هم اکنون نیز از دانش و تجربیات ایشان برخوردار می باشد. نخستین فرآورده شرکت بنام پودر جوانه گندم تژین وارد بازار شد و در اختیار مصرف کنندگان آگاه و علاقمند قرار گرفت، و پس از آن بود که بتدریج ده ها موسسه و شرکت دیگر آغاز به تولید پودر جوانه گندم نمودند. صنایع غذایی تژین هم اینک با بیش از 10 فرآورده دیگر در همین زمینه به فعالیتهای خود ادامه می دهد و افتخار می نماید که اولین تولید کننده مجاز پودر جوانه گندم در کشور می باشد. جا دارد از کلیه دوستان و همکاران و گروه کارکنان صمیمی شرکت و نهادهایی که ما را در این راهه یاری داده و می دهند سپاسگزاری نماییم که در این میان بخصوص باید از نهاد جهاد سازندگی یاد کنیم که از همان ابتدای کار راهنما و مشوق ما در ازای این راه بودند.</p>', NULL, NULL, '2025-11-07 19:43:23', '2025-11-08 11:43:18'),
(948, 6679, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-07 23:52:18', '2025-11-07 23:52:18'),
(949, 6681, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-08 08:54:20', '2025-11-08 08:54:20'),
(950, 6686, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-08 17:35:36', '2025-11-08 17:35:36'),
(951, 6691, 'آتالان تک', 'کمتر از 20 نفر', '6cd02ec3c4cf20f415b863162d3bae37.jpg', '153', 'مشهد', 'شهرک صنعتی ماشین سازی و فناوری برتر-صنعت۵-پلاک ۱۸۶A', '۰۹۳۹۳۱۶۴۰۶۴', '11', 'خراسان رضوی', NULL, '<p>شرکت تولید قطعات خودرو<br>آتالان تک فعالیتش در زمینه تولید قطعات جلوبندی خودرو است.<br>محصولات این شرکت شامل لوازم یدکی مانند دیسک ترمز، سیبک، قطعات فرمان خودرو و قطعات مربوط به قسمت جلوبندی خودرو هستند.<br>&nbsp;</p>', NULL, NULL, '2025-11-09 14:52:37', '2025-11-09 15:38:59'),
(952, 6694, 'خدمات آوا گستر اندیشان', NULL, 'company-default.png', '418', 'همدان', 'همدان', '09339735828', '30', 'همدان', NULL, '<p>همکاری با ده ها شرکت تامین کننده معتبر مانند گروه رضوان شکلات و محصولات مولفیکس، رانی و... همچنین بیش از 70000 مشتری فعال در حوزه هایپرمارکت ها، فروشگاه های زنجیره ای، تعاونی ها، کارخانجات صنعتی تولید کننده بستنی و اصناف کوچکتر همانند شیرینی جات، قنادی و سوپرمارکت ها، از سال 1395 اقدام به توزیع مویرگی محصولات خود نموده است و در مدت زمان کوتاهی سهم مناسبی از بازار فروش در سراسر کشور به دست آورده است.</p>', NULL, NULL, '2025-11-09 17:31:46', '2026-01-28 12:35:38'),
(953, 6696, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-09 21:49:23', '2025-11-09 21:49:23'),
(954, 6699, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-10 09:27:00', '2025-11-10 09:27:00'),
(955, 6713, 'رائین سیستم', NULL, 'company-default.png', '117', 'تهران', 'تهران خیابان مفتح شمالی', '21-88709828', '8', 'تهران', NULL, '<p>شرکت مهندسی رایین سیستم با در اختیار داشتن کارشناسان مجرب کامپیوتر با تخصص های متفاوت ، در سال 1372 تاسیس گردید و در طول فعالیت خود با جذب نیروهای متخصص در سایر رشته های مرتبط و با مشاوره ، همیاری و بهره جستن از تخصص مدیران درجه اول کشور در رشته های گوناگون وآموزش دقیق پرسنل بمنظور آشنایی با جدیدترین فن آوری های علم کامپیوتر ، همواره حضور قوی و مطرحی در زمینه تولید و ارائه و پشتیبانی نرم افزارهای قدرتمند مالی ، تولید و هتلداری داشته است .</p>', NULL, NULL, '2025-11-10 14:45:18', '2025-11-10 14:50:03'),
(956, 6726, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-11 13:29:14', '2025-11-11 13:29:14'),
(957, 6730, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-11 16:35:43', '2025-11-11 16:35:43'),
(958, 6741, 'پیشتاز صنعت', NULL, 'company-default.png', '117', 'تهران', 'تهران -محدوده مترو دکتر شریعتی', '02136429008', '8', 'تهران', NULL, '<p>تولید کننده قطعات سنگ شکن و قطعات ماشین آلات معدنی و راه سازی و در سال 1385 تاسیس شده است .&nbsp;</p>', NULL, NULL, '2025-11-12 14:00:05', '2025-11-13 10:55:36'),
(959, 6747, 'بنیاد سلامت', NULL, 'company-default.png', '153', 'مشهد', 'ملک آباد 9 ، نسترن7 ، پلاک 40', '09058615402', '11', 'خراسان رضوی', NULL, '<p>دکتر حوصله، متخصص حرکات اصلاحی و بهبود عملکرد بدن، با سالها تجربه در حوزه سلامت و تناسب اندام، همراه شماست تا مشکلات جسمانی را شناسایی کرده و با ارائه برنامه‌های تمرینی شخصی‌سازی شده، به شما کمک کند تا دردها را کاهش دهید، وضعیت بدنی خود را بهبود بخشید و کیفیت زندگی خود را ارتقا دهید.</p>', NULL, NULL, '2025-11-12 17:11:21', '2025-11-13 11:06:30'),
(960, 6771, 'فولاد تجارت عرفان', NULL, '75ab61ae5290b563eef74a2e507c18d1.jpeg', '117', 'تهران', 'مرزداران', '۴۷۳۸۵۰۰۰', '8', 'تهران', '205a1764c3cd7fe7418ff241d03fe448.jpeg', '<p>شرکت فولاد تجارت عرفان &nbsp;در سال 1387 تاسیس شده است .&nbsp;</p><p>شرکت در زمینه خرید و فروش انواع پروفیل،ورق و ... فعالیت دارد.<br><br>محصولات و خدمات : ورق،پروفیل،میلگرد<br>&nbsp;</p><p>&nbsp;</p>', NULL, NULL, '2025-11-13 16:13:09', '2025-11-15 12:41:09');
INSERT INTO `companies` (`id`, `user_id`, `name`, `size`, `logo`, `city_id`, `city_name`, `address`, `tel`, `province_id`, `province_name`, `gallery`, `intro`, `culture`, `advantages`, `created_at`, `updated_at`) VALUES
(961, 6776, 'مهتاب سازه توس', NULL, 'company-default.png', '153', 'مشهد', 'پیروزی 23/3 پلاک 81', '38769990', '11', 'خراسان رضوی', NULL, '<p>این شرکت در سال 1382 توسط 5 تن از فارغ التحصیلان رشته مهندسی عمران تاسیس ، و با بهره گیری از مهندسین و متخصصین رشته های مهندسی عمران، برق و مکانیک موفق شده است پروژه های مختلفی را در زمینه های ابنیه و ساختمان سازی در سطح کشور به انجام رساند.<br>دامنه فعالیت های این شرکت در زمینه طراحی و اجرای عملیات ابنیه، ساختمان، راهسازی، محوطه سازی، اجرای دیوار و ساختمان پیش ساخته و کلیه ی عملیات مربوط به زیرساخت های پستهای برق فشار قوی، و مدرسه و مراکز بهداشتی و نیز پروژه های سازمان عمران شهرهای جدید بوده است.<br>نظر به اینکه این شرکت توانسته است پروژه های خود را با کیفیت عالی و در زمان پیش بینی شده به اتمام برساند ، موفق شده رضایت کارفرمایان مختلف را جلب نماید.</p>', NULL, NULL, '2025-11-14 00:46:36', '2025-11-15 11:57:39'),
(962, 6793, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-14 23:44:06', '2025-11-14 23:44:06'),
(963, 6799, 'دفتر مرکزی اسپورتلند', 'کمتر از 20 نفر', 'a571976e40adb764e0fed5faf971e8f7.jpg', '117', 'تهران', 'سعادت آباد صرافهای شمالی کوچه یزدهم شرقی پلاک 12 طبقه 2', '90003717', '8', 'تهران', NULL, '<p>بزرگترین مولتی برند ورزشی &nbsp;دارای شعب فروش مختلف در اقصی نقاط کشور<br>محیط کاری آرام ،محترمانه&nbsp;<br>فضای رشد شغلی و ارتقا&nbsp;<br>مزایای رفاهی بن خرید از مجموعه ،پاداش،اضافه کاری ،بیمه تامین اجتماعی از روز اول&nbsp;</p>', NULL, NULL, '2025-11-15 10:22:02', '2025-11-15 10:36:27'),
(964, 6804, 'پیشروتجهیزالماس', NULL, '763569d29c3117e75312f70035ac4733.jpg', '117', 'تهران', 'سعادت آباد- علامه جنوبی', '09011496229', '8', 'تهران', NULL, '<p>شرکت پیشرو تجهیز الماس با تکیه بر توان علمی و فنی متخصصان جوان و متعهد خود همچنین امکانات لجستیک شامل بیش از 40,000 مترمربع فضای انبار، دفاتر خارج از کشور، همچنین سابقه همکاری با تولیدکنندگان معتبر داخلی و خارجی در بالاترین سطح کیفی و براساس استانداردهای معتبر جهانی و با رعایت اولویت مشتری مداری و کیفیت برتر خدمات، توانسته است رضایت کارفرمایان را در دامنه های صنعتی مرتبط نظیر : نفت ، گاز ، آب و … فراهم نماید.</p><p>&nbsp;</p>', NULL, NULL, '2025-11-15 13:29:17', '2025-11-15 14:57:17'),
(965, 6809, 'فنی و مهندسی سریر سازان رایکا', 'کمتر از 10 نفر', '10bc276405fde73963d7aac2c34fe526.jpg', '117', 'تهران', 'تهران بزرگراه آبشناسان سردارجنگل جنوبی بهار غربی جنب حسینیه روضه الشهدا پروژه شهرزاد', '09128603056', '8', 'تهران', NULL, '<p>شرکت فنی و مهندسی سریر سازان رایکا ، به عنوان یک بازیگر متخصص و باسابقه در صنعت ساخت‌وساز و پروژه‌های عمرانی، با بهره‌گیری از کادری مجرب از مهندسین، کارشناسان و مدیران پروژه کارآزموده، فعالیت می‌کند. مأموریت اصلی این شرکت، ارائه خدمات جامع از مرحله مطالعات اولیه و طراحی فنی تا اجرا، نظارت و تحویل پروژه‌های ساختمانی و عمرانی مطابق با بالاترین استانداردهای کیفیت و ایمنی است. این شرکت با مدیریت یکپارچه و استفاده از فناوری‌های نوین، متعهد به تحویل به موقع پروژه‌ها در چارچوب بودجه مصوب بوده و نقش بسزایی در توسعه زیرساخت‌ها و تحقق چشم‌اندازهای عمرانی منطقه ایفا می‌نماید.</p>', NULL, NULL, '2025-11-15 15:19:21', '2025-11-15 16:09:07'),
(966, 6823, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-15 19:58:55', '2025-11-15 19:58:55'),
(968, 6837, 'اطلس تجارت افشان', NULL, 'cb37bf27bd49801f500c6d4f2a89d6a0.png', '117', 'تهران', 'مرزداران ابراهیمی برج الوند طبقه اول واحد ۸/۲', '02144389472', '8', 'تهران', NULL, '<p>شرکت اطلس تجارت افشان فعال در حوزه بازرگانی مواد اولیه فلزی غیر اهنی&nbsp;میباشد.<br>شرکت افشان روی از تولیدکنندگان شمش روی و اعضا انجمن سرب و روی ایران می باشد که با سابقه بیش از ۲۰ سال در این صنعت ؛ همواره تلاش داشته تا با تکیه بر تجربه و آگاهی علمی و فنی، نقش موثری را در زنجیره تامین واحدهای مصرف کننده این محصول ایفا نماید.</p>', NULL, NULL, '2025-11-16 09:25:31', '2025-12-21 12:54:09'),
(969, 6841, 'زیستار', NULL, 'e6bcfbf772bb9404bd1b702877dfea02.jfif', '283', 'کرج', 'فردیس بلوار فرگاز نسترن شرقی پلاک 412', '02636607040', '5', 'البرز', NULL, '<p>این شرکت در زمینه تولید و پخش ملزومات حیوانات خانگی فعالیت می کند.</p>', NULL, NULL, '2025-11-16 10:49:38', '2025-11-16 10:52:26'),
(970, 6853, 'رز دیبا فارمد', NULL, '95de191dab2ffeb7fbbee73f53687c14.jpeg', '117', 'تهران', 'شیخ بهایی جنوبی ، برج بین المللی تهران ، واحد تجاریA2', '02196660053', '8', 'تهران', NULL, '<p>محققین ما در بخش تحقیق و توسعه با تکیه بر دانش فنی و با استفاده از تخصص محققین سدرما فرانسه به فرمولاسیونی بی نظیر در جهت درمان و مراقبت تخصصی از پوست دست یافته اند. ما افتخار میکنیم توانسته ایم با توجه به دانش و تکنولوژی پیشرفته اروپا محصولاتی تولید کنیم که به لحاظ کیفیت و ظاهر، بی نظیر است و با آب و هوای ایران کاملًا مطابقت دارد. فرمولاسیون تمامی محصولات رزالیا برپایه دانش ارزشمند مراقبت از سلولهای بنیادی و DNA نانوتکنولوژی و اثرات اعجاب انگیز آن در سلامت و جوانی سلولهای پوست می باشد. این تکنولوژی در حقیقت با تقویت دیواره سلولی و تامین مواد مورد نیاز جهت نگهداری آب سلولی نه تنها از تخریب سلول ها توسط رادیکال های آزاد جلوگیری میکند بلکه به راحتی سبب معکوس شدن روند پیری شده و جوان سازی و ترمیم سلولها را به دنبال دارد. در واقع مجموعه لابراتور رزدییا فارمد آمیزه ای از تکنولوژی، تخصص، طبیعت، مدرنیته و احساس شادابــی میباشد که با استفاده از محصولات طبیعی مشکلات مربوط به سلامتی و زیبایی پوست را برطرف میکند.</p><p>توانایی تیم تحقیق، تولید و توسعه رز دیبا فارمد به شرح ذیل می باشد:</p><p>• انتخاب دقیق ترکیبی بی نظیر از مواد موثره با تکنولوژی برتر در هر یک از محصولات</p><p>• ارتباط مستمر با کارشناسان و لابراتوارهای معتبر بین المللی</p><p>• آزمایش و کنترل کیفیت دائمی محصولات براساس معیارهای درماتولوژیک و درموکازمتیک</p><p>• بررسی کارایی و اثرگذاری محصولات طی انجام آزمایشات دقیق علمی تایید تستهای تحمل، غیر کمدوژنیک و هیپوآلرژنیک بودن محصولات</p>', NULL, NULL, '2025-11-16 14:34:48', '2025-11-16 15:33:15'),
(973, 6905, 'فرافن گاز تهران', 'تا 100 نفر', 'company-default.png', '117', 'تهران', 'ظفر - خ وحید دستگردی - پلاک 200', '02122224210', '8', 'تهران', NULL, '<p>شرکت فرافن گاز تهران یک شرکت تولیدی و تجاری در زمینه گاز و تجهیزات مربوط به آن می باشد. این شرکت یکی از تامین کنندگان پیشتاز در زمینه گازهای صنعتی، آزمایشگاهی و طبی است. تیم تولید مجرب این شرکت ، توانایی ساخت انواع مخلوط های گازی در گستره غلظت های PPM &nbsp;تا درصدی، مانند مخلوط های گازی استاندارد و کالیبراسیون، جوشکاری، برشکاری، اطفا حریق و … را دارد.</p>', NULL, NULL, '2025-11-17 13:28:43', '2025-11-17 13:58:30'),
(974, 6917, 'شرکت رهاباتری نکاس', 'کمتر از 20 نفر', 'c7b5540e69f9d20777c1929fc6c89374.png', '283', 'کرج', 'کرج ب کامیون داران نبش گلستان 11', '02634006077', '5', 'البرز', NULL, '<p>نکاس باتری از سال 1368 فعالیت خود را در زمینه واردات و فروش انواع باتری بصورت عمده آغاز نموده که از سال 94 طبق مصوبه دولت به جهت حمایت از تولید ملی و اقتصاد مقاومتی واردات محصولاتی که تولید ملی را دارا هستند ممنوع گردید و این بازرگانی فعالیت خود را از واردات به فروش عمده و فروشگاه هاي زنجیره اي تغییر داده است.</p>', NULL, NULL, '2025-11-17 16:27:37', '2025-12-27 11:38:42'),
(975, 6924, 'تکلان بیلان پارس', 'کمتر از 20 نفر', 'company-default.png', '153', 'مشهد', 'امامت ۱۵پلاک ۴۹ طبقه اول', '05136083573', '11', 'خراسان رضوی', NULL, '<p>تکلان بیلان پارس در سال &nbsp;1389تاسیس شده &nbsp;و در زمینه کار تبلیغات و چاپ مبتکران توسعه تجارت کاج فعالیت میکند .<br>اهداف شرکت ، تولید محصولات تبلیغاتی است.</p>', NULL, NULL, '2025-11-17 20:18:05', '2025-12-09 10:14:07'),
(976, 6933, 'کاسپین تجهیز', NULL, 'company-default.png', '117', 'تهران', 'پاسداران کوهستان هفتم', '22800079', '8', 'تهران', NULL, '<p>شرکت کاسپین تجهیز تجارت پارس با رویکردی نوآورانه و تخصصی در حوزه تأمین، مشاوره و ارائه راهکارهای پیشرفته تجهیزات پزشکی و صنعتی فعالیت می‌کند. ما با بهره‌گیری از دانش روز و همکاری با برترین برندهای بین‌المللی، متعهد به ارائه محصولاتی با بالاترین استانداردهای کیفیت و ایمنی هستیم. هدف ما، ایجاد بستری مطمئن برای تأمین تجهیزات مورد نیاز صنایع پزشکی، داروسازی و سایر بخش‌های حساس است.</p><p>تیم ما متشکل از متخصصان مجرب و متعهد است که با شناخت دقیق نیازهای بازار و مشتریان، بهترین راهکارهای سفارشی‌سازی‌شده را ارائه می‌دهند. ما با تأکید بر کیفیت، نوآوری و پشتیبانی مداوم،<strong> </strong>به دنبال ایجاد روابطی پایدار و مبتنی بر اعتماد با مشتریان و شرکای تجاری خود هستیم. کاسپین تجهیز همواره در تلاش است تا با ارائه خدمات متمایز، نقش مؤثری در ارتقای سطح کیفی تجهیزات سیستم درمان کشور و فرآیندهای صنعتی و پزشکی ایفا کند.</p>', NULL, NULL, '2025-11-18 08:08:13', '2025-11-19 14:36:08'),
(977, 6973, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-18 21:01:06', '2025-11-18 21:01:06'),
(978, 6977, 'آرامیس تجارت پرداز زرین', 'تا 50 نفر', 'company-default.png', '117', 'تهران', 'بازار بزرگ تهران خیابان ناصر خسرو پاساژ شمس العماره', '02136916277', '8', 'تهران', NULL, '<p>همراه گلد یک پلتفرم تخصصی و نوآورانه در حوزه خرید و فروش آنلاین طلا و سکه است که با هدف ارائه تجربه‌ای امن، شفاف و سریع برای کاربران راه‌اندازی شده است. این مجموعه با ترکیب فناوری‌های روز و استانداردهای حرفه‌ای بازار طلا، امکان انجام معاملات مطمئن را در بستر دیجیتال فراهم می‌کند.</p><p>در کنار خدمات آنلاین، همراه گلد دارای فروشگاه حضوری نیز می‌باشد تا مشتریان بتوانند با اعتماد بیشتر، از خدمات مشاوره، خرید محصول، و پیگیری حضوری بهره‌مند شوند. تمرکز این مجموعه بر ایجاد محیطی قابل اتکا برای سرمایه‌گذاری هوشمند، ارائه قیمت‌های به‌روز، پشتیبانی حرفه‌ای و تضمین اصالت کالا است.</p><p>همراه گلد با تکیه بر تیمی متخصص و ساختاری مشتری‌محور، تلاش می‌کند پلی مطمئن میان بازار سنتی طلا و دنیای مدرن دیجیتال ایجاد کرده و تجربه‌ای متفاوت و ارزشمند برای کاربران و سرمایه‌گذاران رقم بزند</p>', NULL, NULL, '2025-11-18 22:32:50', '2025-11-19 12:43:43'),
(979, 7044, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-19 19:25:21', '2025-11-19 19:25:21'),
(980, 7056, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-19 21:34:25', '2025-11-19 21:34:25'),
(982, 7104, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-20 17:58:24', '2025-11-20 17:58:24'),
(983, 7139, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-21 13:51:53', '2025-11-21 13:51:53'),
(984, 7140, 'آفتاب عالم تاب', 'تا 50 نفر', '88628a0ffa277a5462feeb6ce335355b.png', '117', 'تهران', 'شهرک غرب - خیابان شریفی - کوچه بخشی - برج دوبرال', '02188574061', '8', 'تهران', '', '<p>به گواه تاریخ ؛ زیبایی، پاکیزگی و سلامت همواره یکی از بنیان های اصلی فکری ایرانیان بوده و در طول تاریخ به یک فرهنگ و ذائقه اجتماعی تبدیل شده است. به همین دلیل امروز جامعه ایرانی را به عنوان یکی از خوش سلیقه ترین و مشکل پسندترین جوامع در انتخاب محصولات آرایشی و بهداشتی می‌شناسند. از دل این جامعه پزشکانی برخاسته‌اند که درزمره حرفه ای ترین و نکته سنج ترین پزشکان دنیا بوده و همواره مورد توجه کمپانی های بزرگ آرایشی و بهداشتی جهان قرار گرفته اند. همه‌ی اینها در کنار جمعیت جوان و آگاه؛ ایران را به یکی از قطب های جذاب صادراتی برای شرکت های تولید کننده آرایشی و بهداشتی دنیاتبدیل کرده است.<br>&nbsp;محصولات ایرانی تاهمین اواخر نه سهم چندانی از بازار جهانی داشتند و نه با استقبال در خوری در کشور مواجه بودند.<br>اواخر دهه ۸۰ به بعد همراه با ورود نسل جوان داروسازان و فرمولاتور ها به این بازار بود که رویکرد های شرکت های پیشرو در این صنعت هم تغییر کرد. ما وسایر همکاران جوان که در آغاز کار بودیم ، مصمم شدیم با بهره گیری از تازه های علمی دنیا و تآسی از تجربه و دانش باارزش اساتید و پزشکان ایرانی محصولاتی با کیفیت و در کلاس جهانی به بازار عرضه نماییم.<br>تست های بالینی دقیق و تغییرات ظریف و مکرر در فرمولاسیون، در نهایت منجر به تولید اولین سری از محصولات ما با نام تجاری دوتینی شد. به جرئت می‌گوییم حساسیت های در نظر گرفته شده برای تولید این محصولات اگر بیشتر از استاندارد های اروپایی نبوده باشد، از آن کمتر نیست.<br>اکنون شما محصولاتی را در اختیار دارید که با تمام وجود برای ایجاد رضایت و نشاندن لبخند بر لبانتان تولید شده اند و نیک می‌دانید که در پس این محصولات با کیفیت و زیبا، مسیر سخت و دشواری بوده که تنها با این هدف پیموده شده است . راه دشواری که جز با عشق به ایران و ایرانی، پیمودنش میسر نمی شد.<br>چشم انداز ما در آفتاب عالمتاب، تولید محصولات مراقبت از پوست و مو در کلاس جهانی برای ایرانیان و پس از آن تبدیل شدن به یکی از نام های تجاری شناخته شده در دنیا و حضور در بازار فروش تمامی کشور هاست.<br><br>قطعا روزی باهم محقق شدن این رویا را جشن خواهیم گرفت!</p>', NULL, NULL, '2025-11-21 14:09:31', '2025-11-23 11:39:22'),
(985, 7147, 'حسابگران سپاهان', NULL, '9df79c702a33606ea25bd1340cc4b158.jpg', '79', 'نجف آباد', 'اصفهان - نجف آباد - ویلاشهر - خیابان معلم - نبش ویلای شمالی (رو به روی پاساژ خلیج فارس) - دفتر حسابداری حسابگران سپاهان', '091020910', '4', 'اصفهان', NULL, '<p>شرکت حسابداری حسابگران سپاهان به منظور گسترش تیم مالی خود دعوت به همکاری از افراد حسابدار و رئیس حسابدار جهت انجام امور مالی و مالیاتی می نماید.</p><p>مزایا:</p><p>بیمه</p><p>حقوق اداره کار</p><p>فرصت های آمورشی و توسعه حرفه ای</p>', NULL, NULL, '2025-11-21 20:53:06', '2025-11-21 21:07:42'),
(986, 7153, 'پیشگام ماشین', 'کمتر از 20 نفر', '23070d1c9a416b04db15ff27cf4b74f8.png', '130', 'چهاردانگه', 'چهاردانگه شهرک کامیونداران', '۰۹۰۲۲۴۶۴۵۰۸', '8', 'تهران', NULL, '<p>شرکت پیشگام ماشین همایون با هدف تامین ماشین آلات پروژه های عمرانی و راه سازی و معدن کشور مبادرت به همکاری با بزرگترین و معتبرترین کمپانی های تولید کننده بین المللی فعال در این زمینه نموده است تا در آبادی و سازندگی هر چه بیشتر ایران عزیز و ارتقای نام ایران در عرصه جهانی باشد.</p><p>دسترسی به جدید ترین ماشین آلات صنعتی روز دنیا</p><p>ارائه قیمت های رقابتی در مقایسه با سایر همکاران</p><p>تنوع در انتخاب ماشین آلات صنعتی بسته به نیاز کارفرما</p><p>بهترین خدمات پشتیبانی و فنی</p>', NULL, NULL, '2025-11-22 10:30:43', '2025-11-25 11:00:09'),
(987, 7155, 'سیستمهای اطلاعاتی تصمیم سازان اسپانه', 'بیشتر از 200 نفر', 'e6fc8d7bb82cfedded20a39d0b971c9f.jpg', '60', 'اصفهان', 'اصفهان خیابان پروین', '03131319280', '4', 'اصفهان', NULL, '<p>گروه دمیس، به کمک قابلیت های فناوری اطلاعات و فناوری نوین، در حوزه بیمه و سلامت، یک روند پویا را در پیش گرفته و در چشم انداز خود به دنبال بهبود کیفیت زندگی از طریق تسهیل دسترسی به خدمات بیمه و سلامت، در هر زمان و مکان است. شما در مجموعه دمیس، گروهی توانمند و متخصص از مدیران، کارشناسان و مشاورینی را خواهید دید که در حوزه تولید محصولات کارآمد نرم افزاری، فعالیت چشم گیری دارند. از طرفی تیم ما، بهترین راهکارهای خلاقانه و هوشمند را برای کمک به مشتریان و حل مشکلات آن ها ارائه می دهند. فعالیت دمیس به گونه ای است که در زمینه طراحی و پیاده سازی راهکارهای جامع بیمه های تجاری، راهکارهای سلامت الکترونیک و پرونده سلامت، سامانه های پردازشگر اسناد پزشکی و درمان بیمه تکمیلی، طراحی و توسعه نرم افزارهای سفارش مشتری، طراحی و توسعه سامانه های مبتنی بر هوش مصنوعی، مناسب سازی و استقرار سامانه های برنامه ریزی منابع سازمانی و طراحی و توسعه اپیلیکیشن های موبایل در حال فعالیت است. تیم ما متشکل از خلاق‌ترین و پر انرژی‌ترین برنامه‌نویسان و طراحان می‌باشد. به تیم دمیس بپیوندید. از حضور شما استقبال خواهیم کرد.</p>', NULL, NULL, '2025-11-22 12:17:18', '2025-11-22 12:31:05'),
(988, 7176, 'Kolbeh Cleaning', 'تا 50 نفر', 'b4d57709d3a5ad5674ba31ee5bb3e2cc.jpg', '129', 'پاکدشت', 'پاکدشت، خاتون آباد، روبروی دوربرگردان اول، پلاک 1618/4', '02136460060', '8', 'تهران', '8b34e0554485c019d21fb4614e452283.jpg,17d881e8a1d0bfb6637e0dd3765ee20e.jpg,c987e236585ddc077135fe117bc081e1.jpg', '<p>مجموعه کلبه، متخصص ابزار تمیزی، تولیدکننده محصولات نظافتی و بهداشتی در صنعت پلاسکو با بیش از 20 سال سابقه خانوادگی هست.</p><p>ما در کلبه به دنبال معنا بخشیدن واژه تخصص در صنعت تولیدی محصولات نظافتی و بهداشتی هستیم.</p><p>در کلبه رشد فردی و گروهی اهمیت به سزایی داره و تمام تلاش ما در رشد همیشگی هست.</p>', NULL, NULL, '2025-11-23 10:02:53', '2025-11-23 10:07:39'),
(990, 7209, 'شرکت روغن نباتی سه گل خراسان', 'تا 200 نفر', 'company-default.png', '154', 'نیشابور', 'کیلو متر 27 جاده نیشابور مشهد ابتدای جاده روستای محسن آیاد', '05141422120', '11', 'خراسان رضوی', NULL, '<p>شرکت سهامی (خاص) تولیدی و صنعتی فضل نیشابور تحت برند (روغن نباتی سه گل خراسان) در سال ۱۳۴۴ و با سرمایه گذاری بخش خصوصی فعالیت خود را آغاز کرده و پس از گذشت 60 سال به عنوان یکی از برندهای معتبر و پیشرو در کشور شناخته می‌شود. این شرکت با تکیه بر فناوری روز، نیروی انسانی متخصص و استانداردهای کیفی جهانی، انواع روغن‌های مایع و جامد را برای مصارف خانگی و صنعتی تولید می‌کند.ظرفیت روزانه این شرکت به میزان ۱۵۰ تن انواع روغن‌های نباتی تصفیه شده و استحصال ۱۵۰ تن روغن‌کشی انواع دانه‌های روغنی است. از مهم‌ترین محصولات این شرکت تولید انواع روغن‌های خوراکی مایع آفتابگردان، سویا، کلزا، پالم اولئین و روغن سرخ کردنی می‌باشد.این مجموعه قابلیت روغن‌کشی انواع دانه‌های روغنی به ویژه سویا، کانولا، آفتابگردان و گلرنگ را دارا می‌باشد، تولید انواع روغن خام، انواع کنجاله مورد استفاده در خوراک دام و طیور از محصولات واحد روغن‌کشی این شرکت به شمار می‌رود.</p>', NULL, NULL, '2025-11-25 11:29:56', '2025-11-25 13:25:26'),
