(993, 7238, 'فولاد', NULL, 'company-default.png', '153', 'مشهد', 'شهرک صنعتی کاویان', '۰۰۰', '11', 'خراسان رضوی', NULL, '<p>شرکتی فولادی در شهرک صنعتی&nbsp;</p>', NULL, NULL, '2025-11-26 16:07:43', '2025-11-26 16:13:27'),
(995, 7251, 'پترو سینا ترابر', NULL, 'company-default.png', '126', 'تجریش', 'ولنجک مقدس اردبیلی خیابان فرشچیان پلاک ۱۲', '02122433391', '8', 'تهران', NULL, '<p><strong>فعالیت شرکت:</strong><br>پخش و توزیع فرآورده ها و مشتقات نفتی اعم از نفت و گاز و نفت سیاه نفت سفید و غیره به تمام نقاط کشور،<br>&nbsp;این شرکت پیمانکار شرکت نفت محسوب می شود.</p><p>&nbsp;</p><p>&nbsp;</p>', NULL, NULL, '2025-11-28 19:29:51', '2025-11-29 13:09:41'),
(996, 7298, 'کیان دریای پردیس', 'کمتر از 10 نفر', 'company-default.png', '403', 'بندرعباس', 'هرمزگان،بندرعباس،میدان یادبود،کوچه پیروزی ۱۸،ساختمان ستاره بندر،طبقه سوم ،واحد۲۱', '09164286221', '29', 'هرمزگان', NULL, '<p>&nbsp;در سال 1399/11/13 تاسیس شده است .<br>كيان درياي پرديس خدمات حمل کانتینری، فله، رو-رو و مسافربری ارائه می‌دهد.<br>كيان درياي پرديس خدمات حمل دریایی به اکثر بنادر مهم ایران و جهان ارائه می‌دهد.</p>', NULL, NULL, '2025-12-01 10:50:42', '2025-12-01 16:20:47'),
(997, 7300, 'میداس', NULL, 'company-default.png', '117', 'تهران', 'تهران بازار بزرگ خیابان پانزده خرداد شرقی مسجد امام خمینی', '۰۹۱۲۷۹۳۱۱۸۹', '8', 'تهران', '', '<p><strong>تولید و پخش مصنوعات نقره</strong><br><br>میداس به دنبال معرفی هنر طلای ایرانی در سطح بین المللی و در بین برندهای بزرگ جهانی می باشد در این راستا با عمل به موارد ذیل موفقیت در بازارهای جهانی را جستجو می نماید:</p><p>&nbsp;رعایت استانداردهای بین المللی تولید همگام با تکنولوژی روز جهانی</p><p>طراحی به روز و نوآوری&nbsp;</p><p>&nbsp;اعتماد سازی در بین مشتریان با ارائه خدمات ممتاز</p><p><strong>ارزشهای سازمانی :</strong></p><p>مدیریت و کارکنان شرکت میداس تحقق ارزشهای ذیل را سرلوحه فعالیتهای خود قرار می دهد:</p><p>ما به دنبال رضایتمندی مشتریان از طریق نوآوری، تنوع <a href=\"http://midas-ir.portal.trade/fa/product\">محصولات</a> و ارائه خدمات برتر می باشیم.</p><p>&nbsp;نیروی انسانی شرکت میداس به عنوان بزرگترین سرمایه کاری شرکت، همواره با ارائه نظرات خود در بهبود روشهای کارو تحقق آرمانهای شرکت موثر می باشند.</p><p>ما همواره به دنبال ایجاد و حفظ اعتماد مابین شرکای تجاری خود هستیم (مشتریان، نمایندگان و عاملین فروش، سهامداران)</p>', NULL, NULL, '2025-12-01 10:57:34', '2025-12-02 11:27:10'),
(999, 7329, 'محاسبان', NULL, 'company-default.png', '153', 'مشهد', 'فرامرز ۸', '09151008764', '11', 'خراسان رضوی', NULL, '<h2>خدمات حسابداری اعزام نیروی کار</h2>', NULL, NULL, '2025-12-02 08:12:32', '2025-12-02 08:14:21'),
(1000, 7371, 'بسامد سازان', 'تا 100 نفر', 'ff4f543ab58aa847ddf092e7a1965455.png', '117', 'تهران', 'نشانی: پاسداران، ساقدوش، خیابان رحمانیان غربی، پلاک 6، واحد 21', '02126316236', '8', 'تهران', NULL, '<p>شرکت ساختمانی و عمرانی بسامد سازان با بیش از ده سال تجربه موفق در اجرای پروژه‌های عمرانی، ساختمانی و زیرساختی، یکی از مجموعه‌های معتبر در صنعت ساخت‌وساز ایران به شمار می‌رود.</p><p><strong>✨ حوزه‌های فعالیت:</strong><br>طراحی و اجرای پروژه‌های ساختمانی مسکونی، اداری و تجاری<br>پروژه‌های عمرانی شامل راه‌سازی، پل‌سازی و سازه‌های زیرساختی</p><p><strong>🎯 مأموریت و چشم‌انداز:</strong><br>مأموریت: ارائه خدمات عمرانی و ساختمانی با بالاترین کیفیت، رعایت استانداردهای ایمنی و تحویل به‌موقع پروژه‌ها.<br>چشم‌انداز: تبدیل شدن به یکی از پیشگامان صنعت ساخت‌وساز در کشور با تمرکز بر نوآوری، پایداری و رضایت مشتریان.<br><br><strong>💡 ارزش‌های سازمانی:</strong><br>پایبندی به اصول مهندسی و استانداردهای بین‌المللی<br>شفافیت و صداقت در تعامل با کارفرمایان<br>استفاده از فناوری‌های نوین در ساخت‌وساز<br>توجه به توسعه پایدار و حفظ محیط‌زیست</p>', NULL, NULL, '2025-12-03 11:19:05', '2025-12-03 14:13:44'),
(1001, 7383, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-03 13:56:50', '2025-12-03 13:56:50'),
(1002, 7386, 'طرح پردازان نقشینه افق', 'کمتر از 20 نفر', '25b12eaf522a39ef12eee2677976bcb2.png', '117', 'تهران', 'شادآباد، بلوار الغدیر، بن بست سپیدرود، پلاک 5', '66684320', '8', 'تهران', '', '<p>مجتمع چاپ و کارتن سازی ایده فعال در حوزه کارتن سازی، خدمات طراحی و چاپ افست و دیجیتال، کاتالوگ هوشمند، هدایای تبلیغاتی، ادکلن تبلیغاتی، پوشاک صنعتی و تبلیغاتی، دیجیتال مارکتینگ، تصویربرداری تبلیغاتی، ابزار ایمنی می باشد.<br>تیم ۱0 نفره ما ترکیبی از تخصص، خلاقیت و تجربه در حوزه تبلیغات است. هر یک از اعضای تیم با توانایی‌های منحصر‌به‌فرد خود، به ایجاد کمپین‌های تبلیغاتی موفق کمک می‌کنند. هدف ما ارائه راه‌حل‌های نوآورانه برای ارتقاء برندها و افزایش تأثیرگذاری است.<br>در مجتمع چاپ و کارتن سازی ایده، کیفیت کار همواره در اولویت است. از طراحی تا اجرا، تمامی مراحل با دقت و توجه به جزئیات انجام می‌شوند. تعهد ما به ارائه خدمات با بالاترین استانداردها، تضمین‌کننده نتایج ماندگار و موفقیت‌آمیز برای مشتریان است.</p>', NULL, NULL, '2025-12-03 14:57:24', '2025-12-03 15:01:47'),
(1003, 7403, 'شیشه ایمنی خراسان', NULL, 'fad0707ff13e1f4e29aea2fa72b3890f.webp', '153', 'مشهد', 'پیامبر اعظم 101', '051-36516131', '11', 'خراسان رضوی', NULL, '<p>گروه تولیدی صنعتی شیشه ایمنی خراسان با بیش از دو دهه سابقه و تجربه و با داشتن سرمایه و پشتوانه لایزال الهی و مدیران جوان و متعهد به علم و صنعت دست همکاری و ارشاد تمامی دست اندرکاران تولید و مشتریان محترم را با صمیمیت و گرمی می فشارد.</p><p>با توجه به شناخت بیشتر جامعه نسبت به کاربرد شیشه و برتری این کالا در مقایسه با دیگر مصالح در صنعت ساختمان و غیره و مصرف روز افزون شیشه در جامعه و با هدف ایجاد اشتغال بومی و رفع نیاز صنعت ساختمان به شیشه سکوریت از خارج و یا مرکز کشور ، تنی چند از بزرگان صنعت شیشه در سال 1370 اقدام به تشکیل و تاسیس شرکت شیشه ایمنی خراسان نمودند و پس از یک دهه فعالیت نسبی در سال 1380 با تغییر مالکیت و با بکارگیری نیروهای جوان و متخصص و همچنین مدرنیزه نمودن خطوط تولید و متنوع شدن محصولات ، هوای تازه و سرشار از نشاط به کالبد شرکت دمیده شد و ثمره تلاش مدیران و تمامی همکاران دستاورد کم نظیری را به ارمغان آورد به نحوی که در هر سال شاهد توسعه ساختمان ها و تجهیز واحدهای تخصصی و مستقل و مجهز به پیشرفته ترین ماشین آلات و فن آوری روز دنیا می باشیم.</p>', NULL, NULL, '2025-12-04 11:42:56', '2025-12-16 11:31:48'),
(1005, 7473, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-06 19:11:29', '2025-12-06 19:11:29'),
(1006, 7474, 'زرین جام مانا', 'کمتر از 20 نفر', 'company-default.png', '153', 'مشهد', 'چراغچی 27 نبش اسلامی 8', '05191014505', '11', 'خراسان رضوی', NULL, '<p>شرکت &nbsp;زرین جام مانا ، یکی قدیمی ترین شرکت ها در حوزه تولید و تامین محصولات مصرفی قنادی ها، کافی شاپ ها و رستوران هاست.&nbsp;</p>', NULL, NULL, '2025-12-06 19:14:11', '2025-12-06 19:19:13'),
(1007, 7490, 'لوازم یدکی رشیدیان', NULL, 'company-default.png', '153', 'مشهد', 'خیابان امام رضا (علیه اسلام) 38، چهارراه اول سمت چپ، فروشگاه رشیدیان', '05138532509', '11', 'خراسان رضوی', NULL, '<p>فروشگاه رشیدیان ارائه دهنده انواع لوازم یدکی خودرو در شهر مشهد است. ما با تمرکز بر سه ویژگی، یعنی: قابل اعتماد بودن، خدمات مشتری و منحصر به فرد بودن ، در کنار شما خواهیم بود. فروشگاه رشیدیان در سال ۱۳۷۲ توسط عادل رشیدیان تأسیس شد و سپس بعد از مدتی مدیریت را به اقازاده خود عباس رشیدیان واگذار کرد .<br>فروشگاه فعالیت خود را در خیابان امام رضا (ع) مشهد اغاز کرده و در دو بخش دفتر فروش و انبار فعالیت دارد و ما اکنون در سرتاسر ایران به مشتریانمان خدمات ارائه می دهیم، و از اینکه در همه ی این سال ها کنار شما بودیم و اعتماد شمارا جلب کرده ایم بسیار خوشنودیم.</p>', NULL, NULL, '2025-12-07 10:04:37', '2025-12-07 13:25:22'),
(1012, 7539, 'نیمه دولتی', NULL, 'company-default.png', '117', 'تهران', 'اتوبان ارتش شرق . بعد از مینی سیتی', '09132274789', '8', 'تهران', NULL, '<p>شرکت در سال 1383 تاسیس شده &nbsp;و در زمینه تجهیزات پزشکی . و الکترونیکی فعالیت میکند</p>', NULL, NULL, '2025-12-08 16:59:38', '2025-12-09 09:51:44'),
(1013, 7542, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-08 17:15:27', '2025-12-08 17:15:27'),
(1015, 7606, 'آبتین تجارت فولاد ونداد', 'کمتر از 20 نفر', '0f2b0a4e6a88d4acece33ba4ab9d6d68.jpg', '153', 'مشهد', 'بلوار دانشجو - دانشجو 10', '05191770077', '11', 'خراسان رضوی', '', '<p><strong>شرکت آبتین تجارت فولاد ونداد</strong><br>یک شرکت فعال در حوزه تامین و توزیع محصولات فولادی( ورق های فولادی ، گالوانیزه، میلگرد و تیرآهن) و تجهیزات پیشرفته صنایع ( نفت و گاز و پتروشیمی) است.<br>که با تمرکز بر ارائه خدمات باکیفیت و رقابتی در بازار ایران و آسیا فعالیت می‌کند.<br><strong>حوزه فعالیت:</strong><br>- تامین تجهیزات صنایع نفت، گاز، پتروشیمی و پالایشگاهی.<br>- تأمین و فروش انواع مقاطع فولادی شامل ورق، میلگرد، تیرآهن، نبشی و ....<br>- ارائه راه‌حل‌های تخصصی در صنایع ساختمان، خودروسازی و صنایع سنگین.<br><strong>ویژگی‌های متمایز:</strong><br>- تأمین از بهترین تولیدکنندگان داخلی و بین‌المللی.<br>- قیمت‌گذاری رقابتی و شفاف.<br>- تیم فروش حرفه‌ای و پشتیبانی مشتریان پس از فروش.<br>این شرکت با تکیه بر تجربه و تعهد کاری، به دنبال ایجاد روابط بلندمدت با مشتریان در صنعت مختلف است.</p>', NULL, NULL, '2025-12-09 15:37:37', '2025-12-16 11:27:19'),
(1016, 7655, 'پیمانکاری فتحی', NULL, 'company-default.png', '60', 'اصفهان', 'اصفهان شاهپور جدید', '09133673004', '4', 'اصفهان', NULL, '<p>دفتر حمل و نقل که از سال 1335 مشغول به کار هستش<br>و توی همین مکان یه دفتر بازرگانی که در زمینه مدیریت های مالی کسب وکار ها فعالیت میکنیم<br>&nbsp;</p>', NULL, NULL, '2025-12-10 10:54:52', '2026-01-08 07:18:03'),
(1018, 7702, 'دیان إرامهر', 'تا 50 نفر', 'company-default.png', '117', 'تهران', 'وردآورد. بلوار اصلی وردآورد.', '02174391399', '8', 'تهران', NULL, '<p>شرکت ما یک مجموعه پخش مویرگی فعال در حوزه لوازم آرایشی و بهداشتی است که با شبکه توزیع منظم در سطح تهران و استان‌های اطراف فعالیت دارد.<br>ما با برندهای معتبر همکاری می‌کنیم و هدف‌مان ارائه خدمات سریع، دقیق و حرفه‌ای به مشتریان فروشگاهی و سازمانی است.</p><ol><li><strong>✔️ فرهنگ سازمانی</strong><br>در شرکت ما تعهد، نظم، شفافیت مالی و احترام متقابل ارزش‌های اصلی هستند.<br>محیط کاری پویا، فرصت رشد شغلی، همکاری تیمی و مسئولیت‌پذیری از ویژگی‌های مهم فرهنگ سازمانی ماست.<br>ما باور داریم که موفقیت شرکت نتیجه عملکرد یک تیم منسجم است و برای توسعه مهارت‌های افراد اهمیت زیادی قائل هستیم</li></ol>', NULL, NULL, '2025-12-11 16:21:18', '2025-12-13 10:37:47'),
(1019, 7780, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-13 18:02:22', '2025-12-13 18:02:22'),
(1022, 7835, 'تابران', 'تا 100 نفر', 'company-default.png', '153', 'مشهد', 'شهرک صنعتی فناوری برتر - صنعت 4', '09152600036', '11', 'خراسان رضوی', NULL, '<p>شرکت تابران با بیش از 30 سال سابقه فعالیت در زمینه تولید ماشین آلات صنعتی و خطوط تولید</p><p>&nbsp;</p><p>&nbsp;</p>', NULL, NULL, '2025-12-14 10:12:37', '2025-12-14 11:10:18'),
(1023, 7840, 'شریف تریپ', 'تا 50 نفر', '8094d58970b5c83d6f614aa81573926e.jpg', '117', 'تهران', 'تهران ، زعفرانیه ، خیابان فلاحی ، پلاک 5 طبقه دوم واحد 4', '۲۲۷۷۷۷۹۷', '8', 'تهران', 'd018e39f740478b307846d66013f4c91.webp,8b8f2bc34b37e8534ed170647b6bfe74.webp,2ac0dc5d8966eff1b7f74ee099a18ac9.webp,8ec414b5d1a4f502ddbc0f8875e8caad.webp', '<p>ما یک مجموعه بین‌المللی فعال در حوزه شهروندی دوم، سرمایه‌گذاری بین‌المللی، اقامت و مهاجرت تحصیلی هستیم که با بیش از ۱۰ سال تجربه موفق، مسیرهای جدیدی برای زندگی، تحصیل و تجارت بدون مرز ایجاد کرده‌ایم.</p><p>شریف‌تریپ با دفاتر فعال در ایران، دبی و و همکاری با نهادهای رسمی بین‌المللی، تاکنون صدها پرونده موفق در حوزه‌های پاسپورت دوم، سرمایه‌گذاری و مهاجرت تحصیلی را مدیریت کرده و به یکی از برندهای قابل اعتماد این صنعت تبدیل شده است.</p><p>آنچه ما در شریف‌تریپ تلاش کردیم به آن برسیم :</p><p>نگاه حرفه‌ای و مشاوره‌محور (نه فروش‌محور)</p><p>استانداردهای کاری شفاف و اخلاق حرفه‌ای</p><p>محیط کاری پویا، رو به رشد و مبتنی بر یادگیری</p><p>فرصت رشد شغلی واقعی در یک مجموعه بین‌المللی</p><p>همکاری با تیمی متخصص، جوان و هدفمند</p><p>ما به دنبال افرادی هستیم که:</p><p>به رشد شخصی و حرفه‌ای خود اهمیت می‌دهند</p><p>مسئولیت‌پذیر، دقیق و نتیجه‌گرا هستند</p><p>علاقه‌مند به فعالیت در فضای بین‌المللی و حرفه‌ای‌اند</p><p>دوست دارند بخشی از یک برند معتبر و در حال توسعه باشند</p><p>&nbsp;</p><p>&nbsp;</p><p><br>&nbsp;</p>', NULL, NULL, '2025-12-14 11:06:47', '2025-12-14 12:23:26'),
(1024, 7854, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-14 12:21:58', '2025-12-14 12:21:58'),
(1025, 7856, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-14 12:24:41', '2025-12-14 12:24:41'),
(1026, 7890, 'بازرگانی سپهری', 'بیشتر از 200 نفر', 'dc46faecf81b2c731415b22c651562e4.jpg', '153', 'مشهد', 'مشهد - بزرگراه شهید بابانظر - بابانظر86- پلاک 21', '09153200049', '11', 'خراسان رضوی', '640eddd6dd54ed9d5f360f8b86535c79.jpg,dc3c748deb65cf71a04a768f08848fd7.jpeg', '<p>بازرگانی سپهری - نماینده اصلی &nbsp;فروش کارخانه ابمیوه مجتبی در کل کشور و محصولات غذایی رعنا در استان خراسان و هرمزگان با بیش از سی سال تجربه درخشان در صنعت مواد غذایی کشور با بیش از 420 نفر نیرو در واحد های مختلف فروش ، لجستیک ، حسابداری و مالی ، منابع انسانی و اداری در استان خراسان رضوی شهر مقدس مشهد میباشد و در حال احداث کارخانه جدیدی از محصولات متنوع مواد غذایی علاوه بر ایجاد اشتغال مثبت برای مجاورین محترم شهر مشهد باعث تنوع بخشیدن به سفره ایرانیان با فرهنگی غنی و سرشار میگردد.&nbsp;</p>', NULL, NULL, '2025-12-14 14:02:40', '2025-12-16 16:08:41'),
(1027, 7891, 'شرکت آتی طب درمان پارس', NULL, 'company-default.png', '153', 'مشهد', 'مشهد نبش   پاسداران2 مجتمع فیروزه شرق', '05138385320', '11', 'خراسان رضوی', NULL, '<p>فعالیت شرکت تجهیزات پزشکی می باشد. حقوق بر اساس توانمندی فردی &nbsp; بیمه و سایر مزایا&nbsp;</p><p>ساعت کاری 8 تا 16</p>', NULL, NULL, '2025-12-14 14:04:00', '2025-12-14 14:08:21'),
(1028, 7930, 'مرینو', NULL, '0df6ec50ef2773e4802d3edbafd95657.jpg', '130', 'چهاردانگه', 'تهران-شهرک صنعتی چهاردانگه', '09120379207', '8', 'تهران', NULL, '<p>این مجموعه با تمرکز بر طراحی و تولید پوشاک کودکان و با همکاری تیم های متخصص و حرفه ای در واحدهای طراحی، تولید، بازاریابی و فروش، در حال فعالیت می باشد، که از سال ۱۴۰۰ با ثبت برند تجاری مرینوپوش و با تاسیس شعب خود در نقاط مختلف استان تهران و همچنین اهدای فرانچایز در سایر نقاط کشور به صورت رسمی در حال فعالیت در بازار پوشاک ایران می باشد.<br>&nbsp;</p>', NULL, NULL, '2025-12-14 16:19:03', '2025-12-16 11:18:28'),
(1029, 7977, 'سیما تجارت امیر رویان', NULL, '4c12fb1fc539f3e5de04e7e6bd51db43.png', '117', 'تهران', 'اقدسیه خیابان موحد دانش نرسیده به سه راه اقدسیه پارک سوم پلاک1', '02122827331', '8', 'تهران', '', '<p>این سازمان بیش از 10سال در زمینه محصولات آرایشی و مراقبتی فعالیت داشته است .</p>', NULL, NULL, '2025-12-14 18:51:05', '2025-12-16 11:06:26'),
(1030, 8000, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-14 19:37:51', '2025-12-14 19:37:51'),
(1032, 8159, 'دیدگاه نوین', NULL, 'c6eab1c193cc713ef1daa132641b8615.jpg', '117', 'تهران', 'اتوبان ازادگان.بعد از پل صنیع خانی ٫بازار مرکزی اهن(اهن مکان)،فاز دوم مرکزی،پلاک 320. و321', '02155519855', '8', 'تهران', NULL, '<p>تولید کننده پروفیل upvc سان نوین sun win&nbsp;<br>واردات و توزیع یراق آلات upvc<br>ارائه دهنده و نماینده پروفیل دکتر وین و رئال وین</p>', NULL, NULL, '2025-12-15 11:05:47', '2025-12-17 11:21:55'),
(1033, 8167, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-15 11:47:48', '2025-12-15 11:47:48'),
(1034, 8199, 'آریابهین ترخیص', 'کمتر از 10 نفر', '444765f84dbb301fc4bf83ef6672605d.jpg', '117', 'تهران', 'میدان آرژانتین خیابان وزرا  کوچه بیستم وزرا', '02188104106', '8', 'تهران', NULL, '<p>&nbsp;ترخیص کالا از تمام گمرکات<br>واردات و صادرات + ثبت سفارش و امور گمرکی و بازرگانی<br>شرکت آریابهین ترخیص به مدیریت آقای پویان خداپرست، کارگزار رسمی گمرک ایران، در سال 1377 با هدف بهبود بخشیدن به روند بازرگانی و همچنین کارآفرینی در حوزه ترخیص کالا تأسیس گردید.<br>مجموعه آریابهین ترخیص با کادری متخصص و حرفه‌ای، پرانگیزه و با اطلاعات دقیق و به‌روز، خدمات متمایزی را در زمینه ترخیص کالا ارائه می‌دهد. از جمله این خدمات می‌توان به مشاوره تخصصی، خرید خارجی، ترانزیت و ترانسفر کالا، ثبت سفارش کالا، اخذ مجوزهای قانونی، ترخیص کالا از کلیه گمرکات، حل اختلافات گمرکی، اخذ گواهی از ادارات و سازمان‌های دولتی و خصوصی، و همچنین فرآیند عملیات امور بندری در زمینه تخلیه و بارگیری کالاهای فله و کانتینری اشاره کرد.</p>', NULL, NULL, '2025-12-15 15:26:27', '2025-12-16 11:11:47'),
(1035, 8272, 'سانیکث', 'تا 50 نفر', '3de2184743507c949facd30c8ec24152.jpg', '117', 'تهران', 'شهرک غرب خیابان حسن سیف', '02188560009', '8', 'تهران', NULL, '<ol><li>طراح، ناظر و مجری پروژه های ساختمانی لوکس مسکونی و اداری با سبک و تفکری به روز و نوین و تجربه ای درخشان</li><li>&nbsp;</li></ol>', NULL, NULL, '2025-12-16 12:22:32', '2025-12-16 12:52:00'),
(1036, 8349, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-18 19:22:07', '2025-12-18 19:22:07'),
(1037, 8384, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-19 23:07:07', '2025-12-19 23:07:07'),
(1038, 8412, 'گروه ونداد', NULL, '3a2b2c1794132317bb92ef96c69a4597.jpeg', '117', 'تهران', 'منیریه', '09100317583', '8', 'تهران', NULL, '<p>یک شرکت برگزار کننده همایش ، که به صورت دورکاری و سبک ترین حالت ممکن همکاری ( چندروز در ماه) از حسابداران گرامی جهت همکاری دعوت مینماید. ( فاکتور زدن ، سامانه مودیان، مالیات ارزش افزوده فصل، مالیانه سالیانه و درآمد)&nbsp;</p>', NULL, NULL, '2025-12-22 11:59:16', '2025-12-22 12:05:42'),
(1039, 8413, 'رامپکو', 'بیشتر از 200 نفر', 'a425399248d680df6f0bea0e7b0f8db9.jpg', '117', 'تهران', 'خ ولیعصر بالاتر از میرداماد خ بابک بهرامی پلاک 50', '88207860', '8', 'تهران', NULL, '<p>شرکت مهندسی و نصب و نگهداری کارخانجات پتروشیمی (رامپکو) در زمینه ساخت و تعمیرات صنایع پتروشیمی و پالایشگاهی و صنایع معدنی بصورت EPCدر داخل کشور و سایر کشورها مشغول فعالیت میباشد .</p>', NULL, NULL, '2025-12-22 12:57:47', '2025-12-24 15:29:06'),
(1040, 8418, 'ناوگان گستر کرانه', 'کمتر از 10 نفر', 'f62cd7109d2e03c458ed8ca3057220e7.jpg', '117', 'تهران', 'تهران، بلوار جنت آباد جنوبی، نبش بلوار لاله، پلاک 82، مرکز خرید سمرقند، بخش اداری، طبقه ۸، واحد 806', '02144416950', '8', 'تهران', 'c20cd6fedc1d96f18be98ea1fba404c3.jpg', '<p>شرکت حمل و نقل بین المللی ناوگان گستر کرانه مفتخر است خدمات بین المللی حمل و نقل و ترانزیت را بصورت کریری و فورواردری به مشتریان و همکاران گرامی با شرایط رقابتی ارائه می‌نماید. تیم حرفه‌ای ما شامل بخش عملیات و شبکه نمایندگی در کلیه بنادر و گمرکات کشور، خدمات تخصصی حمل و نقل جاده‌ای، دریایی و چندوجهی را از و به کشورهای روسیه، ترکیه، چین، اروپایی و... ارائه می‌نماید. خدمات ترانزیتی که توسط شرکت ما برای مشتریان خارجی ارائه می‌شود، آنها را قادر می‌سازد تا محموله‌های خود را از طریق خاک ایران با سریع‌ترین و رقابتی ترین نرخ حمل و نقل جاده‌ای و ریلی ترتیب دهند. ما همواره تلاش می کنیم تا با فراهم آوردن سریع‌ترین و بصرفه‌ترین شیوه و شرایط تجارت شما مشتریان گرامی را آسان‌تر، مطمئن‎‌تر و بهینه‌تر کنیم.</p>', NULL, NULL, '2025-12-23 09:06:35', '2025-12-23 09:09:08'),
(1041, 8419, 'گالری پارچه فلامینگو', 'کمتر از 20 نفر', 'company-default.png', '153', 'مشهد', 'بلوار فرودگاه بین جمهوری اسلامی 24 و چهارراه مقدم', '33493359', '11', 'خراسان رضوی', NULL, '<p>ما یک مجموعه تخصصی در صنعت پارچه و منسوجات هستیم و جزء 10 انتخاب اول مصرف کنندگان پارچه در مشهد می باشیم . مجموعه درحال پیشرفت و رشد است و نیاز به نیروهایی با انگیزه و عاشق کار دارد که در کنار تیم رشد نماید و مجموعه را در راه رسیدن به اهداف آن یاری نماید .</p>', NULL, NULL, '2025-12-23 09:52:24', '2025-12-23 10:03:43'),
(1042, 8511, NULL, NULL, 'company-default.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-24 22:19:31', '2025-12-24 22:19:31'),
(1043, 8548, 'گیو سبز خرم', NULL, 'company-default.png', '117', 'تهران', 'جردن عاطفی شرقی پلاک ۶', '۰۹۱۲۳۷۰۹۳۵۸', '8', 'تهران', NULL, '<p>شرکت «گیو سبز خرم» در زمینه بازرگانی خرید و فروش گل و گلدان تزیینی فعالیت می‌کند که در سال 1400 در تهران به ثبت رسیده است.</p>', NULL, NULL, '2025-12-25 08:45:49', '2025-12-27 12:22:39'),
(1044, 8553, 'سهندتجارت عطار', NULL, '53e52a0052118e00a26d65db453185bd.jpg', '153', 'مشهد', 'بزرگراه آسیایی-بین پیامبراعظم 10و12-مجتمع اداری سپهر', '051-36516500', '11', 'خراسان رضوی', NULL, '<p>شرکت بازرگانی سهند تجارت عطار فعالیت خود را از سال ۱۳۹۶ با هدف تأمین و توزیع نهاده‌ها و خوراک دام آغاز کرد. این مجموعه با تکیه بر دانش فنی، رویکرد مشتری‌محور و شناخت دقیق از نیاز بازار، توانسته جایگاه قابل اعتمادی در صنعت دام و طیور کشور به دست آورد.</p>', NULL, NULL, '2025-12-25 09:31:17', '2025-12-25 11:27:56'),
