(1071, 9085, 'جام تراز ایرانیان', NULL, 'company-default.png', '153', 'مشهد', 'معلم ۶۴ ساختمان نیایش واحد ۴', '۰۹۱۵۵۷۵۴۴۱۹', '11', 'خراسان رضوی', NULL, '<p>با سلام و احترام . شرکت جام تراز ایرانیان در راستای تکمیل کادر پرسنلی خود اقدام به جذب نیرو با شرایط زیر می نماید . &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;مدرک تحصیلی : کارشناسی حسابداری و یا در حال تحصیل &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ساعت کاری : 8 الی ۱۶. &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;تسلط کافی بر اصول و مفاهیم حسابداری،آشنایی کافی با نرم افزار حسابداری،آشنایی کافی با ورود و اکسل،متعهد،منظم و علاقه مند به یادگیری &nbsp; &nbsp;مهارت های مورد نیاز: &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;مالی و حسابداری &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Microsoft Office. &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; نرم افزار های حسابداری &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; حداقل سابقه کار: مهم نیست &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;جنسیت: مهم نیست &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;وضعیت نظام وظیفه: مهم نیست &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;نوع همکاری: تمام وقت&nbsp;</p><p>&nbsp;</p>', NULL, NULL, '2026-01-29 09:53:13', '2026-01-29 10:09:09'),
