(1073, 9098, 'راین رویش ماندگار', 'کمتر از 20 نفر', '0311bf4948b303b8368e3f7b8b737b5d.jpg', '117', 'تهران', 'تهران، کوی نصر، کوچه 39، پلاک 7', '88264871', '8', 'تهران', NULL, '<p>راین (Rooyesh Innovation Engineering) یک شرکت مهندسی در حوزه سازه و ژئوتکنیک است که خدمات طراحی و مشاوره فنی پروژه‌های عمرانی و صنعتی را ارائه می‌دهد. محیط کاری منظم و حرفه‌ای است و روی گزارش‌دهی دقیق و شفافیت مالی حساس هستیم.</p>', NULL, NULL, '2026-02-01 10:09:56', '2026-02-01 10:16:56'),
